-- reviews_backfill.sql (分割版) : 新36アプリのレビューをMac経由で投入（Workerを迂回）
-- D1のstatement長制限に合わせて50行ずつのINSERTに分割。INSERT OR IGNORE で再実行安全。
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '14223630657', 'Denali_10', 5, 'Great app at a great price', 'I love the Bear app. It’s WAY better than Evernote and reasonably priced. Keep up the great work!', '2.8.2', 'us', '2026-06-25T00:29:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '14204827562', 'dimelicd', 4, 'I’m using this nonstop now', 'I love this notes app is just what I needed! Though I’m giving this 4 stars because I really wish the lock notes feature would be free.', '2.8.2', 'us', '2026-06-20T04:10:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '14199281513', 'V-9013372', 3, '无法和windows网页版很好同步', '在网页上写东西，第二天起来发现没有按照网页上最新写的同步，而是同步了手机里没写新东西的旧版本，天塌了你知道吗。这体验太差了，因为我前一天晚上专门试验过会不会同步，看的时候没有问题，结果早上起来给我开大招。', '2.8.2', 'us', '2026-06-18T17:07:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '14135687639', 'Steveofmaine', 3, 'Sadly, voiceover support is lacking.', 'I was really excited to try this app especially since so many people love it and because I’m looking for something that is simple that also supports wiki linking. unfortunately, as a VoiceOver user, I’m finding the app very difficult to use. Many of the buttons are not labeled and also voiceover has trouble tracking focus as I move around the app. As such, the app is currently not usable for me at least on iOS. I hope that the developers will consider adding more robust voiceover support in the future, I would definitely be a very happy user..', '2.8.2', 'us', '2026-06-02T08:50:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '14088942640', 'SmartWater Drinker', 5, 'Exactly what I needed', 'I was looking for an Evernote alternative where I could use tags, and this is perfect. I both like to write and store recipes using tags for season, type, occasion etc. The support for nested tags is much appreciated, and their Pro plan is very reasonable. Not much is paywalled (it’s just cloud features, themes, and search), so give it a try!', '2.7.5', 'us', '2026-05-21T04:29:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13983959274', 'TalonJF', 4, 'Almost', 'It’s almost perfect, it won’t render math or PDFs or anything, it was working, the update broke it I love how it looks but the exporting and rendering are pretty fundamental and I feel like it should really be able to do more, like why not also have rich text as an option and if it’s only markdown then it’s a pretty high priority that it should do markdown literally flawlessly and it doesn’t Hope it gets fixed asap If still recommend it but with warnings and if there were anything else better this app could easily lose to that There are so few options for anything like this it’s pretty mind blowing', '2.7.4', 'us', '2026-04-21T22:14:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13962346487', 'Johnny Guierrmo', 2, 'Extremely suspect privacy policy', 'Expressly states data can be used for beta testing and worst of all the testing is done with what is quite arguably the least privacy conscious company of the 21st century: Microsoft. Not to be outdone, the rest of the policy is extremely vague but lends itself to the interpretation that absent written notice provided to either the developer or applicable authorities OR both (language isn’t clear and would need to dive deeper), you have absolutely no it rly zero expectation of privacy here. In a market with 50 other competitors, this isn’t the way to do business IMO. Massive wasted opportunity here', '2.7.1', 'us', '2026-04-15T18:31:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13923421935', 'FrigidFridgerton', 5, 'Just better than anything comparable', '- It works - It works consistently - Great UI - Smooth down to the smallest of interactions - Fast - Same great experience on every Apple device No matter how many times I try other note taking apps, none of them come close to the simple, great experience of Bear.', '2.7.1', 'us', '2026-04-04T17:40:10-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13916967833', 'thayesx', 5, 'Should need no introduction', 'Bear slaps. I''ve used it for like 8 years now. Super simple, just the right amount of complexity. Themes and styles are beautiful, including all the custom icons. Sync is always super fast and smooth. Exporting, tagging, formatting, all just work exactly how you''d want. Everything feels crisp and easy to use, especially and most importantly the note editor UI, which is truly perfect. Keep doing what you''re doing dev team give somebody a raise', '2.7.1', 'us', '2026-04-03T00:36:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13871641120', 'krizhka', 5, 'ipad rendering bugged for months now', 'when using bear on the ipad in windowed mode (not full screen), sometimes following a link within a note causes a bug with rendering where the bottom portion of the note is not rendered. you can sometimes fix it by restarting bear.', '2.7', 'us', '2026-03-21T07:09:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13832464105', 'TeaChiffon', 5, 'The very best! ♡', 'This app is reliable, easy to navigate, and stylish. I love using it every day! Please consider adding a feature for user-made themes in the future! And a feature to toggle a note’s history + restore versions!', '2.6.7', 'us', '2026-03-09T22:07:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13821192574', 'JohnnyDorean', 5, 'Bear is the Best!', 'Hands down my favorite notes app I’ve ever used. It’s getting more features all the time and has everything I need. Most aesthetically pleasing app, too. I love how it syncs across my iPad and MacBook, and the way it centers the content inside the window is an amazing but simple feature that not all other notes apps have. Well worth the money. My go-to for many years now. Small development team I believe, too, so I’m more than happy supporting this gem.', '2.6.7', 'us', '2026-03-06T15:24:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13817958521', 'Utterlydonein!', 3, 'Great for saving info', 'Well, it was a great app, but the latest update just screwed up the copy and paste function. Used to be you could just copy and paste, then edit your data; now after you copy, it gives you a multiple choice for paste for which no selected options work, so they just rendered my favorite note taking app useless for copying data to edit.', '2.6.7', 'us', '2026-03-05T16:37:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13814077862', 'DanielJohnsonReal', 5, 'Fantastic', 'Love it. It’s a little glitchy sometimes but overall I love the design and feel', '2.6.7', 'us', '2026-03-04T13:15:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13768591442', 'Jessie Westlake', 4, 'Almost Perfect Out of the Box', 'I would give it 5 stars if there was the ability to disable word wrap in code blocks and allow a sideways scroll. I do a lot of code snippets, but most lines are beyond the iPhone Pro Max screen width. Callouts could benefit from this as well. It would also be great if we could add or edit a CSS stylesheet file for the HTML export, or dare I ask for in-app style customizations beyond the prebuilt theme and the font face and size/spacing options (which are great by the way, thank you!) Finally, but not an issue of this app at all and not affecting its rating, would the developers PLEASE, PRETTY PLEASE make a Windows app, or at least a web app I could use on Windows? Then I would be a diehard forever customer.', '2.6.7', 'us', '2026-02-19T21:43:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13747134650', 'RogerThatWolf', 5, 'Thank you for the safe space', 'This app feels safe, calm, useful, simple.', '2.6.5', 'us', '2026-02-13T21:52:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13714511249', 'Standard io', 4, 'I want to love it so badly', 'Bear would be my perfect notes app, and I would gladly pay the subscription for it. However, the keyboard toolbar/text editor on iPhone is so bad, especially when compared with the default Apple notes. (Please just copy how Apple notes sets up their keyboard toolbar, it’s so much better). If you want to format anything, it is such a headache and so incredibly slow because everything is hidden behind a formatting menu icon, which you have to press, select the formatting option you want, then change back to keyboard. This could very easily just be one button press like it is in Apple Notes. And considering how often I format notes, this time adds up quickly. Aesthetic at the cost of efficiency is useless. Also pls pls pls just copy the way Apple’s todo lists work. I want to be able to drag around todo list items. Unfortunately, Bear is an app clearly designed to be used with a mouse and keyboard, not fingers and touchscreens. I think it is so beautiful, and I love the organizational structure with the tags and markdown. But this basic functionality that is missing is so core to a notes app that I will very sadly have to replace it with Apple notes. If they fix this, I’m buying the subscription and changing my review to 5 stars.', '2.6.5', 'us', '2026-02-04T21:52:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13664735089', 'lightstreem', 3, 'Tags for folder organization???', 'I’m looking for a new Notes app. I like the color themes that Bear offers. The app looks really good. The text and paragraph formatting options are limited imo. Where Bear lost me though was when I discovered in order to create folders and nested folders, I have to use tags. I mean, come on. Just let me create folders and nested folders. Had to delete the app. I think I would’ve kept it and paid the yearly subscription if I could just make folders and nested folders easier.', '2.6.5', 'us', '2026-01-22T17:53:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13657320935', 'Kwassant', 5, 'What I’ve been looking for', 'It’s like it was made for me', '2.6.5', 'us', '2026-01-20T17:11:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13656660030', 'swarmtistic', 1, 'All my work is gone', 'They updated the app and absolutely everything that I’ve kept there is gone and customer service has helped very very little. If ur gonna use the app at least keep your work backed up elsewhere', '2.6.5', 'us', '2026-01-20T12:54:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13621430899', 'DJ Justice', 5, 'Indispensable', 'I do a ton of notetaking, and Bear is now my indispensable tool for doing so. The UX is great across iPhone, iPad, and Mac, syncing across devices just works with iCloud without any extra subscription, and the Markdown support is great for portability between systems like blogs.', '2.6.5', 'us', '2026-01-11T07:15:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13607539573', 'CelesteWrob', 5, 'Brilliant, lovely', 'So easy to use and intuitive. The aesthetics make it fun. I haven’t found a better app for organizing all the notes, documents, links, and courses I collect and refer to to support my career-change coaching practice. The tagging system allows me to classify something by topic and also author or source. It’s a beautiful personal library. And the customer service is extremely responsive.', '2.6.5', 'us', '2026-01-07T18:07:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13606941304', 'rock1001', 5, 'Clean and Powerful', 'This app shines in the little details: it’s crazy fast, compare it to Apple notes and you will see a night and day difference, especially for long notes. It has table of contents, which makes it easy to navigate long notes. The tag system is miles better than folders. You can manage your todos by following a thin line under each of your notes that shows the progress of your todos in the note. It supports latex! So you can write math formulas now. It has web access. It has a nice menu of themes. It shows you unmentioned backlinks: you can reference other notes that mention the title of your current note. You can lock notes with attachments. You can copy links to each note. You can export to multiple formats. You can draw (although here it’s a bit basic) and have Bear detect words in your images. It gives you useful stats about your notes. And I could keep going. You would not tell half of these when you first open the app, and that’s the point. Its power is modest. It enables you and gets out of the way so you can work. Their dev team is small and slow, but they deliver. Late sometimes, but they deliver. This app is a powerhouse.', '2.6.5', 'us', '2026-01-07T14:19:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13590775650', 'Preston Embers', 5, 'Tried them all-came home to Bear', 'This app is so streamlined that it can be deceptive how brilliant it is. Bear works with your mind—without friction. Hashtags are one of five key power tools here. Use them to create a filing system, as well as to cross index any files you want. Bear seems simple, but it is in fact the most elegant writing tool out there. In its elegant simplicity exists ultimate creative power. As a fiction writer, with many large projects on my plate, I can tell you—as someone who has tried all the excellent writing apps out there—nothing comes close to Bear. It’s exactly what it needs to be, leaves everything else in its wake, is created by people who design with pure intent, which is why it’s literally pristine. Even if you doubt, master its incredibly simple tools, and build out a file system using the tags— they nest like breadcrumb trails…and there you go. You no longer have to choose a folder, or even a title. Just write, just flow, just go.', '2.6.5', 'us', '2026-01-03T11:36:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13520418656', 'Gracie.', 5, 'Perfect & Private', 'I’ve had this for years and love it. Just open and start writing, and the company does NOT extract or use any of your information, location, contacts, etc., which is a great sign of integrity, especially today.', '2.6.5', 'us', '2025-12-16T07:05:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13501496229', 'simple man’s gospel', 2, 'almost good', 'if you could send notes to people like in evernote i would drop other note apps and go full bear. upgrade it and grab the money on the table bear', '2.6.5', 'us', '2025-12-11T07:39:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13493668973', 'VermilionTheWriter', 1, 'Voiceover users beware', 'I didn''t even get to read the welcome notes before deleting this app. The side menu will not stop popping out, no matter what I do. The advice was to swipe right from the middle of the screen to avoid this but nothing worked. And if the welcome notes have titles, VO didn''t read them. Just skip this one. Save yourself the headache.', '2.6.5', 'us', '2025-12-09T05:52:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13474329471', 'nknewt', 5, 'Clean interface, intuitive function', 'I’ve tried pretty much every web clipping app out there in pursuit of the perfect system to store and organize my research. Bear comes pretty close! The UI is simple and uncluttered (super important to me as someone with difficulties navigating busy designs). The nesting note system keeps all my notes and clippings well organized and easily searchable. Unlike other Markdown-based apps I tried, there was no learning curve—use was completely intuitive, so I could get to work right away. I particularly like the note menu design with its ability to assign an icon to each category—again, as someone who has difficulty navigating dense text designs, the icons provide a helpful identifier to help me quickly navigate to my most-used categories.', '2.6.5', 'us', '2025-12-04T07:13:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13441230371', 'Magic Kingdom Zeal', 5, 'Solid and beautiful text editor', 'I’ve used Bear for a few years now. I really enjoy the functionality, UI, and ease of formatting. I have the yearly subscription, so my notes sync across devices readily. I can also adjust font, spacing, and color themes easily. I’m not an advanced Markdown user, but I’m beginning to learn more features I’ve barely touched, like making your notes into your own pseudo-wiki (!). It’s really nice.', '2.6.5', 'us', '2025-11-25T16:27:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13440449124', 'rdparris', 5, 'Excellent for so many things', 'I’ve been using Bear Notes almost from the beginning. It was slow going at first and I hung in there as Bear moved closer and closer to 2.0 and I have to tell you after using nearly all of the options that are out there for note taking, journaling and more, there’s no better. So if you’re stuck with another note app, and want to see what else is out there, give Bear a try. You will not regret it. Excellent work developers, I look forward to being with you for years to come.', '2.6.5', 'us', '2025-11-25T11:28:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13417199970', 'champagne.ivers', 5, 'One of a kind!', 'Beautiful, efficient, and versatile! This is a one-of-a-kind app that I’ve made an inextricable part of my daily flow. Truly, it’s a masterpiece of elegance in software design. My only hope is the devs keep focus, as its versatility is going to encourage adamant recommendations for all kinds of added functionality and integration that could easily pull the app in a thousand different directions. I include myself among the masses. I wish the devs would add integration with the native iOS apps, especially the calendar and reminders.', '2.6.4', 'us', '2025-11-19T09:05:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13411048839', 'Amo este juego me encantó', 5, 'Amo', 'Me gusta mucho,tiene muchas opciones de texto,puedes hacer de todo un poco,es buena para ipad y teléfonos,simplemente me encanta', '2.6.4', 'us', '2025-11-17T17:27:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13407108047', '白起灬', 1, '不好用', '非常垃圾。辛苦写了几个小时的字全没了。不建议使用。', '2.6.4', 'us', '2025-11-16T16:38:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13364389433', 'GuardianGate', 5, 'The best writing app.', 'My only go to app for writing. I love it.', '2.6.3', 'us', '2025-11-06T08:51:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13349625069', 'lkf0xx', 4, 'Lovely, but a few suggestions!', 'I’ve been using Bear for years, long before Bear 2 released and it truly has come a long way! As a student, I don’t use Bear for anything particularly professional. I’m just a person who enjoys keeping everything simple and organized. Bear is just that. It’s easy to use yet has always been steps ahead of the iOS Notes app as far as features and UI go. I use other apps for structure and organization like Obsidian, but everything I do starts in Bear. If I need to write anything at all, I open Bear without feeling overwhelmed by assigning it a category immediately. I’m a Bear Pro user and I don’t plan on letting go of Bear anytime soon so here are a few tiny things I’d love to see in the future: 1. There are a few instances where I like to be able to have a note throughout all of a tag’s subtags and main page out of convenience. For example, if I have a note called “resources” with the tags #physics/GR and #physics, currently the tag will only appear in the GR subtag. 2. I wish the pencil icon next to external links could be disabled. 3. It would be nice if users could adjust the primary action that appears in the menu. For example, the current first attachment action is Take Photo and any other requires you to hold down the button. I personally use the Add Images option way more so it would be more convenient if users could decide what shortcut appears on top.', '2.6.3', 'us', '2025-11-02T20:17:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13345078037', 'Snowmo.on', 4, 'Just a few annoyances', 'Bear is one of my favorite note-taking apps. It’s beautifully designed and incredibly intuitive to use. I just wish it had an archive option — sometimes I want to hide older notes without deleting them or cluttering my daily tags. Also, the Trash folder is always visible at the top of my tags, which can be a bit distracting. It would be nicer if it were hidden or moved to the bottom. Overall, it’s an amazing app with just a couple of small things that could make it perfect.', '2.6.3', 'us', '2025-11-01T20:48:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13306926328', 's-carhome', 5, 'Best Notes App', 'I’ve tried multiple brand name note taking apps and this is by far my favorite. Sleek, simple and has all the features I need.', '2.6.3', 'us', '2025-10-24T01:37:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13284967026', 'TresAppy459', 1, 'App not syncing across devices - iOS 26 broke it', 'App not syncing across devices - seems to have broken with iOS 26. :(', '2.6.3', 'us', '2025-10-18T20:08:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13279733390', '@!€ (Timothy)', 4, 'Thank You Bear', 'Agree with most comments. Great UI, subpar UX. Need to consolidate between apps and shifted to Obsidian but that’s for a personal decision across platforms and also for higher expressions of note taking that Bear doesn’t have. One key plus is pasting images into the note, much easier than with Obsidian. But Bear has been a great mobile app.', '2.6.3', 'us', '2025-10-17T14:50:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13259761524', 'krew303', 5, 'very functional without extra junk', 'I replaced evernote with bear about 9 months ago and wish I had done it 2 years ago. Bear is super functional, I get pretty much everything I need. Get bear pro, it is completely worth it and the best deal of all the notes apps.', '2.6.3', 'us', '2025-10-12T21:41:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13256549739', 'Tadhg12345', 3, 'Used to like this more', 'There’s been a UI revision in the last while that’s made it super confusing to do things like add images to notes from my phone (go to BIU, open a keyboard, hold down on a camera icon, etc). It’s not at all fluid.', '2.6.3', 'us', '2025-10-12T04:30:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13240622043', 'Kittyyyyuh', 5, 'My go-to writing app', 'I downloaded Bear back in 2016 and it’s been my exclusive writing app since. The interface is intuitive yet non-intrusive, something very important to me. I can write without a bunch of buttons scattered across the screen and can pull them up easily when I do need them. The tag system is amazing and easy to work with and I love the small touches like changing tag icons! I write every day and it’s thanks to Bear!', '2.6.3', 'us', '2025-10-08T09:35:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13163138080', 'Keebasabe', 5, 'Great Note app for light formatting', 'I don’t like the iOS Notes app much. I wanted a text editor with light formatting options, like WordPad in Windows. Bear is perfect for this. You can apply bold, italic, underline, strike-through or highlight to text, have bullet lists, numbered lists, H1, H2, H3. You can add footnotes. It’s got pretty much everything I need. Hashtags make organization easy. These features are available with the free app, no subscription necessary.', '2.6', 'us', '2025-09-20T14:41:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13118276445', 'YURI_1010', 3, 'Honest review', 'This app has nice features, but it doesn’t beat Apple Notes, which is free. For specific needs, I already use Microsoft Word and Apple Pages. So I’ve got more than enough apps that cover everything Bear does, and more. The only edge is exporting to multiple formats, but copy and paste to Word or Pages does the job. Paying $30/year ($2.5/month) makes no sense with all the overlap. Subscriptions add up, and apps like Procreate or Inshot, for example, in their industry give much more for less money. I’d only consider paying for Bear with a one-time lifetime license price, or a much cheaper plan, where many more people wouldn’t mind paying for, something like $10/year. For the features and design alone I would give 5 stars. But the pricing is overselling and overwhelming and the world full of subscriptions. If you decide to change your pricing plan, to something that makes more sense from a consumer standpoint, please let me know.', '2.5.2', 'us', '2025-09-09T12:08:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13103937580', 'seven 1', 5, 'This is such a good application!', 'I’ve been a Bear user for many years. It’s very easy to use, making even complex sets of notes easy to create and manage. Bear puts the polish on notes like no other. The developers are actively adding new features, and updates are meaningful and useful. There are several very good notes apps out there, but Bear is excellent and elegant. Like your iPhone, Mac, or iPad, everything just works and works well.', '2.5.2', 'us', '2025-09-05T19:40:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13047643679', 'Fish netter', 1, 'Good, but files sometimes disappear.', 'I have been using this note app to copy and organize my old recipes. It is easy enough to use, once one learns the special characters needed for anything outside of plain script. My problem is that notes occasionally are erased, through no keystroke I can find. If I try to correct a spelling, the note disappears, completely erased. It is not shown on the list, a search for key words finds nothing, and categories no longer show the note. Some of these are old family recipes, and if I have deleted the source copy, it is completely lost. This app is SO CLOSE to being exactly what I need, but how can I trust an app that saves “most” of the notes, but randomly drops others? If I need to keep an old copy, just to be safe, why would I need this one for a duplicate?', '2.5.1', 'us', '2025-08-22T08:55:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '13015878309', 'starfishface345', 4, 'Almost perfect', 'Great note app does most things iOS notes can do and maybe more except make folders and sub folders to organize notes . And add audio files . If you could add these features I would say price is justified .', '2.5.1', 'us', '2025-08-14T10:44:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '12996267119', 'Reviewerxx', 3, 'App is stutters and very buggy after mathjax update', 'This is a great app normally, but I hope the mathjax feature gets more polished soon, or please just revert this app back to previous version until the feature is more ready. As it is, the app is almost unusable for me.', '2.5', 'us', '2025-08-09T12:48:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1016366447'), '12988099936', 'Telugu learning app', 5, 'Best App I have on my phone', 'I love this app!! It’s so useful and a lot better than the regular notes app. Definitely recommend', '2.5', 'us', '2025-08-07T11:30:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14264070053', 'RedDahlia🌺', 5, 'Five stars', 'I really like this app, but it disappoints me to find out you can’t change the color of the line and arrow connecting things, but please add that it would be cool', '1.12.7', 'us', '2026-07-04T17:55:21-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14246050298', 'wisteyria', 1, 'No search feature?!', 'Everything has always worked fine but the last few weeks the search feature is completely broken, displays no results, and attempting to use it will break the rest of the app too and make it impossible to use until i reopen it. Admittedly, I have hundreds of files, but they''re only text files, I''m not sure what is causing this? Should I relocate my files to another vault or something? Use another app? -_-', '1.12.7', 'us', '2026-06-30T10:32:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14242804483', '@hello-new-world', 1, 'Can’t locate my vault in iCloud', 'Good grief it should be super simple to tell it how to locate my vault that is in an iCloud subfolder.', '1.12.7', 'us', '2026-06-29T16:19:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14233139795', 'Mr Mew', 1, 'Requires a subscription', 'Sends new users to their website to pay for a subscription so they don’t have to report in-app purchases', '1.12.7', 'us', '2026-06-27T08:06:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14229086312', 'Key of USA', 1, 'keeps wanting me to pay', 'keeps wanting me to pay', '1.12.7', 'us', '2026-06-26T08:26:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14212898142', 'Owen T Brown', 1, 'Does not load even in new phone', 'Does not load. Black screen, just sits there. When it does load, very slow.', '1.12.7', 'us', '2026-06-22T06:39:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14203163109', 'HackerNickname', 1, 'Not responding', 'App is not responding and cannot open notes', '1.12.7', 'us', '2026-06-19T16:51:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14198969628', 'Hejsjxhdud', 1, 'Onedrive', 'Can’t use onedrive to sync so all my pc notes are staying there ig🫩', '1.12.7', 'us', '2026-06-18T15:04:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14187912869', 'Dimuc G', 5, 'good design', 'use icloud as base, I can sync the PC and mobile side notes, very powerful by MD format', '1.12.7', 'us', '2026-06-15T19:24:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14182314310', 'ArKanGirl', 3, 'The iCloud Sync is a little Glitchy', 'I downloaded this app on my phone and when I went to set up the sync, selecting iCloud as my option, after creating my vault, I got a black screen. There was nothing for me to select, it would not let me create a new note or anything, it was as if it crashed while trying to sync to iCloud or something. I closed out of the app, opened it back up, went through the process again, and still got the black screen of nothing. I even deleted the app and re-downloaded it, went through the process, and still got the black screen of nothing. I had to create a vault WITHOUT setting up the sync in order to get it to work. I might try setting up the sync on my computer to see if that works, but if you are on an iPhone, this app is a little glitchy when it comes to setting up the sync using iCloud. Other than that, it works okay for what it is.', '1.12.7', 'us', '2026-06-14T09:14:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14169645575', 'Swedav66', 5, 'Best app ever, what I wanted for 25 years', 'Solves so many problems', '1.12.7', 'us', '2026-06-11T05:06:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14168833891', 'NewGirlJade', 5, 'Legacy hardware support', 'I can’t express how grateful I am that the app makes older versions available to old iPads, which have lost functionality in a really frustrating way. There used to be apps that worked great, the OS was fast, and browsers actually worked, but now they’ve been abandoned in favor of shinier revenue streams for apple. I’m so glad I can use my old iPad mini 2 (which I paid a lot of money for) to jot down and see my thoughts on the bigger screen and that I can breathe new life into a device I felt bad for not using even though she’s a perfectly good little device which deserves to be useful.', '1.12.7', 'us', '2026-06-10T23:23:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14160029269', 'I’m still bad when I review', 3, 'No free sync', 'Great app for world building the only issue is you can’t access vaults made on one device from another which sucks. I love this for world building but I don’t want to pay 4 dollars a month to sync the vaults once! It slows the entire process and makes me want to use another app', '1.12.7', 'us', '2026-06-08T15:37:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14149615239', 'GoyardJay', 5, 'Inevitable', 'If you like to think - this is inevitably your brain.', '1.12.7', 'us', '2026-06-05T23:36:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14143378743', 'E.K. Hofer', 5, 'World building', 'As an aspiring author, this has by far been the best tool I’ve come across when it comes to world building, developing my characters, and building links and connections between everything. Thank you so much for this app! :)', '1.12.7', 'us', '2026-06-04T08:39:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14137946514', 'appendJared', 5, 'Life changing software', 'Obsidian has made me take notes everyday (for the past 2 years)and my mental health has improved significantly. The dev team has such an eye for design and function; all of your other apps will feel pale in comparison. My favorite features: highly customizable input mechanisms (toolbar for mobile, native vim mode, everything can be a shortcut), daily notes, links and backlinks. Thanks team!', '1.12.7', 'us', '2026-06-02T22:50:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14119475504', 'Just some guy 47', 1, 'Sync non-functional', 'The desktop UI is unintuitive and the sync does not work.', '1.12.7', 'us', '2026-05-29T06:32:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14116045298', 'Halfnelson117', 2, 'So slow to open', 'App is so slow to open on mobile , especially in low latency environments (often on mobile). It''s getting to the point where I may even switch off as it just takes so long to get to an editor.', '1.12.7', 'us', '2026-05-28T08:28:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14115405704', 'zachbugay', 5, 'Best app', 'It’s really the best app out there. Yes out of all apps that exist in the world this one is the best. It provides limitless freedom, and the community driven plugins just add even more value. Use it for just about everything and anything for yourself.', '1.12.7', 'us', '2026-05-28T05:16:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14113882703', 'WebstersBadHairDay', 1, 'just an ad for sync', 'you hardcoded the path so users have no sync choices despite what documentation says. disappointing. i have my files already and the app just doesn''t work for iOS files.', '1.12.7', 'us', '2026-05-27T18:24:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14105094857', 'M Doss', 5, 'No AI :)', 'No integrated AI, thank goodness for that. Very good file system. I can’t recommend any other services higher than Obsidian.', '1.12.7', 'us', '2026-05-25T10:08:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14099516245', 'hcrobg', 5, 'Phenomenal App. Long time user!', 'Just fantastic. I’ve been using Obsidian for years now. Godsend, beautiful app. No notes. 10/10. Highly recommend.', '1.12.7', 'us', '2026-05-23T23:20:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14085292324', 'Karfunkal', 1, 'Useless', 'What is going on with this app!?!?!?! You guys certainly sell a big idea but you fail to deliver. If you have an Apple product AVOID!!', '1.12.7', 'us', '2026-05-20T04:30:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14083478388', 'Davejunk', 5, 'Best app', 'I think Obsidian MD is probably one of the best apps I’ve ever used. It’s allowed me to do so many things keep notes like keep my own data and build applications inside. It’s one of the things I recommend to as many people as I can. The small obsidian team delivers all the time.', '1.12.7', 'us', '2026-05-19T14:53:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14070441137', 'nuIIpointr', 5, 'The single greatest notes program ever made', 'I don''t care what anyone says. Logseq, Anytype, Octarine... none of them are Obsidian. Love you bb.', '1.12.7', 'us', '2026-05-16T03:27:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14063882746', 'Fake Lizard', 5, 'The Best Future Proof Notes App', 'Files over app, even if this app stops receiving support your files will still exist, your notes can carry over to the next app of your choosing. So many philosophies for taking any kind of note from visual, to zettlekasten, to bases and tags, card view, ratting systems, not to mention SEARCH-ABILITY! if you ever forgot the name of a note or have to many files to look thru just use the omnisearch community plug in and find anything from headings to titltes to text in images, honestly the community behind this app is insane.', '1.12.7', 'us', '2026-05-14T08:20:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14060438079', 'Juice805', 3, 'Vault Locations Limited', 'The lack of versatility in vault locations on mobile is a real issue. It can ONLY be in their service, in the Obsidian iCloud folder, or local only. Let us pick where our vault is in Files.', '1.12.7', 'us', '2026-05-13T09:25:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14059409044', 'sdjffjeeojfg', 2, 'So buggy', 'It’s a great Idea for an app, but it’s so buggy. Sometimes 10 minutes will pass before I can access a note - even on a very small vault.', '1.12.7', 'us', '2026-05-13T03:50:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14050097260', 'stephenjayakar', 5, 'obsidian is an apple notes replacement', 'one of the last bastions of good software', '1.12.7', 'us', '2026-05-10T12:16:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14049948422', 'tdubc138', 1, 'Limited sync options', 'Obsidian on iOS lacks the ability to sync with any other service aside from Obsidian Sync or iCloud.', '1.12.7', 'us', '2026-05-10T11:27:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14046377335', 'a.k.a.S.h.a.e', 3, 'WHY?? Mobile overrides desktop', 'I have been using Obsidian sync (paid, no iCloud integration) for more than a year now and have done my own troubleshooting to no useful conclusion: WHY TF DOES SYNC PRIORITIZE MY MOBILE DEVICE STATE OF FILES OVER WHAT I''M DOING ON MY MAC??? I delete something via Mac Obsidian and- POOF!- it comes right back! I can''t reliably edit on my computer and have the changes sync to my phone and tablet. WTF.', '1.12.7', 'us', '2026-05-09T12:48:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14044966631', 'LNY34997', 5, 'Incredibly powerful', 'The more I do with Obsidian, the more I find I can do. It takes a fair amount of upfront configuration but the flip side is you can do pretty much what you want with it. I manage my home, my family and my business with it. Great integration with plugins. Constantly surprised just how much is possible from the iOS version - it’s very full featured and I can do all sorts of things on the move.', '1.12.7', 'us', '2026-05-09T05:19:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14019562144', 'XopxePaMupec', 4, 'The last update broke the iPhone app.', 'After the last and second-to-last updates, the note interface started glitching—plugins would reload every few seconds, the note would reopen, and some of the text would be lost. Ultimately, it became unusable. Nothing else was done to the app other than updating it, and no additional plugins were installed. Device: iPhone 13 mini, iOS 17.5.1 Update: Only a complete reinstallation of the application fixes the issue.', '1.12.7', 'us', '2026-05-02T03:18:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '14010860375', 'ajhqt', 3, 'Obsidian - amazing, app - subpar', 'I love Obsidian so much. The tool itself is incredibly powerful. However, I have CONSTANT issues with the app. My vault functions as my second brain but half the time when I open the iPhone app it is stuck on “loading plugins…” so the thought I just wanted to document has now been sidetracked and, in my effort to refresh and load, the thought is often lost because I can never get the app to load. It’s infuriating and reduces its utility as a tool for capturing thoughts. I’m writing this review after opening the app to take a note, having it be stuck, refreshed multiple times, and 15 minutes later STILL stuck on the “loading plugins” despite multiple times clicking “Reload app”', '1.12.7', 'us', '2026-04-29T16:28:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13989290806', 'Ranger_Dovefalcan', 3, 'I use it because I need to', 'Still a struggle to use compared to the desktop app. Mobile needs to be overhauled for simplicity rather than trying be 1:1 with desktop.', '1.12.7', 'us', '2026-04-23T10:42:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13983719908', 'soundneedle', 4, 'Sidebar sux', 'Way too narrow to be useable. Need to be able to change the width of the left sidebar.', '1.12.7', 'us', '2026-04-21T20:10:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13982024049', 'LovingLich9258', 5, 'Notion for people who are actually tech-savvy', 'I used Notion for a while then discovered Obsidian. It''s truly like night and day. While it takes longer to set up, Obsidian undoubtedly has many more features than Notion via plugins. You can take handwritten notes, insert images, make your own website, free calendar integration, etc. Syncing without the paid Obsidian Sync was a pain to set up but I eventually got it. Notion is easier when it comes to visual customization and templates, but Obsidian cannot be beat on the actual feature front. Also, Obsidian is more secure and doesn''t badger you with any AI nonsense. And if you DO want AI, there''s plugins for that too!', '1.12.7', 'us', '2026-04-21T08:29:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13981105971', 'Shawn’s iPhone', 5, 'i need it 👍👍👍', 'very useful', '1.12.7', 'us', '2026-04-21T02:56:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13979676954', 'quazzimoto', 5, 'I love it', 'I love it', '1.12.7', 'us', '2026-04-20T15:12:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13971582287', 'JohnnyV8', 5, 'The Learning Curve is Worth It', 'As an adult with learning disabilities, I need compensatory tools. At first I thought it might work but gave up after a week and returned to Apple Notes. But Notes had so many issues I tried Obsidian again and I am glad I did.', '1.12.7', 'us', '2026-04-18T09:11:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13959411542', 'Ashdbdbndkw', 1, 'cannot create vault with iCloud', 'iPhone will become black screen. iOS 18.7.7', '1.12.7', 'us', '2026-04-14T22:43:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13959384808', 'Arsenii Z', 5, 'Powerful, private and actually mine!', 'Obsidian is one of the few apps that feels like it respects my brain instead of trying to trap my attention. It is fast, clean, works offline, and gives me real ownership of my notes instead of making everything feel locked into someone else’s system. What I like most is that it can be as simple or as deep as I want. I can quickly write notes on my phone, but I can also build a serious personal knowledge system over time. Syncing, backlinks, folders, graph view, and plugins make it feel powerful without forcing complexity on day one. It is not the prettiest or most beginner-friendly notes app, and some people will prefer something more polished out of the box. But for me, the flexibility, privacy, and feeling of control are worth much more than flashy design. This is the kind of app that feels better the longer you use it. Rare.', '1.12.7', 'us', '2026-04-14T22:28:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13952109462', 'Venik', 1, 'Unclear purpose', 'I have no idea what this app does. It is really bad as a markdown editor.', '1.12.7', 'us', '2026-04-12T18:53:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13951424329', 'Brenntron', 5, 'Amazing Personal Notes App', 'I use this daily to organize my day.', '1.12.7', 'us', '2026-04-12T13:53:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13945033419', 'lemols', 4, '最后一个文件看不到', '在软件左侧的侧边栏展开全部文件后，最后一个文件的名称隐藏到最下方的里面去了，只能显示很少的一部分，看不全', '1.12.7', 'us', '2026-04-10T20:21:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13941459284', 'JonAuro', 3, 'Has become unusable', 'Everyone I open it the “indexing..” goes on for 20+ seconds. Back and forth if switch out to copy paste text for a minute. Doesn’t stay in reader mode. I try to select text and when I do it switches out of reader mode despite me not wanting to write . So now I have to be careful to notice if I hit space bar to deselect text and not erase it, because if I don’t deselect and try to scroll up it creates a new document and then I lose my place… I’m just trying to be a regular user but it takes too long to load every minute and I can’t stay in reader view when copying text', '1.12.7', 'us', '2026-04-09T20:17:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13936257746', 'J. M. Jones', 5, 'Indispensable', 'Can’t sing its praises enough. Just an essential, wonderful piece of software for managing notes. One of my favorite pieces of software ever. I hope the team holds strong and keeps doing what it’s doing, while ignoring any of the noise or monetary temptations that have to exist around them, and would ruin this project.', '1.12.7', 'us', '2026-04-08T09:21:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13931010921', 'Playoff97', 1, 'Can’t connect to iCloud vault', 'I can’t acess my iCloud vault whenever I press iCloud it says no vault detected', '1.12.7', 'us', '2026-04-06T21:28:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1557175442'), '13926175746', 'AppFzx', 1, 'Black screen', 'Black screen. Won’t load.', '1.12.7', 'us', '2026-04-05T12:05:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14266721795', 'jaaaaaycub', 3, 'Slow launch time', 'When I need to make a note, I need to make it now. Fraught iCloud sync and periodic updates make it so there is a lag between opening the app and when I can start working. I’m not sure if Apple prompts the review pop up or if the app developer controls that, but whenever I get that pop up I am compelled to leave a negative review as it prohibits me from getting to work. Goodnotes gets 3 because it is generally pretty great (once the notebook loads!)', '7.1.0', 'us', '2026-07-05T09:59:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14264434628', 'Dr.Rahat', 2, 'LINK CAN BE IMPROVED DRAMATICALLY', 'please make it easy for linking between documents/Pdf that i made. For example, if I want to link a word to a page of another pdf, i have to go to that pdf and see the page number of that particular page and then have to return back to my current pdf and then add it by browsing there to that particular page of the pdf. ********It will be great, if you can make a “way to copy a link of Any page, “so that i can directly paste the link / add link to any particular word in another pdf without scrolling and going to that particular page of another pdf from this pdf', '7.1.0', 'us', '2026-07-04T20:23:07-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14263559387', 'PinkPonky', 4, 'Pretty good', 'I use this for lecture notes and it’s pretty good. Only draw back is when I export my daily lecture as pdf , the pdf loads funny. I also wish I could modify the top tool bar to my liking more. But overall I think the app is great', '7.1.0', 'us', '2026-07-04T14:21:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14263311939', 'Erick 718', 5, 'The Best!!!', 'If you want to organize your life ,this is the app to get', '7.1.0', 'us', '2026-07-04T12:47:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14263010232', 'LolaPR1', 1, 'Fix glitch', 'When i search something and then click X to erase the search words, it closes up the whole document. Frustrating.', '7.1.0', 'us', '2026-07-04T11:03:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14262782711', 'Badtouse', 1, 'To hard to use', 'Does not work Iike they say it does', '7.1.0', 'us', '2026-07-04T09:52:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14260037686', 'Protect our Kids.', 4, 'Code Blue', 'Review of Dispatcher narrative and communication between officer’s Response', '7.1.0', 'us', '2026-07-03T17:42:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14255955758', 'Usagi83', 4, 'Tape Tool Issues', 'The tape tool doesn’t save imported tapes. Otherwise, everything is great.', '7.1.0', 'us', '2026-07-02T18:14:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14255771540', 'Dingleberry2000', 5, 'Good app!', 'Super useful and helps to keep a lot of thoughts and teachings organized and safe. I would 100% recommend for school,church,journalism and even drawing! Very helpful and easy to use. And it even gives you 3 free notebooks to start with and a good deal to get more afterwards which I guarantee that you won’t regret. ☺️', '7.1.0', 'us', '2026-07-02T17:04:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14255712264', 'Thecreator87', 5, 'Must have', 'has really helped transform my notes\ Assignments for classes over the past three years', '7.1.0', 'us', '2026-07-02T16:42:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14255513304', 'KACPSD', 1, 'Low number of Ai credits', 'I ran out of Ai credits after only one meeting.', '7.1.0', 'us', '2026-07-02T15:27:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14253957110', 'Erikarr443', 2, 'Photos', 'It was easy to put screenshots like a moth before, now when you try it shows the whole screenshot even when you already cropped it and is saved in pictures cropped, and you need to make it small yourself.', '7.1.0', 'us', '2026-07-02T07:26:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14253179586', 'Blue293', 3, 'Been A Supporter From Day One!', 'I have been with Goodnotes a long time. Have been a strong supporter. Rarely any issues, well complaints. Other issues seem to be corrected with update Kudos! However, the dropdown to access the toolbar to get started is not accessible unless you’re in Full screen mode (window). The red, yellow, green buttons cover the tool bar. It’s safe to say most of us probably aren’t in full mode most of the time. I have pics but can’t upload. When Apple changes their setup, you have to change yours. Please correct this, other apps have. Thanks.', '7.1.0', 'us', '2026-07-02T03:39:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14252844715', 'الكحلي ١١١١', 1, 'CRASH', 'lifesaver app but crash so many times even with a lot of empty space and extra space in iCloud for sync', '7.1.0', 'us', '2026-07-02T01:32:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14252355213', 'So-over-it-dani', 1, 'Paid for subscription and it has said no subscription since!', 'It may have been a great app once but I have not had a useful experience with it at all which sucks. Waste of money for the yearly subscription and waste of time to download. I paid on June 18th and it has not showed my subscription yet!. I do not recommend at all.', '7.1.0', 'us', '2026-07-01T22:12:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14250862196', 'MoSki1122', 1, 'Disappointed with subscription model', 'I was disappointed to login to my account to discover that I have to repay for notebooks that I already had access to, due to whatever new subscription model you all have decided to change to. I paid a one time fee which means I should still have access to all of my notebooks that I originally had access to, not just 3. I will NOT be paying to upgrade and will explore other pdf apps.', '7.1.0', 'us', '2026-07-01T13:02:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14250586734', 'Armitaq', 5, 'Great app,but password recovery needs improvement', 'i’ve been using Goodnotes as my primary note taking app, but I’ve hit a major block. I forgot the password to my locked notes and didn’t enable biometric unlocking as a result I’m currently locked out of my important Notes and for some reason, the app also prevents me from creating any new locked notes. it would be incredibly helpful if you could implement a new password recovery option or a way to access great app overall, but this limitation is quite frustrating.', '7.1.0', 'us', '2026-07-01T11:34:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14246598000', 'jass419', 2, 'Doesn’t Sync Well', 'I’ve had to redownload the app on my MacBook multiple times just to log in and get my stuff synced between the laptop and my iPad', '7.1.0', 'us', '2026-06-30T13:21:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14246305708', 'ChocoChipCappucinos', 3, 'It won’t let me upload photos', 'Every time I try to upload a photo it kicks me out of the app! Wish it was fixed, I love this app!', '7.1.0', 'us', '2026-06-30T11:48:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14244452207', 'kfoster', 2, 'Great on MAC but..', 'A very significant limitation is the poor compatibility with MS Windows. I bought this expecting a seamless connection on my windows and Mac computers, but it didn’t happen. Can’t recommend it to users who plan to use it on these two systems.', '7.1.0', 'us', '2026-06-30T03:01:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14241354324', 'Oswin Katerina 14', 5, '💖💖Love but one thing!💖💖', 'Please read! I love ALL the stuff that GoodNotes has. but i started my 7 day free trial and I don’t like that you have to pay for using this app and i have searched everwhere for this kind of App and I found one. Sadly it cost money and I don’t want to pay for something that I would use only on school days and writing essays. but if you are willing to pay I would DEFINITELY recommend this app!!! Thank you for reading and sorry if my spelling is wrong and how I wrote this bye thanks for reading!!💖😊 Also to the app maker thanks for making this app but please make it free!', '7.1.0', 'us', '2026-06-29T08:25:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14240078884', 'Lavya rasheed', 5, 'Çok iyi bir uygulama', 'Gerçekten mükemmel bir uygulama denemenize tavsiye ediyorum bir haftadır kullanıyorum ama çok memnunum 🤍👌🏻', '7.1.0', 'us', '2026-06-29T02:02:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14239176303', 'Bawedert', 3, 'It doesn’t let me download “free” products for the Essential subscription', 'I’ve already updated the app and tried many times (on different days) but still says that an error occurred and to try later.', '7.1.0', 'us', '2026-06-28T19:37:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14237673157', 'Goodnotesbad', 1, 'Lost all my notes', 'I’ve used this app for notes for this past year. I was going to export my notes when the app froze and kicked me out. When I went back on, all my notes were gone and had disappeared! Absolutely terrible experience!', '7.1.0', 'us', '2026-06-28T10:22:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14237133650', 'Kat Cal1229', 1, 'Get One Note', 'They just emailed me with a no reply email that my account is being deleted in 7 days for no reason. Signing in to my school account has been a nightmare. Don’t pay for this just go Microsoft and save yourself the hassle. No customer support email is crazy', '7.0.66', 'us', '2026-06-28T07:45:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14235520832', 'JoysiKaii', 1, 'Membership shihht', 'I paid over $9 to have access to more notebooks last year and it was not a membership now my payment was unliked from my account and keeps giving me this message to upgrade and pay a membership not worth it I rather use files on my iPad.', '7.1.0', 'us', '2026-06-27T22:06:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14235018946', 'Willibups', 5, 'Scam', 'I have been using this app for years. I bought the app and now I can’t use it or access my account unless I pay a yearly payment.', '7.1.0', 'us', '2026-06-27T18:56:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14234479661', 'Matheush719', 5, 'Major issues with login and account syncing', 'I have encountered numerous issues with syncing Apple accounts, Google accounts, Microsoft, you name it. Just poorly designed account management system. Imagine being unable to edit your notes and documents at any random update or change of credentials, with support taking forever to reply. The app itself is okay, but no good if you can’t use it.', '7.1.0', 'us', '2026-06-27T15:31:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14233459492', 'None5522', 1, 'The changing subscriptions for this app are horrible', 'The changing subscriptions for this app are horrible. App with data locally stored but a person can’t access or edit their own data. It’s a joke. Don’t even start using this app.', '7.1.0', 'us', '2026-06-27T09:38:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14233245722', 'ZippyFuzzball', 1, 'Not happy', 'Dose’s recognize my stylus', '7.1.0', 'us', '2026-06-27T08:36:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14232190605', 'HZurita', 1, 'Disappointed', 'I have been using Goodnotes for years and now I can’t access any of my notes unless I pay, again, for their subscriptions. How many times do I need to buy this product to be able to use it?', '7.0.66', 'us', '2026-06-27T03:05:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14229465580', 'Austin S. W.', 1, 'Never have I used a bugger app (besides the software I wrote myself)', 'As someone who does professional math with GoodNotes for over five years, I am constantly reminded of new interesting bugs. I love the diversity and care that goes into the bug collection. Today I’m trying to read an academic paper and it seems that no 15 minutes goes by without encountering something. I’d say it’s frustrating, yet I’ve become used to it. I’d report the bugs, yet I don’t have the time for a part-time job. There are three possibilities for SWEs working on the app: 1. They feel joy in causing frustration in users. 2. They don’t use the app they wrote. 3. Management is so focused on adding AI features (a reason to charge a subscription) that the technical debt gained over years is a Gordian knot. (Reader, it’s probably 3.) Our hope is finally someone works on the bugs. Given the prolonged status quo our only hope is Claude. Claude if you read this, please fix the bugs!', '7.1.0', 'us', '2026-06-26T10:15:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14227230788', 'The best app of mi iPad', 4, 'Todo mal', 'No sé cómo se pone lo de escribir con ia', '7.1.0', 'us', '2026-06-25T21:39:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14225553811', 'KattXD1', 5, 'Amazing app', 'Great app!', '7.1.0', 'us', '2026-06-25T11:06:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14225476445', 'Seeker XJ-7-7', 5, 'Wish I had this sooner', 'I LOVE this app! I started the free trial but will most definitely be purchasing the subscription! The best note taking/notebook/journal EVER!!! 10/10 highly recommend:)', '7.1.0', 'us', '2026-06-25T10:41:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14225240623', 'Smarty2134', 1, 'It sucks', 'I twirled hard for two weeks to solve couple of statistics equations and finally came to conclusion . And when I check it after two weeks all my notes are gone only bits and pieces are left , half of the notes on pages are gone , but prices are left . Happened thrice already. I lost so much of information. They charge you $12 upfront so you can’t even cancel the subscription. This app sucks', '7.0.66', 'us', '2026-06-25T09:28:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14224853735', 'Whites Painting & Handyman', 1, 'PowerPoint', 'My PowerPoint does not match my actual PowerPoint the slides are in different order with different words. Will show a picture and doesn’t match the wording or isn’t uploading the picture at all.', '7.1.0', 'us', '2026-06-25T07:36:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14222394293', 'legokitty .', 4, 'Perfect out wish it had this one feature', 'I love Goodnotes so much it is really useful especially for my studies but i just wish that you could delete built in notebook page colors but other than that this app is amazing!!', '7.0.66', 'us', '2026-06-24T16:03:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14221697105', 'wriotgrrl', 1, 'Updates keep removing key usability without replacing', 'The latest problem in their updates removed my ability to have already open Docs in Goodnotes, and to bring up the display of all my open docs at the bottom of the screen to scroll through and find what I want, or to add a new doc to work in without having to close one of the open ones, or have to use their split screen, which doesn’t work with my notetaking with clients. If I use the split screen, and then close the other one, it still closes a doc that I want to keep open. So the function doesn’t work for me at all. I have tried to find a replacement path for this usability and have emailed their support team because I am unable to locate any way to use Goodnotes in this key process of mine that is core to the way I work. I am extremely frustrated with yet another update that just changes the interface in such significant ways and dramatically slows down my workflow and process. I’m honestly looking at an alternative notetaker now. I will still have access to my current notes because I have a lifetime subscription, but it is not really usable for me without this functionality moving forward.', '7.0.66', 'us', '2026-06-24T11:52:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14221417391', 'Zacouwa', 2, 'The app became worse as time went on', 'I used it to study flash cards through my medical program. I could before scroll up and down on my flash cards with a longer explanation. As I continued to use it, this feature got harder to use and now I can’t even use this feature on my iphone make me redo likely over a thousand of flash cards before my state exam. Im not paying for this app anymore or recommend it.', '7.0.66', 'us', '2026-06-24T10:22:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14220942779', 'RM Vice', 3, 'Overall, it’s decent', 'The app itself is a great app. The issue comes up if you’re using an Apple Pencil. The latency is high and the lines cross slightly (giving you a small hook) when you lift the pencil to start the next word\letter. i will tend to look like an upside down r I ensured the reduce latency was on and tried it off, pencil is new but still tried swapping the tips, and i disabled the hover (helped a little). I don’t want to stop syncing as that wouldn’t be beneficial for me using the app.', '7.1.0', 'us', '2026-06-24T08:01:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14220769989', 'Player longing to play uno', 1, 'DON’T WASTE YOUR MONEY', 'This app is always glitching and has terrible storage/syncing even when I set up my iCloud to it. I just cancelled my subscription and will be using another application for my notes/studies. As a doctoral student apps like this are extremely important to me, so having one that glitches 24/7 that holds all my important documentation it is detrimental to my studies and progress in my program.', '7.1.0', 'us', '2026-06-24T07:12:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14220749260', 'whatamIdoinghereImunhappy', 1, 'Paid for app to be forced to pay for a sub', '>pay good money for app >app introduces subscriptions retroactively >app useless without paying for subscription >lawsuit filed', '7.1.0', 'us', '2026-06-24T07:06:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14220241045', 'FvshionKillaa', 3, 'Sync function sucks', 'I do work on my iPad and laptop and there is always an error message when it comes to syncing my laptop. Please update the app because this is very frustrating.', '7.1.0', 'us', '2026-06-24T04:30:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14220183949', 'Ali Hamid Abduljabbar', 5, 'Great App', 'Fantastic trying with “Goodnotes”', '7.1.0', 'us', '2026-06-24T04:09:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14217269310', 'Asavvix', 2, 'Barely does what it needs to do', 'Many bugs. Every update there’s a chance some of the features might not work like they should. Right now, for example, I can’t import files (ongoing issues for months).', '7.0.66', 'us', '2026-06-23T09:15:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14214446911', 'clenching fists in anger', 1, 'SO LAGGY', 'app has some good features like customizing notebook cover and pages, customizing toolbar, and considering palm rejection in the ways you hold your pen. BUT the program is so laggy where you write lines and it becomes dots attaching together. This happens in unlimited whiteboard AND regular notebooks when you near a "max" in how much content you put into the tab. Laggy especially nearing an update or after an update. I WISH i could attach a screenshot so i can show. The app also lags on swapping between pen and eraser, so the eraser doesnt erase or erases the part you want and then some dots show back up. Im 🤏 this close from screwing my 35 dollars one time fee and finding a new app or going back to stones and a chisel. Not to mention the palm rejection doesnt work for the common ways people hold their pens, despite 6 different kinds.', '7.0.66', 'us', '2026-06-22T14:56:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14214061772', 'Morarasg', 5, 'Great ap', 'Great simple app', '7.0.66', 'us', '2026-06-22T12:38:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1444383602'), '14213947069', 'Ceovante', 4, '9.5/10 note taking app', 'It refreshes almost every time you try to open books. There’s no way to cut it off. There’s no longer a way to see the size of the documents. They took this away. Note taking is top tier. I use this app constantly and it has proven reliable. Overall, this is the app you want for graduating from the university to working for your own practice. 9.5/10', '7.0.66', 'us', '2026-06-22T12:00:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14263099016', 'Dichromtastic', 1, 'Fix squeeze gesture!', 'Recent update ruined the squeeze gesture by forcing you to interact with a palette to switch to the eraser tool instead of allowing you to auto-switch to eraser. This makes you do an odd movement with your wrist to reach and select the eraser tool, which SIGNIFICANTLY slows down your work progress. I’m seriously questioning why the palette was introduced as a mandatory feature when it completely nukes the smoothness of using the app. At this point, might as well save some money and use Goodnotes.', '16.5.2', 'us', '2026-07-04T11:32:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14262965193', 'Anônimo 1010', 5, 'Excellent', 'I’ve been using it for years, and I love it. Much easier to study.', '16.5.2', 'us', '2026-07-04T10:48:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14255324362', 'Imadeitnursingschool', 5, 'Nursing School', 'This has been the best thing ever for note taking and lectures', '16.5.2', 'us', '2026-07-02T14:17:15-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14251583288', 'Malevolentmoon', 1, 'Uploading and Saving Notes', 'I would love to to rate this 5 stars, but until now, I have never experienced the lack of having to reupload my notes, and having to figure out each one. I made the mistake of syncing the app to my iCloud. I normally use Google Drive, and so when I went to open my Notability app, the notes were gone. I figured, I can reupload them, but lo and behold: you have to upload them manually and individually. It would be super cool if the backup system could upload as one has their set-up.', '16.5.2', 'us', '2026-07-01T17:26:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14251126194', 'charleigh kilo', 5, 'Pretty cool app', 'So far so good I just hope it has enough room on it in the folders for all my read later documents', '16.5.2', 'us', '2026-07-01T14:34:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14251081619', 'śæráh', 1, 'Update hate it', 'They changed the Apple Pencil connection so when you squeeze it instead of it ONLY being the eraser now you have to choose. That’s a Good Notes feature that I hate and a a reason I use note ability. Switch it back, this is so inefficient.', '16.5.2', 'us', '2026-07-01T14:18:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14250409844', 'Angela3perez', 1, 'FIX ASAP', 'Please fix the app I am debating switching apps as my notes never load. Sometimes they are there sometimes they are not. I am paying for the highest subscription therefore I am thinking should be the best. Please fix it asap before I finally give up and get a new app.', '16.5.2', 'us', '2026-07-01T10:40:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14248622728', 'dJ CV', 1, 'Constant log-ins delay the note taking activity for too long to be useful', 'Have been using Notability on iPhone and iPad for years, have been recommending it to so many people. With some recent update, it requires me to log-in every time, instead of just opening. Mail with code takes way too long to be delivered. When I want to take a note, the app needs to be ready immeaditely, not take minutes of my attention and occasions to pass.', '16.5.2', 'us', '2026-07-01T01:43:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14248104244', 'Netflixkid1000', 5, 'Love this app', 'this has been so helpful in my school work.', '16.5.2', 'us', '2026-06-30T22:17:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14246826434', 'Via Salutis', 1, 'For over a Decade', 'I have been using Notability forever. I paid for the full version and then I started subscribing. As a subscriber I decided to use Notability Cloud syncing. I was surprised that I could not also use Apple iCloud sync and backup. This is a deal breaker. And now, I cannot revert back to Apple iCloud sync and backup. WHY? Please allow me to do both or at least allow me to go back to using my Apple iCloud storage and backup that I also pay for. This is a sleight of hand that is disingenuous and not fully transparent. Please change your new policy and allow your paying customers to revert back to Apple iCloud sync and backup.', '16.5.2', 'us', '2026-06-30T14:40:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14246611593', 'RiversCa', 1, 'NEW UPDATE SUCKS', 'The eraser feature sucks now! You used to be able to just hold down the button on the Apple Pencil, now you have to move your hand unnaturally every time you want to undo something. This has seriously slowed down my workflow. I wish you can just switch back to how it was before, but nope, you’re stuck with it whether you want it or not. Cancel your subscription if you have one, or just don’t buy one if you don’t.', '16.5.2', 'us', '2026-06-30T13:25:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14246610202', 'AlixAlix1', 1, 'Bring back option to squeeze to erase on Apple Pencil', 'Bring back the squeeze to erase option! Pretty annoying that there is an extra step just to erase now when it was extremely simple before.', '16.5.2', 'us', '2026-06-30T13:25:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14245297596', 'javanmard110', 4, 'RTL option', 'I’m using notability for years and very satisfied with it but recently forced to move to another app because notability do not support RTL option for specific note Please add it in your next release', '16.5.2', 'us', '2026-06-30T07:13:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14242960645', 'Waysys', 1, 'New version fails to work', 'I have used Notability for over a year. It provided a simple, yet powerful way to take notes on my iPad. I could then print the notes to my printer. Recently, the app changed. Now, to print I have to log into a Notability account. But once I do that and I try to print, the app asks me to log into again. When I do this, the app says I am already logged into again. Several other features like converting to PDF have the same problem. I tried to print a note by accessing the Notability website. I tried to import a note, but I got an error message that the import failed. No reason was given. I have cancelled my subscription.', '16.5.1', 'us', '2026-06-29T17:20:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14242827266', 'rsfs', 1, 'They will loose your notes/data!', 'While I loved the convenience and ease of using this platform to take and store notes, the platform is unreliable and they lose your data! Don’t rely on your important notes to be there from day to day! They involuntarily switched me from iCloud sync to their cloud services. When I contacted them it took me multiple times to get through to a live agent. Most of the inquiries all go through AI. And the hope of an actual chat to resolve anything is nonexistent. When I follow the directions and switched back to iCloud sync I lost 45 days worth of important notes. Once again impossible to chat or contact an actual person. No explanation nor Resolution was offered even though I’m on the paid Pro version! So I will be moving to a new platform.', '16.5.1', 'us', '2026-06-29T16:28:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14242546013', 'Joe Robinn', 1, 'PLEASE HAVE AN OPTION FOR SQUEEZING THE APPLE PENCIL AND TURNING ON THE ERASER', 'Before the update, I loved to use notability, especially with the efficiency of being able to quick select the eraser just by squeezing the apple pencil. Now that it has been removed, it is quite irritating to have to select eraser over and over again. It was so efficient before, please have an option to revert the controls from the update.', '16.5.1', 'us', '2026-06-29T14:38:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14241125387', 'RoarkSG', 1, 'Terrible update', 'Long time user of this app for at least 5 years. Now they force me to use their cloud services and must log-in. I’ll switch to using Goodnotes instead.', '16.5.1', 'us', '2026-06-29T07:25:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14240163839', 'Zayyar7777', 1, 'Poor Syncronization after update', 'Annoying backup after app update... i cant even import files from icloud.. its only good for newbies... So many bugs after update... Old user like me became dispointed...', '16.5.1', 'us', '2026-06-29T02:36:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14237960040', 'Emerald Jade Greenball', 1, 'Ugh', 'I’m so upset. It’s not free. I was looking for an app that was free but apparently this isn’t it.', '16.5.1', 'us', '2026-06-28T11:54:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14236706729', 'Shimuo3', 1, 'WORSE NOTE APP EVER', 'I have been using this app since I started college and have had everything backed up on my iCloud and google drive didn’t have a problem with this app until recently. After coming back from athree month break of using this app all of my notes started to redownload for some reason and so I waited FOR A WHOLE DAY to try and re use my notes so I can send it to my professor. SINCE IT WAS TAKING AGES TO REDOWNLOAD I decided to go to where my notes were backed which was google drive BUT SINCE IT WENT TO THE DRIVE THEY USE A ZIP FOLDER WHERE U CANT EVEN LOOK ATBTHE NITES ANYWAYS USELESS BACKUP. Then I decided to go to my iCloud back up but since I haven’t used my iPad for quite sometime my iCloud decided to re back up EVERYTHING so that also took ages to open. Then I decided to turn my iCloud on and off for notability(hind sight bad idea ik but I was tired of waiting) and when you turn off the iCloud backup it tells you if you want to keep all of ur notes and I did choose that option BUT IT DECIDED NOT TO AND IT SO THEN DELTED EVERY SINGLE NOTE I HAD FOR MY FOUR YEARS OF COLLEGE AND NOW. DONT USE THIS GODFORSAKEN APP EVER', '16.5.1', 'us', '2026-06-28T05:39:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14235370030', 'cjx05685', 1, 'Used to be a good app', 'Now I need to create an account to access the notes I’ve been taking for the last 8 years… all so I can be forced to use their stupid cloud service', '16.5.1', 'us', '2026-06-27T21:06:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14233839525', 'dre26892', 1, 'iPad Pro M4 OVERHEATING', 'Simple note taking overheats my ipad', '16.5.1', 'us', '2026-06-27T11:37:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14230692994', '5eany3oy', 1, 'New squeeze update is terrible', 'I’ve been using this app for awhile it was perfect for taking notes in class now the new update has come out and has ruined this app for me now with the new squeeze feature you have to select erase which adds another step to taking notes while before you would just squeeze and be able to erase I’m going crazy with this new update small mistake while taking notes now take slightly longer to fix and in a math lecture that goes quick those extra seconds mean less time focusing on the material', '16.5.1', 'us', '2026-06-26T17:32:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14230502353', 'Cherry dee', 5, 'Use it if you’re in school!', 'This is one of the coolest apps if you’re in undergrad or graduate school. I’m able to download professors slides right into the app, mark it up, take notes that AI will use to create a quiz, etc. just a very cool app that bridges the traditional note taking for me-pen to paper, which is how I retain information-but also adds really cool technology features in a mindful way that doesn’t feel overwhelming or just part of the “trend”. Very worth the renewal fee in my opinion lol.', '16.5.1', 'us', '2026-06-26T16:20:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14229917008', 'Neviermore', 1, 'Frustrating update', 'Latest update introduced a significant change to Apple Pencil functionality with no way for the user to revert to the old system- press used to erase and now brings up a mini menu to switch between every tool… except the eraser. Very annoying and diminishes the user experience. The AI integration was annoying enough but at least was ignorable, but this is beyond frustrating.', '16.5.1', 'us', '2026-06-26T12:42:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14229169915', 'Sy0131_88!', 1, 'Not good.', 'I paid premium and not even using a full ‘learning’ they said I used maxed. And if I wanna talk with customers service it’s AI just telling me to update my membership. Which $99 no way. Something wrong with system :( terrible !!', '16.5.1', 'us', '2026-06-26T08:50:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14226134298', 'appreviewer284', 1, 'Please get Goodnotes instead', 'Deleted 5 years of notes from all of college. Can’t get them back.', '16.5.1', 'us', '2026-06-25T14:28:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14225994785', 'Chisum220', 1, 'Don’t Use With 2026 MacBook', 'Going back to good notes. Notability freezes my MacBook Air. There is a syncing problem with iCloud. Maybe can save someone some money. If using a newer MacBook go with Goodnotes. IMO', '16.5.1', 'us', '2026-06-25T13:36:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14225355291', 'Comeyouguysseriously', 1, 'So many bugs and crashes', 'This app used to be free but now you pay for it to crash and lag', '16.5.1', 'us', '2026-06-25T10:03:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14222599823', 'Bill McMains', 1, 'Was good, updates have killed it.', 'As with a lot of tech platforms/apps, they updated it and killed its value, at least for my uses. Was a great app, and has potential, but changes made it very unfriendly to the user. Switching all docs/usage to other apps.', '16.5.1', 'us', '2026-06-24T17:23:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14222233852', 'dresive01', 1, 'Bring back the eraser squeeze', 'I loved this app, until the update ruined it. Atleast give us the option to revert it. Also remove the AI slop, just focus on being a good note taking app. Keep it simple Stupid.', '16.5.1', 'us', '2026-06-24T15:01:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14221126104', 'ghdryJfxohho', 3, 'bad update', 'reverse the apple pencil update PLEASE or give a option to change it back. it’s not more convenient it’s actually quite annoying', '16.5.1', 'us', '2026-06-24T08:54:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14221067589', 'itsyahhgirl_dede', 1, 'BRING BACK PRESS TO ERASE PLEASEEEE', 'I love the app and everything but I do not like the new update they did yesterday. We should have the option if we want to press our pencil to erase or show the tool bar because everyone is different. It’s been bothering my study time. Pressing to erase was just so much easier now we have to press and tap the erase button and have the tool bar in the way', '16.5.1', 'us', '2026-06-24T08:37:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14220778981', 'zen_720', 1, 'Nothing works any more after update. WTF', 'I don’t know what happened with the latest update but now the app just lags, I have to restart it like 7 times in a single meeting because it’s frozen. All is slow and lagging. Do I need to find a new note taking solution??? Have been using this for years (previous review below), but now it’s useless. —- This app has everything I’ve ever wanted and more. I love all the thoughtful features and design tweaks. So many times while using it (after just having it less than a week) I’ve thought “I wonder if it can also do ____?” And every time answer is yes. Unlike many of the reviewers whose feedback I’ve read, I’m not a student (I WISH this had been around when I was a student) but a mid-career professional working on a variety of different projects with tons of meetings, calls and project documents to read — and this app is absolutely perfect for seamlessly tracking notes and details of meetings as well as marking up all the PDFs and Word documents I have to go through while keeping everything in one place. (And I can just slide all my PDF files from my computer into the Mac app window and they’re ready for mark up on my iPad! Fantastic). So many trees can be saved with this, ha. Could not be happier 🤗 it’s almost making work fun ;)', '16.5.1', 'us', '2026-06-24T07:14:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14219076846', 'Wildkatt1360', 1, 'App gets worse with every update. Deserves 0 stars.', 'Every update this app gets worse and worse, and they change things for no reason. I’ve been using this app for ten years now and every update has been a serious downgrade, especially in the past 5 or so years. If you think you like it now, half the stuff you like will probably be changed drastically in the next three years. The devs can’t seem to leave anything alone. You used to not have to sign in, and now you have to login to access the notes that are saved *on your device.* Notes used to have plenty of space, until they changed up the spacing, the font size, and the default font to all be substantially larger. All notes are effectively double spaced by default, and the spacing cannot be reduced to a reasonable size. And the note compresses your text into the center, leaving about an inch of empty space on either side of the note. Moving text boxes is incredibly janky if you have any other insert anywhere in your note. Duplicated text boxes also somehow don’t remember the settings that the original text box had. Once you have more than 50 or so notes created, the entire system becomes noticeably slow. Not sure how that can even happen on a literal note taking app. Overall the developers of this app seem to be more dedicated to what could generously be called quaint features like adding college ruling (who cares) to notes instead of actually fixing any of the myriad issues, or even just adding the ability to toggle old features and formats. Save your time and download any other note taking app. There’s no feature on this one that makes it worth it anymore.', '16.5', 'us', '2026-06-23T20:18:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14218869570', 'MikeyDTheAP', 1, 'New update awful', 'I’ve been using this app for years and it’s been wonderful now I’m stuck because I pay for it and I can’t use the app for more than 30 seconds without it freezing up on me.', '16.5', 'us', '2026-06-23T18:53:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14218628639', 'Dreamlyva', 5, 'Perhaps the best note taking app out there!', 'I have loved and used Notability for about a year now. I have tried a few other apps and none compare to how easy and slick Notability is. I am especially grateful for the PDF highlight function – saves me so much time. I have two suggestions for improvement in future updates: 1) please make it possible to remove the tool bar. I love how easy it is to push to the side in Apple Notes and keep wishing I could just have the PDF full-screen without constantly adjusting to the tool bar line; 2) sometimes the pencil glitches and is not consistent with the Apple Pencil angle – it becomes wide and smudged even if nothing changes in how I hold the Pencil. Other than that the app is wonderful! Thank you for keeping up the good work!', '16.5', 'us', '2026-06-23T17:16:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14217661534', 'saddkayy', 1, 'Used to be my favorite Note Taking app', 'This app was my ride or die and I swore by it. I recommended it to all my classmates and it has been great. Unfortunately this latest update has ruined the experience of the app. Now that I have to pay $99 for one of the best features of Smart Notes I am now seeking other options. This feature enhanced my experience as a student as it allowed me to have an outline to take notes. I found notability to be a perfect middle ground tool for education as pursuing an education is already expensive and demanding. Notability was something that I felt supported the rigorous opportunity of pursuing an education. I hope they reconsider these updates to the payment plans.', '16.5', 'us', '2026-06-23T11:18:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14217579442', 'JCols90', 1, 'Forcing accounts + their own cloud', 'With the most recent update Notability is now forcing you to create an account and use their cloud service even if you aren’t interested. Time to move to competing apps.', '16.5', 'us', '2026-06-23T10:52:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14216832355', 'V jdshg', 2, 'Has had so many bugs since you added ai', 'App should remove ai as it’s bad for the planet and unnecessary at least give an option to turn it off as it slows the whole app down in addition to killing the planet', '16.5', 'us', '2026-06-23T07:05:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14216063125', 'JBZiPhone', 1, 'Notability Cloud destroyed years of work', 'I’ve been a Notability user since day one — recommending it to family, friends, and coworkers without hesitation. That loyalty makes what I’m about to say even more frustrating. After migrating to Notability Cloud, everything broke. Notes lost their formatting entirely — PDFs and handwriting are compressed and jumbled together. The app freezes constantly, lags on every action, and is essentially unusable. What makes this worse? Support responded with an automated message acknowledging it’s a known issue — meaning this shipped broken, and users are left waiting with no timeline for a fix. Notability earned its reputation over years of quality. One careless update shouldn’t be allowed to destroy it. I hope the team treats this with the urgency it deserves.', '16.5', 'us', '2026-06-23T02:37:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14214744650', 'Abradner', 1, 'Update Ruined Snap to Grid', 'The only reason I have stuck with notability for so long is the geometry and snap to grid capabilities. The most recent update has removed that for ellipses and circles. Rotating ellipses non longer snap to horizontal or vertical alignment when you get close - you just have to eyeball it. The same goes for aligning edges of circles and ellipses with the grid in graph paper templates. I used to love using notability because I could make beautiful, geometrically perfect diagrams and repeating patterns, and I could align shapes and lines better than any other platform allows. Now it is just like any other note taking app. I am praying that this is a temporary bug that gets fixed in a future patch. To the devs: PLEASE BRING BACK THE OLD SYSTEM FOR SNAP ROTATION AND GEOMETRY. I have been successfully convincing fellow STEM students to switch to notability for years based on these features. It was perfect and whatever changes have been made have completely ruined what made it special.', '16.5', 'us', '2026-06-22T16:54:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14214622337', 'joncole2014', 5, 'A great note taking app', 'I was looking for something that functioned like the native Notes app and OneNote from Microsoft for my math and engineering classes—Notability did the trick. It has near zero latency for the Apple Pencil, big fan of the math conversions, and allows pretty great customization. One thing I wish Notability had is “digital notebooks” that I can section off, similar to OneNote.', '16.5', 'us', '2026-06-22T16:05:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14213701918', 'McBoone', 1, 'Constant Barrage of Upgrade Requests', 'This used to be my favorite and most-used app on iPad. Now, it generates a constant barrage of full screen upgrade requests that you constantly have to close in order to use the app. Moving on, Notability. Unfortunately. I really liked the app.', '16.4', 'us', '2026-06-22T10:41:10-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14212852812', 'BigNavyLDO', 4, 'Great app', 'This app has significantly increased my ability to review sermons and test myself on the sermons', '16.4', 'us', '2026-06-22T06:25:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14211687542', 'Stefanos Gatdoulos', 3, 'Great for writing notes; but terrible for typing', 'I love and hate this app at the same time. I love using this app when taking notes with my apple pencil. However, to use it like Microsoft Word, it is absolutely buggy and frustrating. There are just way too many bugs to type with this app. (on the MacBook Pro and on the iPad both have many bugs for typing. If you want the best handwriting app, then this is the app for you. If you are looking for the best typing / note taking app, then look somewhere else. The UI is very buggy on the MBPro and even on the iPad Pro.', '16.4', 'us', '2026-06-21T22:27:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14209721485', 'mookeykj', 1, 'DO NOT BUY', 'The Notability team RUINED the Apple Pencil in the latest update. Erasing no longer works properly. Can’t believe there is no setting to change it back. I can’t believe my $150 subscription went to waste overnight.', '16.4', 'us', '2026-06-21T09:40:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14209469784', 'DaveMenefee', 4, 'Great, but…', 'I use this app all the time and love it. I bought it back when it was a one-time purchase, and when they moved to a subscription model I was grandfathered in with the ‘classic’ license. That’s excellent. However, the app continually tries to upsell me on the subscription, which I refuse to buy as I’ve already got too many media and storage subscriptions. I wish I could turn off that annoying popup series.', '16.4', 'us', '2026-06-21T08:25:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='360593530'), '14207613602', 'ejukie', 3, 'new update', 'i don’t like the new update. change it back', '16.4', 'us', '2026-06-20T20:33:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '14116001693', 'iOSBliss', 4, 'Almost there …', 'Greatly appreciate the addition of the Apple Watch app. Just wish it had multiple complications — even a simple one at first, for one tap access. The remaining things that feel limiting: There is no full screen note option on iPhone. I would like to eliminate visual clutter when writing down my thoughts. Also I wish the app didn’t force us to create a title or auto-create it with a date or “Untitled” or make us choose a project every time. A quick notes section or inbox that doesn’t require us to think of a title or project would create a much better flow and faster notetaking. We could assign them later, if desired. Lastly, IMO the “Empty note” place holder is unnecessary and adds additional clutter. If a note doesn’t contain content it should be obvious by the blank note itself. At least a setting in the preferences to remove it would be nice. You may think these are unimportant or small quibbles. But when you are using an app day in and day out they can quickly become annoyances and often will force you to look elsewhere. To me an app has to make you feel good when you open it up and foster clarity while using it, above all else. No doubt the app has a lot going for it. It just needs some more attention to the user experience. Addressing the things I mentioned will go a long way in that regard.', '23.0.1', 'us', '2026-05-28T08:15:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '14065475660', 'Tvjygvjygg', 1, 'No, just no', 'First off I was very hyped over this because I can’t find a free Notes app without paying for extra stuff second off. I instantly tried to find a template for my project that I ended up failing because of me being stupid and not testing this out, but then it told me I had to pay for it don’t try it out ever I don’t recommend it and don’t even say thank you for your opinion. I’m just done with this app. I have tried countless times to do my work, but I can’t.', '22.3.1', 'us', '2026-05-14T18:21:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13983109366', 'Sherap6', 5, 'App icon is Not “attractive”', 'Seriously. Work on your app icon (design). With kind regards ~', '22.3.1', 'us', '2026-04-21T15:32:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13889379615', 'A Wildfire review', 4, 'New to this', 'Well so far I’m 5 min into this app and there is just almost unlimited amount of tools and things I absolutely love it so far will leave another review when I’m done and have went through the whole thing!', '22.3', 'us', '2026-03-26T08:43:30-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13764396333', '|o|ol', 5, 'Missing App Icon Options', 'Love the app. It would be great if there were options to change the app icon. While I love the orange/yellow theme in the app, it’s starting to feel too loud on my Home Screen.', '22.2.1', 'us', '2026-02-18T16:53:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13759489272', 'GreggMayer', 4, 'Almost Perfect', 'I love the app but I feel like it lacks a little bit of optimization. Like when both side panels are closed, I’d like to be able to expand the text/ area of typing. Or even when you have one panel open, the are of typing could move to the other side and stay wider.', '22.2.1', 'us', '2026-02-17T08:14:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13710885006', 'Caribbean Blues', 1, 'App Unusable After Update', 'The latest update has destroyed the functionality of this app. I can’t even type the date into my journal entry! It’s like there’s a ghost in my app moving my cursor and deleting my text. I’m moving back to notes!', '22.0.2', 'us', '2026-02-03T22:11:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13671433835', 'San_Cha', 1, 'App keeps crashing after upgrade', 'App won’t stay open long enough for me to contact support through the app. I have an iPhone SE and both iOS and app are the latest versions. Please help asap, I need the app to work. Thank you.', '22.0', 'us', '2026-01-24T12:06:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13396919626', 'JoseCansecoFan24', 5, 'Favorite Note App', 'This app has many features and is the best replacement I have found for a daily planner. I was to red of throwing planners away and not being able to find something year to year this eliminated the issue for me.', '21.1', 'us', '2025-11-14T06:44:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13185053040', 'Swimmer-Bear', 3, 'What offer?', 'Got a nice email saying there was a sale. Went to see. Unfortunately the email is bad so I can’t see the see the sale prices. No sale. No way contact developer. No purchase. Update - They say I should have contacted customer service. I did. They never got back with me.', '21.0.2', 'us', '2025-09-25T16:57:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '13146964146', 'Bnamso', 5, 'This is the best of them all', 'It’s crazy that I tried so many different apps like Ticktick, Fantastical, Google notes, Google Calendar and more, before I wound this incredible app. Not as popular, but it’s definitely the best for a person that wants to organise the day with notes and calendar combined. To the developers, THANK YOU', '21', 'us', '2025-09-16T20:54:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12967892387', 'quartertonelow', 5, 'Absolutely essential app for the iPad', 'If you manage any kind of project, this is it, kids. Don’t mess around with notion or obsidian or any of the others.', '20.2', 'us', '2025-08-02T10:36:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12624266702', 'YvonneKR', 4, 'Bug Report', 'I’m having lots of lag on the editor. I often have to stop and let it catch up. It’s erasing more than I tap for. It adds words I didn’t type. It erases spaces without reason. It’s predicting words that aren’t remotely useful. The tense of a word usually doesn’t remotely apply, I have to stop swiping and type it completely out. For instance, I just typed “arrive,” and savedsaved is what appeared on the screen and the asterisk jumped two lines and half the editor over. And then I had to tap 6 times to get it to move back to the right spot, and another 4 taps to get it to highlight the misspelled word so I could erase it and tap out what it should be. It’s just not functioning properly. I’m running iPhone 15 pro max and iOS 18.4.1', '20.1', 'us', '2025-05-05T18:15:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12566717592', 'Feeling robbed 77', 1, 'Premium is a lie to get your money', 'This app is not user friendly, nor does it have the features you think you would be getting. Simple things such as changing your password, editing, and user interface that is the worst I’ve ever seen. Any other task or Calendar App is a better choice. Instead of the naming is “Agenda” they should’ve named it what it really is “Theft”', '20.1', 'us', '2025-04-20T12:30:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12419655926', 'Usergoober', 1, 'Engineers & How To Use', 'this app looks absolutely amazing and I’m pretty sure it is. But for me, I wanted to actually use the thing and what did I get a whole bunch of sample data which is great to see how someone else has done it but for the most part this is the what and the why of this app. The how to is buried the tutorials where are they? How do I find them? How do I use this. This is so typical of apps that are developed these days which equates to we know how to use it so you can just figure it out on your own. for many products you have to go online to YouTube or to some other kind soul that took the time to explain this is how you do this or you do that because the company themselves are too busy to think about how to actually use their product. It sounds silly but for me after 10 minutes of frustration trying to figure out how to use this crazy app finally went to leave a review on the App Store. Upon doing that I end up at their webpage that shows a whole bunch of tutorials. Great if I could’ve found those tutorials from the app itself, I wouldn’t be leaving this nasty review. And by the way on their site, it says feedback so that I could actually leave feedback for the developers instead of this nasty gram, there seems to be no actual way to leave feedback for the developers. So once again, I am left pulling my hair out and screaming into my phone with images of Steve Jobs spitting in the face of engineers - make it usable. I mean really how hard it is it to put a little button or an icon somewhere on your product that takes you directly to tutorials. When I first installed the app, it asked if I wanted to include the sample data - I thought yeah sure it’s good way to learn. and to some degree it is but unless you know how to make all of these things happen it’s really just extra noise. At the end when I wanted to remove that data because it was just extra clutter, I could find no way to get rid of the sample data. You might think I’m a newbie but I worked in telecommunications for 20 years. Ran an online web development company an online marketing company so I’m used to working with data and programming and way too far advanced to be this frustrated. I mean are you kidding me? Make it so people can figure out how to use your product - how to is the most important thing with most people that are not technically advanced the what and the Y are important for sure but the how to is what will take them from curiosity to actually using your product.', '20.0.1', 'us', '2025-03-14T08:15:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12382631709', 'Vdorick', 5, 'Our Video Production Organization Lifeline', 'In Agenda we''ve created a project that has basically four notes created as templates: Project/Client Info Pre-production Production Post-production With only four notes and various sub notes we are able to completely organize our projects. It’s great to quickly see where we are at any time, in any of our project categories. We are a small production company and Agenda serves our purpose through ease of use and a beautiful user interface.', '20.0.1', 'us', '2025-03-04T15:17:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12353038965', 'branjc91', 5, 'The Digital Secretary', 'I have used this app to really dig into organizing my mind and life to be more purposeful and intentional with my time management. I use Agenda as a Digital BuJo as well as an Eisenhower Matrix kit. The features coming out are amazing! I love the integration that syncs with iCal and Reminders. This is a complete game changer. Apple notes does not have this integration. It’s also a pleasantly designed user interface. Keep up the hardwork and development. You cannot quantify the results if you take this app seriously!', '20.0.1', 'us', '2025-02-25T04:09:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12253853572', 'NEWREVIEW5/2020', 4, 'New User', 'I''m a former Evernote user and have been using Agenda for a few weeks now. Agenda appears to be a very good product to date with a very reasonable price. However the one thing I dont like is the app will not allow users to change the font size or style within the App.', '20.0.1', 'us', '2025-01-31T10:09:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12217153724', 'v from midlo', 2, 'Seriously lacking a key functionality', 'UDATE: Nothing like a dev telling a PAID customer that what they want is not important. I am avoiding this DEV FOR GOOD. TOO ARROGANT. END UPDATE: This app needs templates for projects. It has templates for notes which for me is useless but templates for projects would be priceless. The first request for this functionality on the devs website for Agenda was in 2018 and several others followed. All such requests have been commented on by several users stating how much they desire this functionality. Based on how nice this app looks & functions (this one critical issue aside), I doubt that it can’t be done and I don’t understand why it hasn’t with so many requests. This app is not cheap. I use it for several tasks but one is for planning woodworking projects. I have a project I would like to use as a template as I have notes within it that apply to all of my woodworking projects (Materials, cut list, joinery by part, machining by part, assembly instructions/order). For each project, each note is different (thus a template for notes to me is useless) but I need the same notes in each project (thus the need for templates for projects). I understand not all requests for update can be done or are feasible (I think this can be done and is feasible) but what is frustrating is the number of customers requesting the functionality and it not being implemented in the 4+ years since it was first requested.', '20.0', 'us', '2025-01-22T08:54:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12193832186', 'litlfroggi', 1, 'Scam so far', 'I did the trial and had all the features unlocked then paid for premium on Jan 10, 2025 via Apple and everything is now locked and I can''t use a single promised premium feature. They scammed me for $34.99 plus tax. After paying I only have access to the free version. My templates are gone/inaccessible, my calendar sync is missing, my tags are unusable. This was a total rip off.', '19.2.1', 'us', '2025-01-16T20:43:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12150462916', 'DevonFill66', 5, 'Exactly what I was looking for', 'I’ve played a lot of video games, particularly RPG’s, and wanted something similar to the typical “Journal” feature that tracks quests and their various stages and whatnot, often with explanatory notes attached. At first I wasn’t sure if this app was what I was looking for, but it was exactly. Maybe that’s not the intention, but it fits the bill exceedingly well. This is the only app I’ve ever written a review for, so that says something I hope. When I was setting up my notes and projects, I thought to myself that it was a little inconvenient that I couldn’t see everything at once, then I clicked on the overview and saw everything at once. I’m not a big time white collar worker, nor do I own a business or something, I just use this to be a bit more organized. Speaking as someone who doesn’t have the same kind of responsibility typical of the users of this kind of app, it’s been exactly what I’m looking for (this is without premium too).', '19.2.1', 'us', '2025-01-05T20:13:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12136608619', 'Nettex', 5, 'Most useful Agenda manager, features explained in the youtube channel.', 'Very satisfied. Track project, combine all data needed like contacts, files, location and links. pretty much everything you can possible want to attach. Great concept, very user friendly UI. Highly recommended. Great online community with developer wonderful support. Please add people info like phone number.', '19.2.1', 'us', '2025-01-02T10:43:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12097763003', 'Ash_Cat_', 5, 'Love it! Great for free users!', 'The app is similar to Bear or Evernote, but majority of the features are free to use. There is an option to go premium, which allows for more color customization and some ease of use features, but the app has so many great features for free that you don’t have to get the premium version to use the app. My favorite part of the app is that it integrates with the calendar and reminder apps to be able to plan for future events and see the information in some type of timeline view. I also love that you can have as many notes, sections, and categories as you want without having to pay for premium! (There could be a point where it happens but from my few years of using the app I don’t think there is a limit like that.) I have experienced a bug on my laptop where the menu for the little icons / embeds (like reminders) would not close with the app. The minimize and close buttons wouldn’t work either, but it never effected my usability of the app. On the laptop it is a little difficult at first to find some of the features, I would love to see an option to have icons in the app on the laptop similar to the icons on the IPad version to make it that much easier to find, but definitely not entirely needed. Ultimately, I would recommend this app to anyone, it has been the only app like this that I have found that has almost every feature available to some extent for free! My best example of this is using the highlighter feature on text only has the yellow color available for free, but with premium you can customize it to whatever you want. Although I do use the free version of the app, I am considering getting the premium version because I do enjoy the free version so much. I have used the free version for a few years now and haven’t experienced much of any limitations when it comes to using the app, but color customization is locked behind premium for the most part.', '19.2.1', 'us', '2024-12-23T12:26:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '12071506580', 'ZeekoReza', 5, 'The best', 'This may very well be the best app that I have , i also use for note taking where I think even beats Evernote.', '19.2.1', 'us', '2024-12-16T13:39:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11961257646', 'The 5th Try', 1, 'Home Screen Won’t Display', 'Have tried for several hours to get Agenda to work. Even deleted and re-downloaded to no avail. Watched the YT videos and instructions and the home screen that is shown is never displayed or able to maneuver to. My environment is an M4 iPad Pro 13 at iPadOS v18.1. Can get to the examples and edit them but never back to the top level home screen as shown in the App description or videos. And worse - if there is a way to get to the home screen and I haven’t been able to figure it out - shows how incredibly bad the UI is. It should be very straight forward and is not.', '19.2.1', 'us', '2024-11-17T09:57:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11894785266', 'RuffedUpButNotRuined', 1, 'Huge Disappointment', 'This app is goofy. I use an outline structure to take notes. So, I heavily rely on indentation, deep indentation. I should not be required to alter the way I take notes. Yet, the limitations of this app are causing me to second guess it. When I view my deeply indented notes on the iPhone app they are unreadable because the goofy app will not move to the right as I scroll from top to bottom. Sorry, not sorry. This is just goofy. When it comes to such basic funtionality, I require a better thought out app. SMH Really?', '19.2.1', 'us', '2024-10-31T00:13:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11800243531', 'v1rusOne', 5, 'Great, but…', 'I love the capabilities of the app. Specially, the clean UI, and the amplitude of export options. However, as a iPhone + PC user, I can’t have the full experience… Nothing bad with that, but… On iPhone, both the Calendar and Notes side panels are too small to use as all-in-one app. To be able to see & plan the Calendar… the stock or third-party calendar needs to be used, which defies the purpose of the calendar panel. Equally, the Notes panel is too small. I recommend to rebuild the UI on iOS to a more efficient layout. Instead of side panels, a Navigation tool bar at the bottom with the tabs: “Notes - Home - Calendar” which displays a full view of each tab. That would make it easier to use in mobile, and would have the advantage to use it as an All-In-One app. Looking forward to that possible evolution.', '19.2.1', 'us', '2024-10-05T07:24:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11782378948', 'BL info', 5, 'Beginning student', 'Want to learn to use this app. Am 90, energetic, busy and need organization. Suggestions for learning from the meaning of “browser,”. Yes born into the decade of raising children, grands and greats and never learning about the computer. I’m giving you a 5 star rating because I believe I might be a challenge.', '19.2.1', 'us', '2024-09-30T11:31:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11654541166', 'Tiereza', 5, 'iPad + Agenda = Da Best', 'I can honestly, enthusiastically say Agenda is the nest/catalyst/caretaker for my entire life. (I couldn’t decide on a descriptor, so I used them all.) I’m a Premium account holder. It is worth every single penny. I’d make that choice again in a hot minute.', '19.0', 'us', '2024-08-26T04:48:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11465617030', 'celstone', 5, 'This is the app I’ve been waiting for!', 'I have recently been wondering why no one had yet made a better want to stay organized between calendar, notes and reminders. THIS IS IT! I am beyond excited. Having that…”Just take my money” moment.', '19.0', 'us', '2024-07-07T03:37:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11354380336', 'Notabilitynonono', 1, 'why the music', 'Extremely stupid idea. Delete the app immediately. Didn’t have time to experience.', '19.0', 'us', '2024-06-07T09:32:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11224361921', 'LindsayBourgeois', 5, 'Best Note taking app I have used!', 'I have become a daily user. It has replaced Trello, Google Keep, apple notes, and my calendar app. I have barely scratched the surface of the app’s capabilities, and it has already streamlined so many different programs into one easy to use, visually appealing interface. HIGHLY RECOMMEND!', '18.3.2', 'us', '2024-05-02T08:38:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11181942743', 'Chris Dedman', 5, 'Best Note taking app', 'I’ve been using/trying a lot of note taking apps. I sticked to Nebo on my iPad for taking notes because from all the apps I’ve tried, it is the best that work for me. Now that I discovered Agenda, I must say that I really love it. I am more of a handwriting note taker on my iPad, but I started to use agenda for my computer science studies at school. I just wished that the app had a handwriting support on iPad, like Nebo does which would make me fully transition from Nebo to Agenda (hard to write correct mathematical formulas by just typing). So, I will be using Nebo and Agenda for my computer science studies from now one. I want to say to the developer, good job guys. The design is amazing on both desktop and mobile. You guys rock! I wish the code base was available on GitHub, I would have been happy to contribute. 5 stars for you guys. Y’all amazing! Thank you', '18.3.2', 'us', '2024-04-20T12:02:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11130213948', 'cammcc55', 3, 'paragraph and format auto hide', 'can you auto hide the paragraph and format menus once you make a selection or begin typing? the text reverts to default formatting (from italics top non-italics) after a period. unhelpful.', '18.3.2', 'us', '2024-04-06T20:02:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '11036010379', 'ديمة عمار', 4, 'Very useful💙 but..', 'It took me some time to get used to the app''s interface.. this app is literally what i was looking for, very useful and handy but It would be better if it supported writing from right to left.', '18.3.2', 'us', '2024-03-12T04:04:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10921722121', 'Nightcanon', 2, 'Potential', 'Who has an agenda without a calendar to follow. Deal breaker for me. I can plan all day but without a "callable" calendar, it’s a hard pass. It does show one in the pictures but I’m not reinstalling to search high and low for it. If there is one, it’s hidden or embedded somewhere.', '18.3.2', 'us', '2024-02-09T18:46:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10839416789', 'BillyJoel1', 5, 'Updating my review of Agenda', 'This past year I made the financial commitment to go Premium. The more I used other apps that did similar things, the more I finally realized the uniqueness and success of Agenda. No regrets going premium. I use this daily and it truly brings access to calendar and records of details related to dates that become easily accessible. Thanks for a great product and you ongoing commitment to this app. Recommend it to all.', '18.3.2', 'us', '2024-01-19T05:26:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10413109034', 'JessaLu', 1, 'What happened to the $14.99 option?', 'I have an iPhone and an iPad. No mac. When you check pricing in the App Store it lists a $14.99 premium option. When you go to purchase the premium option in the app you have the $34.99 option and the lifetime. That’s it. Talk about bait and switch.', '18.1.1', 'us', '2023-09-27T09:30:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10389140867', 'BlitzTD', 2, 'Would not recommend', 'Yeah this app is basically the same as calendar. Would not recommend.', '18.1.1', 'us', '2023-09-20T12:43:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10387670141', 'Julie Boolieee', 5, 'Use it daily', 'I use it to take client notes throughout the day. I love the templates, the ability to quickly search for notes, the formatting options, the archive feature. I have 5000+ notes easily organized. Highly recommended.', '18.1.1', 'us', '2023-09-20T04:14:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10352645047', 'ssnui', 3, 'Annoying bug', 'When switch to another app and come back it jumps to a place it wants to instead of the last location of the cursor. Also lagging on iPhone and iPad', '18.0.1', 'us', '2023-09-09T21:04:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10302996260', 'chezahmet', 4, '35 dollar for a year !!?!', 'It is not the app we deserve, but it is the one that we need', '18.0.1', 'us', '2023-08-26T17:17:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10287911137', 'Duke Fuca', 3, 'App needs fix', 'The design is great. But, but, but, why is the entire UI interaction always so stuck??? How come???', '18.0.1', 'us', '2023-08-22T11:46:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10273738174', 'Rabbit H', 4, 'Add more features.', 'The app is very good. I have renewed many years. Please, add more features as sort notes in alphabet, color titles of each notes like color text. Thanks', '18.0.1', 'us', '2023-08-18T14:35:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10051231673', 'Seattle tester', 5, 'Amazing', 'I know the lifetime membership may seem steep but honestly I think it''s a steal of a price. Considering all the great features Agenda 17 touts, to imagine there is so much in store! The UI alone is so aesthetically clean and easy for the eyes. I''m either in front of a computer or ny phone majority of the day, so it''s nice when reading my notes doesn''t irritate me haha. Thank you guys :)', '17.0.2', 'us', '2023-06-19T13:26:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '10028105456', 'Organizedj', 2, 'So much lag and crash', 'To start, I love agenda. In my opinion it’s the best concept out there. I believe in it enough that I’ve purchased the lifetime upgrade. I am tremendously disappointed though in how laggy it is on a regular basis (on iPhone, iPad and Mac) and how often it gets stuck and either crashes or I have to force close the app and restart it. Hopefully this gets fixed soon. I do often use Apple notes for something if I need it to be reliable and I’d really like to be able to believe that agenda will always work and be more consistent in its performance.', '17.0.2', 'us', '2023-06-12T20:51:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '9999074981', 'Janellebbb', 1, 'Used to be great', 'Used to be great but extremely glitchy since the last update under a year ago', '17.0.2', 'us', '2023-06-04T10:18:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '9851703200', 'MyLoveOfJazz', 5, 'A Great Project Planning Tool', 'Agenda has been an effective project planning tool for nearly 2 years for me. With the advent of establishing a new business, I have been able to document each of my projects.', '17.0.2', 'us', '2023-04-23T00:53:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1370289240'), '9748889363', 'Quark Gluon Plasma', 1, 'Overbuilt with no clear use', 'This app has evolved into a feature-rich monstrosity with no use case that I can see. If there is a philosophy, productivity system or typical use motivating the development of this app, I can’t find it. Although it has some characteristics of a journal, a calendar and a todo list, it seems hard to use for any of those functions. In this case, more is less.', '17.0.2', 'us', '2023-03-24T20:29:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14266440372', 'Harry’s Bad Hat', 4, 'Close to perfection', 'As one of those people who thrives making lists, I love this app! A couple of features I need to bump this up to a 5/5 are ALPHABETIZING and NUMBERING - specifically being able to see how many ✨things🌝 are in a project/list etc. Still really enjoy the way this app looks and functions otherwise', '3.22.9', 'us', '2026-07-05T08:36:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14258629461', 'tiberiuvs', 5, 'great app, major request', 'have been using it for years. please please please have it so that the widget also shows upcoming calendar events when on the Today view just like in-app, so I can use one widget to see my entire day.', '3.22.9', 'us', '2026-07-03T09:31:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14233225748', 'Hold on for this ride', 5, 'Works great for me', 'This app has become foundational to my life. I have four rentals three children, several sources of employment and income. It allows me to keep track of all of them seamlessly- at least for the way I think', '3.22.9', 'us', '2026-06-27T08:30:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14233186347', 'Have ski hfbhaiKbf', 5, 'Only Review I’ve Ever Written', 'I truly have never considered writing a review for an app. I’m an admin professionally and have spent years testing ways to keep a todo list that didn’t feel like more work. I could never find something easy that somehow cleanly held EVERY todo I have - and here it is! Worth every penny, would buy again and again - my brain has never been happier or less full of junk.', '3.22.9', 'us', '2026-06-27T08:19:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14232183431', 'Iv__c', 5, 'Great', 'After trying multiple planners and task managers, I can confidently say that this one is the best in terms of design and functionality. Clean and not overwhelming, perfect for daily use. I use it as a grad student and it helps me track my daily goals as well as multiple projects.', '3.22.9', 'us', '2026-06-27T03:02:33-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14222803534', 'The_Music_Head', 5, 'This one works for me', 'I get things… done.', '3.22.9', 'us', '2026-06-24T18:40:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14212868945', 'showroomdummy', 5, 'The best. I''m satisfied.', 'Pretty enough that I enjoy using it but also I can just forget about it because of all of the things it does so well.', '3.22.9', 'us', '2026-06-22T06:30:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14184047962', 'Dr. L.', 4, 'Nearly Perfect', 'Love the ability to drag and drop tasks as my priorities change throughout the day. So much simpler than constantly having to reset priorities. Also love being able to see my appointments and tasks all in the same view so that I can better manage my day. There are just a few features I''d like to see in future versions - a month view showing appointments and tasks for each day; the ability to create and edit events from within Things rather than having to switch to another app; the ability to swipe from day to day rather than having to leave the Today view and navigate to the Upcoming view; the ability to see the next Action in each project in the Today view so you don''t have to do back and forth between Today and Projects. If screen real estate is an issue, it strikes me that the Inbox, Anytime and Someday are duplicative.', '3.22.9', 'us', '2026-06-14T19:32:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14181690258', 'SamiS2026', 5, 'Beautiful', 'As a computer scientist, I am very discerning when it comes to apps. This one is brilliant in its balance between rich features and simplicity. I was about to sit down and write my own out of frustration with existing apps…but then I found this work of art. Kudos to the designers!', '3.22.9', 'us', '2026-06-14T06:07:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14124490217', 'Doug-Loyd', 3, 'Can’t Check Off Recurring Tasks Early', 'This app came highly praised and the reviews are almost unreal but this app doesn’t have the one feature that, for me, is the most important: inability to check-off recurring tasks due in the future. Complete waste of money as I got the iPad version too. I’m going back to Apple Reminders to get basic functionality.', '3.22.9', 'us', '2026-05-30T12:03:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14104200956', 'AmyB8484', 5, 'Best productivity app', 'This app is worth the money. It’s better than any other productivity app I’ve tried, and I’ve tried them all. It has so many features.', '3.22.9', 'us', '2026-05-25T05:40:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14103089276', 'JTJTW0', 3, 'Simple', 'I''d like to see a live activity function for task that are due within a couple of hours.', '3.22.9', 'us', '2026-05-24T21:40:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14093595096', 'gerasimovni', 3, 'Не хватает изображений', 'Купил в надежде на «идеальность» И было бы именно так, если бы была возможность загружать картинки в описание задачи. Без этого функционала лично для меня - бесполезное приложение при прочих удобствах. Даже не могу представить полноценное использование приложения подобного назначения без возможности вставлять куда-то картинки', '3.22.9', 'us', '2026-05-22T09:49:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14048528537', 'austintema', 4, 'One Missing Feature', 'The only thing keeping this app from being a home run, slam dunk, end game app is the lack of Natural Language Processing. If they add that, I’ll never consider bouncing to another task app.', '3.22.9', 'us', '2026-05-10T03:55:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14047257914', 'bigballerbrandd', 1, 'Scamming', 'Absolute scam having to buy this from all of your devices. Do not waste your money', '3.22.9', 'us', '2026-05-09T18:45:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14046788223', 'joelfreeman3d', 5, 'Best of the best', 'Things is probably my favorite app ever made on Mac and iPhone. It’s rare to find software of this quality longevity and reliability and I genuinely base my entire life around it. I hope it’s still here in 30 years from now because I intend to keep using it. I look forward to every update. I’ll be the first line to support the team however I can even after all these years. I keep discovering new features that surprise and delighted, that genuinely improve how I live and work that kind of staying power is almost unheard of. Here’s to many more decades of Things app!', '3.22.9', 'us', '2026-05-09T15:31:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14041165700', 'TahoeIsGreatGruberIsWrong', 1, 'Confused', 'For costing 80$ across all 3 operating systems, this app should support ALL OS features. Where are dynamic island, live activity, location, and focus filter support? You can filter widgets to show tasks with tags. Why can I slo have the whole app filter to only show me selected tags when I’m in a focus mode. Why should widgets be filter able, but the app itself not?', '3.22.9', 'us', '2026-05-08T04:16:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14014862975', 'leoapagano', 3, 'Lovely app but really badly needs a Recently Deleted section', 'Title', '3.22.9', 'us', '2026-04-30T19:44:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14012721195', 'Chaldean.J', 4, 'Will you support AI Agent MCP/Plugin?', 'It’s AI time now', '3.22.9', 'us', '2026-04-30T06:17:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14011342705', 'meg879c', 5, 'Simple, yet highly functional', 'Great app! I hesitated so long trying to find something free, but this is so worth the price. The design is clean and intuitive. The app is simple and not overwhelming, while being able to take on much more than just to do lists.', '3.22.9', 'us', '2026-04-29T19:57:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '14011259269', 'Eleavi02', 5, 'Intuitive , clean', 'Immediately helped me feel calmer , very easy to start using', '3.22.9', 'us', '2026-04-29T19:20:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13961170716', 'Gafdort', 1, 'No undo option', 'Deal breaker. Deleted my to do list without warning. Tutorial on app is atrocious-assumes you already know how to use the app. Better options out there.', '3.22.9', 'us', '2026-04-15T10:29:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13954397876', 'Ruthanne Reid', 5, 'Finally, a good bullet journal app - and no subscription!', 'So many bujo apps take all your data, or simply are not flexible or lack basic features like repeating daily tasks. Not this one. I have tried just about everything, including apps that try to mimic the bullet journal concept, but this one honestly provides what’s needed. The projects are equivalent to collections. Daily tasks can be repeated or grouped. It’s great. And to top it off, no subscription? Funny how that makes me say “take my money.” Thanks for the great app, devs. May your pillowcase always be cool.', '3.22.9', 'us', '2026-04-13T11:02:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13923412348', 'Chizuui', 4, 'So Close to Perfect', 'I only use this for repeating events/tasks. Which is amazing, but a little clunky. I really wish I could more easily move task date to sooner or later since it just hits you with a "pause" or "change" on the recurring options, not the actual date. I would also like to move things around in the "Upcoming" menu since I like that view to know how packed I made a day, and want to rearrange items to ease the load.', '3.22.9', 'us', '2026-04-04T17:36:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13922632983', 'Rabbit Reader II', 5, 'My GO TO DO list', 'I’ve used several task apps but I like the ease of using Things3. I use it daily because it sure beats paper. I like the tutorials they provide. The only thing the app needs work is the ability to share a photo, like a texted invite photo with dates and times etc. to the things list in a much simpler quicker easier way, ie- please write that software so it can be automatic. I’m getting tired of rewriting data when I could send a picture instead.', '3.22.9', 'us', '2026-04-04T12:09:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13914652584', 'Rekloose', 1, 'Coulda been the best', 'I wasn’t warned about creating an account to keep my entries in the cloud. Lost a lot when I switched phones.', '3.22.9', 'us', '2026-04-02T08:31:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13890046341', 'Papacapp12345', 3, 'Repeat Problems', 'Good app, but can''t check off a repeating task the day before it is due. Can only check it off on the day it is due. So if you get it done a day or so early, you are out of luck. Another problem: If I miss checking off a task on a particular day, it shows up on the next day, but there is no way to find the original due date. It just says due today. I’d like to go back and find what happened on the original due date, but there is no information available to lead me there. Please show the due date somewhere on tasks. Third issue, Siri. Have to say “in Things”. And then hope the iPhone does it correctly. The watch app doesn’t accept reminder request with verbal task input.', '3.22.9', 'us', '2026-03-26T12:29:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13872943864', 'gordonross', 5, 'Simply the best', 'I run my entire life with this app. Love it.', '3.22.8', 'us', '2026-03-21T14:46:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13847385752', 'Milkbuddd', 1, 'Terrible App', 'If you or the app accidentally deletes a to do list theres no undo button', '3.22.8', 'us', '2026-03-14T07:36:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13827592420', 'Bryce St.', 2, 'ok for one time events', 'i paid for this app based off reddit reviews hoping for something to help me with a daily schedule, this app is not it. If you have it set to repeat daily it will add duplicate events. the widgets aren’t very good either', '3.22.8', 'us', '2026-03-08T11:06:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13826745391', 'jrob1906', 5, 'Think I Finally Found It', 'Best productivity I have found thus far and I have tried many over the years. Like the simplicity which works well for me. Enjoying it so far.', '3.22.8', 'us', '2026-03-08T06:22:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13825368046', 'deleejump', 5, 'Better than I thought it would be', 'It’s actually pretty good. It’s exactly what is advertised and the other reviews are right. It’s a good app.', '3.22.8', 'us', '2026-03-07T19:08:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13802794695', 'csageland', 5, 'balance of simplicity, beauty, design and function hits all the right notes', 'Just got this set up, but the balance of simplicity, beauty, design and function hits all the right notes. The only thing I change immediately is that flags are deadlines rather than priority flags, which is weird and annoying. But this was clearly built for people who can get lost working on systems rather than working on work and the flow to focus on the work that needs to get done.', '3.22.8', 'us', '2026-03-01T08:14:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13798776523', 'Dan804584325', 5, 'Fantastic for GTD', 'Great app. I’m using it on an iPhone 15 pro. Works great and a good tool that is in line with David Allen’s Getting Things Done methodology.', '3.22.8', 'us', '2026-02-28T06:48:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13781916459', 'tuxtlequino', 5, 'Just practical', 'I think that the problem with most apps that mean to help you organize your life is the user. No app will help you change ingrained patterns. But I like this app because it doesn’t get o. The way. It is powerful. It is simple. May not be for you but it is perfect for what it does and means to do.', '3.22.7', 'us', '2026-02-23T14:10:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13761470144', 'snailruns', 5, 'Feature request: flagged', 'Please add a flag feature so we can further highlight important tasks', '3.22.6', 'us', '2026-02-17T21:28:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13720315692', 'qmost72703', 5, 'Loving it', 'I have been a big fan of OmniFocus for years. It’s such a powerful tool and I fell in love with how it lets you customize. After getting frustrated at one of the sync issues that happens on that platform, I tried Things and, for my purposes, I have found a home. The extra capabilities in OmniFocus now feel like bloat and I find Things does everything I need without asking me to invest so much of myself in maintaining it. No disrespect for OF or those who prefer it, but things is a much better fit for me.', '3.22.6', 'us', '2026-02-06T11:13:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13713604034', 'Cliffv12', 2, 'Be ready to spend a lot and not be able to share with others', 'I saw all the great reviews and was super excited to buy this app and organize my life! And yes, it’s a great app to organize projects and tasks however it has some serious shortcomings, especially given the exorbitant costs. First, you can’t share with a family member so having a shared family to do list in one app is impossible with this app. The only work around is sharing a log in, which then floods your phone with notifications for someone else’s tasks! Come on, sharing seems like a fundamental function. Second, say you don’t care about sharing but want an app for your Mac. I mean after all your integrated into this app, why wouldn’t you?! Yeah that’s going to cost you ANOTHER $50. That is absolutely insane and a primary reason I’m abandoning this app and recommending others who are looking for a to do app look elsewhere. Great app, lacks basic sharing functionality and is incredibly greedy.', '3.22.6', 'us', '2026-02-04T15:30:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13701575653', 'Leavism', 4, 'The perfect personal task manager', 'Things 3 is truly the perfect personal task manager, but it stops there. If you have no one else in your life that you need to share responsibilities with, then Things is without a doubt a 5/5, but rarely is that the case. I used Things 3 for 10 years, saving money on subscriptions because this is a one time purchase. It does everything right, from how stupid fast everything runs to yearly updates for the latest iOS releases. I just wish there were some collaborative features.', '3.22.6', 'us', '2026-02-01T09:04:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13700877234', 'LemonadeSyrup', 5, 'The best productivity app you''ll ever need!', 'I have tried pretty much every productivity app there is, and none of them come close to Things 3. No subscriptions ✅ Frequent updates ✅ User-friendly UI and UX ✅ Accessible pricing ✅ iCloud seamless pairing ✅ Simple and straight to the point application ✅', '3.22.6', 'us', '2026-02-01T05:42:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13685732835', 'Sharkus7', 5, 'Great app!!', 'Would love to be able to share todos and projects with someone else and let it help manage my household..', '3.22.6', 'us', '2026-01-28T07:57:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13674851839', 'Mister_X.', 5, 'Awesome', 'I use it for a year in iOS and MacOS best 2Do app, I love the UI and UX', '3.22.6', 'us', '2026-01-25T09:43:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13643971005', 'sfey', 3, 'Can’t use across iPhone and iPad with buying another version', 'Admittedly haven’t gotten much into the functionality, but a big reason is I had planned to quickly input items with my phone on-the-go and then reference on my iPad later. Well, after paying $9.99 for the iPhone version, turns out I need to also pay $19.99 for the iPad version. Seems excessive, haven’t done it.', '3.22.6', 'us', '2026-01-17T06:35:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13642656979', 'Instaurator', 2, 'Not Available on Windows', 'I use Apple products for almost everything except work, where I’m required to use a Windows laptop. Not being able to access Things 3 on Windows or even through a web interface is a major obstacle and dealbreaker. I genuinely love Things 3. It’s one of the best designed task managers available. However, many professionals operate in mixed ecosystems, and the lack of any Windows or web access in 2026 is absolutely ridiculous. Even limited or read only web access would solve a large part of the problem. As it stands, the Apple only restriction makes Things 3 impractical for anyone who needs cross platform access for work, which is disappointing.', '3.22.6', 'us', '2026-01-16T22:29:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13622940437', 'luyao 123', 4, '希望可以加入日历功能🗓，这样会更加直观', '去标题', '3.22.6', 'us', '2026-01-11T15:16:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13615437480', 'Just_Girl_03', 4, '7 лет без крупных обновлений', 'Никаких новых функций, даже выбор порядка для новой задачи в разделе «сегодня»: хочу сверху вниз, а не снизу вверх.', '3.22.6', 'us', '2026-01-09T18:52:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13611166042', 'vargarchitecture', 2, 'App doesn’t automatically refresh', 'The app does not refresh content automatically in the background. Updates only appear when you manually open the app, which is frustrating and interrupts workflow. Background refresh is expected in modern apps—this limitation significantly reduces usability and user experience. Please implement automatic background updates so content stays current without constant manual checking.', '3.22.6', 'us', '2026-01-08T16:29:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13607805000', 'revival20', 5, 'Incredible usefulness', 'I didn’t think I will find this app so helpful. I gave it a chance after hesitation, but it’s really amazing.', '3.22.6', 'us', '2026-01-07T19:51:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='904237743'), '13596167008', 'Ablepraxis', 4, 'Love it, but…', 'I firmly appreciate this app for smart design and features. Its sorta understandable that paid app charges again for desktop version (iPad too i think) but with that being the case: my one major wish/request is that developers produce options for proper WIDGET for anyone working on desktop mac, maybe iphone too. Rake in your earnings sure, but please consider the suggestion. Would give 5 stars for that! Cheers!', '3.22.6', 'us', '2026-01-04T19:37:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14267363336', 'ExtraAmo', 5, 'Great Things Alternative', 'Things but works on Windows too. I can’t believe how dumb the developers of an app have to be to lock you into one ecosystem. I love Apple products but sometimes I can’t choose what ecosystem my employer uses…', '8.1.10', 'us', '2026-07-05T13:26:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14266207429', 'Abubucks', 5, 'Просто легендарно.А еше лучше если в бесплатном версии делают 10эелементов больше', '5/5', '8.1.10', 'us', '2026-07-05T07:30:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14266129296', 'BanjoSolo', 5, 'So feature rich', 'And easy to nav. I’m still getting used to it but I plan to keep my subscription after the trial. I guess that’s the ultimate test of an app, right?', '8.1.10', 'us', '2026-07-05T07:08:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14262830984', 'ShannonCooney', 5, 'Basically the holy grail of task managers', 'No notes, good work', '8.1.10', 'us', '2026-07-04T10:06:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14261860416', 'ashhhhhlynnnnnnnn', 5, 'love', 'keeps me on track to my goals best app ever', '8.1.10', 'us', '2026-07-04T05:22:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14260034167', 'Arminz3', 5, 'Love it 🤍', 'The best task management app in the world', '8.1.10', 'us', '2026-07-03T17:40:37-07:00');
