VALUES
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14259047825', 'Jam2688', 5, 'Great app with plenty of features', 'I’ve been very happy with this. I’ve chosen it over all of the other ones I have tested in the past.', '8.1.10', 'us', '2026-07-03T11:38:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14256629687', 'sh4rkw33k', 5, 'Great App', 'I literally use TickTick for everything, highly recommend. Very customizable.', '8.1.10', 'us', '2026-07-02T22:26:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14255203149', 'SpiritLoveRoot', 5, 'TickTick better than Todoist (for me)!', '1. Better repeating task options 2. Better Calendar Views & Integrations 3. Ability to link tasks to each more easily 4. Ability to integrate with Notion more easily 5. Todoist has a nicer UI, is slightly less buggy, and has a slightly nicer quick entry option for tasks 6. But in general, just a lot more little nice power features that make it substantially better than Todoist', '8.1.10', 'us', '2026-07-02T13:34:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14250594367', 'tinyGeek', 5, 'Easy to use', 'I am 64 and still easy to use.', '8.1.10', 'us', '2026-07-01T11:36:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14249807410', 'TheGothfather', 5, 'Great organization tool', 'This is exactly what I need. Super streamlined design. Ability to sort multiple lists by any variables i want, categories, priorities, due dates, etc. this tool is perfect!! Can’t wait to see how they keep improving it. Ive noticed small improvements over my time using it. Ability to link to a google calendar would be awesome, bc google tasks sucks by comparison and it would be great to have everything in one place. For now, switching between things is super worth it. Love this app', '8.1.10', 'us', '2026-07-01T07:53:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14249627903', 'keivanch', 5, 'Goof for me', 'Easy to use for me', '8.1.10', 'us', '2026-07-01T07:05:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14249170078', 'DocSingh', 5, 'Great to do list', 'Perfect to do list for my needs. Very user-friendly. Does everything that is needed on a to-do list.', '8.1.10', 'us', '2026-07-01T04:56:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14242866045', 'Beware of Doug', 5, 'The Best To Do List app', 'The best', '8.1.10', 'us', '2026-06-29T16:44:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14241976110', 'FinchFriend', 5, 'Amazing Planner', 'It helps me remember so many things, there are so many appointments and classes I would have missed if it wasn’t for this. I would highly recommend it. It’s also very easy and intuitive to use. It lets you arrange tasks by priority and allows you to schedule things wayyy ahead of time. You can also schedule repeat tasks and then delete them on specific days without deleting the overall repeating task, which is nice.', '8.1.10', 'us', '2026-06-29T11:24:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14240177584', 'Parker cissne', 3, 'So good', 'I will send reminders like when it would be a good time to drink water', '8.1.10', 'us', '2026-06-29T02:42:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14238499847', 'MusicLover2711', 5, 'An amazing app for someone with ADHD!', 'Helps keep my to-do list, task, and ALL of my calendars in one place so I can effectively manage my time! With this app I can see everything at once as well as its importance! The notifications and reminders keep me on track! So happy I found this app! ❤️', '8.1.10', 'us', '2026-06-28T15:08:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14237414091', 'Bwills13', 4, 'Love love this app!', 'This app is great! I do wish there were more options for actual notes. Overall this has improved the way I organize both work and life tasks, goals and habits.', '8.1.10', 'us', '2026-06-28T09:05:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14235429986', 'neverwhere9', 4, 'Great app, a few features could be added', 'This app is incredible for ADHDers who need to switch up their task view and break tasks down. You can even choose a sound for when you complete a task, and there’s a GREAT stats section that’s not just based on how many things you’ve done, but how efficiently you’ve done them, which makes it waaaay more rewarding to level up. Quite a few features I’d like are being a paywall (including syncing up both ways with Google Calendar, which is sad), but the app is still perfectly functional free. I haven’t decided if I’m purchasing yet. My big request: Why not a “due date” AND the option of a “do date?” So many other apps have this, and I feel like it’s the one missing thing that would make it perfect for me!', '8.1.10', 'us', '2026-06-27T21:30:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14234670856', 'toropov.photo', 5, '4 года я открываю все больше возможностей для себя', 'Лучшее приложение для планирования и не только, закрывает все мои потребности по задачам, контенту, фокусированию', '8.1.00', 'us', '2026-06-27T16:46:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14234554605', 'Bleed18', 5, 'Great app been using it for over a year now', 'Great app, been using the free version for over a year and honestly all the other ones are annoying with the dumb features you have to pay for. With Tick tick you only have to pay for, imo, the unnecessary options.', '8.1.10', 'us', '2026-06-27T16:00:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14233570773', 'nicolehjeck', 1, 'bad', 'i love the app and its features but when i had gotten a free prescription it canceled a week later as planned. I haven’t been getting notifications from the app and I haven’t really been minding because I didn’t really think the app suits Me, but it’s been a few weeks since I had gotten my free subscription and two days ago I had barely noticed that they charged me for the yearly plan, which I never consented to. please make sure your not letting apps steal your money', '8.1.10', 'us', '2026-06-27T10:11:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14233180237', 'j.cruz2709', 5, 'Thank you', 'Super helpful', '8.1.00', 'us', '2026-06-27T08:17:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14233166118', 'Hammock lover', 5, 'Now working on Vision Pro!!', 'Add Long last the latest revision fixed the problem with the crash on the Apple Vision Pro! Thank you development team!', '8.1.10', 'us', '2026-06-27T08:13:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14230610481', 'amazingzebra6767', 5, 'Suggested Features', 'Love this app! I’ve tried everything from physical to-do lists, Google calendar, Notion, other to-do list apps; but nothing has offered features that are as comprehensive, easy-to-use, and customizable. Just some small suggested features: - Classify Calendar events into the matrix. Changes the color of the event in the list and appears in the matrix tab. - Colors should apply to the entire task text or task box, not just on the side or the checkbox. - More customizable widgets.', '8.1.10', 'us', '2026-06-26T17:01:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14228493528', 'austinbob', 5, 'Life saver!', 'Calendars just don’t work for me, but I have now used tick tick for years and rely on it 5-10 times a day and it has never failed me! It’s super fast and easy. It’s my most valuable app!', '8.1.00', 'us', '2026-06-26T05:44:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14223574613', 'RoeiPatiT', 5, 'I like it', 'It’s a little bit better than the iOS reminders app even without the premium because you have more options to use like habits and Eisenhower matrix', '8.1.00', 'us', '2026-06-25T00:04:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14220995963', 'Aiden Pyke', 5, 'Wish I did this sooner', 'I wish I had switched from Apple reminders to this sooner! I’ve used Notion, and reminders before and this is a much better system for managing tasks. I love the time blocking feature- being able to drag tasks over to a calendar is wicked cool! This works how my brain works and I’m truly grateful for Tick Tick!', '8.1.10', 'us', '2026-06-24T08:16:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14220130792', 'J Lad12', 5, 'Best productivity app I’ve used', 'I’ve been using TickTick every day for probably seven or eight years now, and it’s honestly one of the most useful apps I have. The habit feature has really helped me stay on track and get things done, and I love how easy it is to add tasks especially with the voice feature now. Being able to send emails into TickTick and have them show up as checklist items is also extremely helpful. The recurring task options are really flexible too, so I can set things up exactly how I need them. At this point, I’m not even sure what the app is missing. It just works really well and has become a big part of how I stay organized.', '8.1.00', 'us', '2026-06-24T03:50:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14219999954', 'Crischristmas', 5, 'New', 'I’m still learning the app and all its features. Initially still in the set up phase, however this app offers all the tie manage t tools I’m looking for.', '8.1.00', 'us', '2026-06-24T02:59:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14217316729', 'ba201999 oo', 4, 'Great app!', 'Great app but it crashes too often, especially when creating a new task. Can that be fixed?', '8.1.00', 'us', '2026-06-23T09:29:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14216497506', 'Ben reports', 5, 'Good', 'It’s good', '8.1.00', 'us', '2026-06-23T05:22:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14214092994', '672u', 5, 'Really helpfu', 'This is a really helpful app. I’ve tried other planner-like apps but this one is the only one that has worked well for me. Does everything I need it to do. No issues, really. Nice themes and widgets as well', '8.1.00', 'us', '2026-06-22T12:49:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14213276288', 'HahaRyan732', 5, 'still learning but so far so good', 'I''ve barely dipped my toes into the full capabilities but so far it''s already making my days easier.', '8.1.00', 'us', '2026-06-22T08:31:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14213012797', 'Makinnini', 5, '♥️ Love this App - Helps with ADHD. (Some Suggestions)', 'Feedback: - Please add the ability to save different filters for views on the calendar & Eisenhower, rather than having to manually switch - Please make it so we can have multiple Eisenhower Matrices Honestly love this app. Syncs with my Google tasks and calendar. I was able to do a two way sync with tasks by using Zapier. It allows me to continue to use my AI for calendar & task management 😃. Eisenhower & priority views are tremendously helpful for me as my ADHD forgets to prioritize properly. I usually end up not prioritizing properly. Having both of the views helps tremendously when planning my day. LOVE the widgets. I have a focus mode and shortcut on my iPad that immediately takes me to my ‘planner’ page, consisting of the many widgets available for use. I love this and it is so incredibly helpful for my ADHD to be able to see everything at once. I am incredibly grateful to the creators of this app, you guys definitely deserve all the positive comments! The pomodoro timer in the app allows you to choose the task, time and has a pop-out timer. On behalf of ADHD folks, thank you! 😭⚡️ On a side note, having different calendar views saved for filtering could help in cases of families sharing accounts. I share a calendar with my BF and because my view for my daily tasks heavily relies on prioritizing, the lack of color for mine vs boyfriends calendar events can be a bit confusing.', '8.1.00', 'us', '2026-06-22T07:13:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14212849149', 'TsumeSeta', 5, 'MY FAVORITE APP EVER', 'This app is amazing! I’ve been using it for a few years after attempts with to-doist, calendar apps, and good old paper and pen! This app just sticks to you like glue. It has everything you could think of and mind you after the first few months I did pay for the subscription, here’s why: - the background ambient music (particularly deep sea) became the only thing that provided me with focus. - the pomodor timers are flexible and adjust to any task you’re doing, the calendar SYNCS to your calendars AND then it can turn it into tasks for you WHAAAT 🔥 - The support team gets back to you fast and they take your questions and feedback seriously. - There’s constant USEFUL updates like adding a countdown feature, a plug-in to NOTION like 🤯 - and of course the habit & Eisenhower matrix sections are my go to. I have become more consistent and my goals more manageable since adopting this app and though it took me several months of on-and-off again use to get used to it, I can’t imagine using a different app. Get it now!!', '8.1.00', 'us', '2026-06-22T06:24:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14212408293', 'Dave in Indiana', 5, 'What a relief!', 'I’ve been looking for a good app to keep track of my tasks ever since the paper days of the Franklin Planner. I can’t count how many I’ve tried - the last being MS ToDo app. I’ve used this app for the past couple of years and absolutely love it. I changed the Eisenhower matrix from High, Med, Low to 80, work projects, church, and personal (my 80 bucket combines all the others into one list). It works fantastic for me. I love the widget on my desk as well. I snap it to the top of one of my giant monitors for easy access.', '8.1.00', 'us', '2026-06-22T03:56:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14211769093', 'Byron Farmer', 5, 'Long term user', 'I used to use the Apple reminder app and many other ones available on the App Store and kept finding apps that weren’t reliable and very glitchy. I pay for the premium version of this app because it so vital to my life. I set reminders for an array of different things in my life such as bills and upcoming events and a reminder app is a daily part of my life to keep me on track and aware of what I need to do. I love this app so much and will continue to support and recommend to others.', '8.1.00', 'us', '2026-06-21T23:07:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14211689065', 'Dr Zagnut', 5, 'Great app works great', 'Is a great app that works for my needs. So far so good. It’s not like other apps that are overloaded with features. Tick Tick is working great for me.', '8.1.00', 'us', '2026-06-21T22:28:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14209439779', 'appleAdamApples', 5, 'A plus app', 'Underrated', '8.0.91', 'us', '2026-06-21T08:16:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14207492324', 'Julz0512', 5, 'Best time management app ever', 'I absolutely love this app it helps me create habits remember allllll the things i constantly forget and makes me feel good about accomplishing things! Theres also a pomadoro feature that i love', '8.1.00', 'us', '2026-06-20T19:43:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14206568081', 'rsal28', 5, 'If you have adhd, you need this app!', 'I would forget EVERYTHING if it weren’t for this app! I have the widget on my home screen and it keeps me so organized. If you’re in school, you can create different folders for your assignments, and the satisfaction of checking something off the list is everything!', '8.0.91', 'us', '2026-06-20T13:31:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14205885423', 'CatEyeSpecs', 5, 'Used it for years', 'Wish I could get everyone in my family & in my company to adopt TickTick. It’s so much better than standard to-do list apps!!', '8.0.91', 'us', '2026-06-20T09:40:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14205601482', 'Bretntx', 5, 'Most helpful', 'As an older man who has suffered with ADHD most of my life, I am always searching for a program or app to help me get my mind organized. Ticktick is the first one that has helped. It allows me to do a brain dump from my mind into a list in the app. I can then put a date, priority, recurring, etc., and keep track of them all on a calendar. That way I’m looking at tasks to do gradually instead of just looking at one giant list and getting overwhelmed.Best of all, it syncs everywhere, so I never have to wait to add a task. I even have it on my Windows desktop. Tick tick has been a lifesaver. Now, instead of looking at paper lists everywhere, I can quickly add a task to a list and schedule it. I even have a separate list for household items where I keep track of bills to pay. There has been a bit of a learning curve (an online manual would be great.) but once you learn it, you find how easy it is to use. There’s so many other things that this program does; I can’t recommend it enough.', '8.0.91', 'us', '2026-06-20T08:15:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14205124031', 'Inspire2013', 5, 'Finally a simple but effective todo manager', 'Instead of working to constantly organize my task list I’m actually getting my tasks done! Love this simple but powerful app', '8.1.00', 'us', '2026-06-20T05:53:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14203325781', 'werblin', 2, 'Missing key feature', 'Great app potential, but you must rely on third party apps or native calendar app to create an event. If you try to create an event in this app, it becomes a reminder, so it does not transfer to other calendars as an event. I asked the developers in-app for an explanation for why I cannot schedule an event in a *calendar* app and they said they’d consider that feature in the future. If that system works for you, it is a great app. If you need to create events, the app is nearly useless.', '8.1.00', 'us', '2026-06-19T17:55:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14202484811', 'Gracie N', 5, 'Habit Tracker meets To-Do List', 'I use this for everything, calendar, to-do list, and habit tracker. Love it, and the desktop version that syncs is even easier to use! I use the free version and it’s great.', '8.0.91', 'us', '2026-06-19T12:36:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14201541072', 'bruhbro12345', 4, 'Really good', 'Wish they gave me 5 habits instead of 4 but I don’t care', '8.1.00', 'us', '2026-06-19T07:42:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='626144601'), '14201291608', 'Reedrune', 1, 'Ok system made me write this dumb review so 1 star for being controlling and invasive', '👎🏼', '8.1.00', 'us', '2026-06-19T06:30:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14249921448', 'KRKapple', 2, 'Some “premium” features aren’t worth it/have work arounds', 'The features that Fantastical wants you to pay for are a bit ridiculous. Pay to add a custom color to the calendar? To add an emoji? Seriously guys?! There are ways to do these things already if you use your head for more than a hat rack. 😏🤫😆Why should I pay for premium? 🤨', '4.1.16', 'us', '2026-07-01T08:23:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14237565097', 'DennyS440', 5, 'Awesome Calendar - The Best I’ve seen', 'I’ve been using Fantastical for more than five years and I’m still discovering new features. It’s rock solid and does wonderful file recovery, and reconciliation on multiple devices. I literally have no complaints. Well done guys!', '4.1.16', 'us', '2026-06-28T09:49:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14216885244', 'Evan Travers', 5, 'The greatest calendar', 'Simply the best, and wherever I think they can''t get better they rollout sensible new features I really need.', '4.1.15', 'us', '2026-06-23T07:21:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14213463479', 'Bee-Ten', 3, 'Crashes when tapping alerts over many versions.', 'June 2026 - tapping iOS push notifications from the lock screen STILL CRASH FANTASTICAL, years later. Crashes when tapping alerts over many, many versions. The failed promise of subscription software. The app is as buggy as ever. I want to love it but the software quality and especially the awful “Natural language recommendations” which only gets in the way of entering data. NOTE TO DEVELOPER: This is NOT a support request. This is an honest product review. Please don’t contact me here.', '4.1.15', 'us', '2026-06-22T09:27:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14209654818', 'Dov+', 1, 'Very confusing now', 'Boo', '4.1.14', 'us', '2026-06-21T09:20:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14209311721', 'Sad&mad', 1, 'Task - big fail', 'Unfinished task carryover to the next day however, when you mark it as complete it revert back to the original day so you have no idea when you actually completed the task. This is a basic function that most all other calendar apps have correctly. It should be on the calendar on the day completed. Also wish they would add “Link Contacts” this would be great to reach out to contacts you have appointments with.', '4.1.14', 'us', '2026-06-21T07:39:10-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14193563229', 'Upset owner', 5, 'Cat lover', 'I couldn''t function without this app', '4.1.14', 'us', '2026-06-17T07:04:59-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14189035921', 'PWM Guvna', 5, 'Years of excellence', 'Fantastical just works on Mac ecosystem. Has been my calendar solution for maybe 10+ years. Pulls together all my calendars so well. Calendar sets are great. The way that an event being on multiple calendars shows up as one event showing multiple colors (for the calendars) instead of multiple side by side events is simplicity exemplified. Using slash to control what calendar events go on, is great. Natural language processing/ parsing is excellent.', '4.1.14', 'us', '2026-06-16T03:55:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14186055256', 'Mental Monsoon', 5, 'Better Than Any Other Calendar App', 'I''ve been through as many calendar apps over the years as have failed relationships. I might still be trying to find the right girl, but I''ve fallen in love with the fantastical app. We had some rocky times with a few bugs here and there, but fixes came quickly, and support is great. I highly recommend this app for keeping track of everything, including blind date nights.', '4.1.14', 'us', '2026-06-15T08:36:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14171873321', 'aallison77', 4, 'Great! BUT 1 option missing', 'After being with BusyCal for almost 15 years, I chose to move to Fantastical. The reason: Lately, BusyCal would not sync across all my devices and other problems. I really like Fantastical. It is FAST and syncs very quickly across all devices. BUT… yes, there is a BIG BUT that really doesn’t sits well with me. I have only ONE (1) suggestion please and I sincerely hope and pray that Fantastical would incorporate this suggestion into the next update… This option is available in BusyCal but not on Fantastical. In Fantastical Calendar view, I have an option if I want to show Tasks in Calendar. I have an option to turn it on or off. However, that is not the case in Fantastical Tasks List. Fantastical forces us to view all events and appointments of Fantastical Calendar in Tasks list. I strongly believe that would be a welcome option to have in the Tasks list if someone does not want to list all appointments and events in Tasks. Thank you for considering this. Best.', '4.1.14', 'us', '2026-06-11T17:08:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14167904764', 'Psychor', 5, 'They listen!', 'I don’t know if this applies for non-paid users, but their support is excellent. Super fast response and they actually follow through and fix issues with their apps when reported.', '4.1.14', 'us', '2026-06-10T16:44:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14164755604', 'Mike macrs', 1, 'Numbers', 'Whenever I enter a number or a date and then try to save it everything disappears. Like tonight I wrote a reminder to call our ac company for 6/26 the numbers disappear. I tried writing it 3 different ways and ways and wa h time the numbers disappear. Why', '4.1.14', 'us', '2026-06-09T21:38:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14163356203', 'Gloie!!', 5, 'Outstanding', 'It’s the best app on my iPhone. It always keeps me on time for all my appointments and reminders of many other things like birthdays and anniversary. I absolutely love fantastical.', '4.1.14', 'us', '2026-06-09T12:23:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14159370741', 'Banjoteacher', 3, 'Foreign holidays can’t be removed', 'I wish we could remove the events that we not only don’t want, like foreign holidays, but they appear twice, sometimes 4 times on our calendar👹', '4.1.13', 'us', '2026-06-08T11:42:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14148539910', 'greenwaterfountain', 1, 'Crashes all the time, what is going on?', 'Latest iOS 26, iPhone Air, Microsoft corp account. It crashes when creating certain events and then it crashes all the time. Can''t do anything with the app anymore. In the past I fix this by quickly deleting the event but now I cannot do it. It is just infinitely crashing. I hope your analytics can capture this.', '4.1.13', 'us', '2026-06-05T16:11:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14144721061', 'Dallasweather', 5, 'Events and reminders in one place!', 'Been using this app for years. Switched from apple calendar b/c I wanted to see my reminders on the same calendar as any events and have never gone back. It’s a simple calendar with not too many bells and whistles to make it annoying. Love it!', '4.1.13', 'us', '2026-06-04T16:27:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14140947164', 'Jmanfl11', 5, 'The best', 'I’ve been using this app for for about five years now, I have always came back to it even after trying new ones. I’m not changing again. This by far has the best features and ties into all my accounts for working and personal I highly recommend.', '4.1.13', 'us', '2026-06-03T16:48:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14130853691', 'mv.arms', 5, 'My favorite calendar app', 'Fantastical is fantastic. It has so many customizable features and is a breeze to use. One of the best little features is that, if you need to have the same event on two different calendars (e.g. work and home) they combine into one visually. A small thing but annoying when your calendar doesn’t do that (like Apple Calendar).', '4.1.13', 'us', '2026-06-01T04:35:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14128902399', 'Meow', 5, 'Fav calendar', 'I find it easy to organize my days with this particular calendar I use a time each day that holds space for similar lists … Cleaning my Airbnb 11am Sunshine emoji Packages arriving 11pm Box emoji Shopping 2pm Bags of money emoji & it helps being able to see my day Then I just move the holding emoji to the next day Thanks for not changing your app every few months too I like it just the way it is Hate when companies feel the need to always change it. :)', '4.1.13', 'us', '2026-05-31T15:05:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14117553625', 'George G 623', 5, 'Amazing App', 'I have been using this app for several years now. Organizes my life. Highly recommend!!', '4.1.13', 'us', '2026-05-28T17:22:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14111597676', 'Wren C.', 5, 'Can’t live without Fantastical', 'One calendar, on all my Apple devices, always-on, always works, never glitches — plus it’s easy to use, and its deep features are worth notice. How could I not fall in love?', '4.1.13', 'us', '2026-05-27T05:02:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14104669063', 'pendolino', 5, 'Super top support!', 'Been using this app for what now 10 years at least? This is my first review and what prompted it was how support quickly addressed a problem I had with recurring events from MS Outlook not reflecting the recurrence pattern/details at all. I was annoyed at having to check outlook all the time and didn’t expect support to make and deploy a working fix so soon! I think they turned it around in a few days. I’d looked at more modern alternatives such as Vimcal but I think I’m sticking with such a solidly supported product that just works! Now if they’d just add a command bar (CMD-K) to the desktop app it would be golden!!', '4.1.13', 'us', '2026-05-25T08:00:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14101037804', 'AceVision9', 4, 'Good, not Great yet', 'Lots of cool features and efficient templates. But the forced all-day meetings template that’s hardcoded and can’t be taken off default mode is very annoying.', '4.1.13', 'us', '2026-05-24T08:40:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14097120853', 'Skym90s', 5, 'Please Make One Time Purchase.', 'I love using this app I actually get things done and checked off every day. I would love to do like a one time payment for premium but I’m not going to start another subscription. Please reconsider adding a one time purchase for premium.', '4.1.13', 'us', '2026-05-23T08:15:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14082511610', 'tracemeek', 4, 'Love it, except for the jumpy UI', 'Exceptional app, with great thought put into all aspects of the design. If I could change one thing, it would be to add a preference setting to turn off language parsing. I can see how some would find it helpful to have people and places automatically tagged in relevant tasks and calendar entries. But I find the interface to be too “jumpy”—every new letter I type causes the search engine to search again, so that there is a distracting, ever-changing dropdown menu overlaying the screen as I type (even when I try to “escape” the parsing by typing a quotation mark before the event title. Most of the time I just want the time and title to be the way I write it, without having people and locations tagged.', '4.1.13', 'us', '2026-05-19T09:03:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14082393435', 'GutenTagY’all', 5, 'By far far far the Best Calendar app', 'This app deserves much better score here on the App Store and I see that lots of negative reviews are from the past. The Mac and iOS apps are irreplaceable. UI is great. Everything works smoothly five out of five stars.', '4.1.13', 'us', '2026-05-19T08:25:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14075851073', 'Ping Pong Ding Dong', 3, 'Why do people swear by Fantastical?', 'The UX is confusing. App integration seems to be the only perk. I’m always second guessing myself if this event I add via Fantastical is going to register. Happy to explain further.', '4.1.12', 'us', '2026-05-17T12:02:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14064104240', 'arupprec', 5, 'Never look elsewhere', 'This application is the most reliable and functional. I think I have been using it for over a decade(?)…at least it seems like it is that long. Updates are always useful and I never have had to relearn anything after them.', '4.1.12', 'us', '2026-05-14T09:31:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14054875672', 'davidmirv', 1, 'Too expensive', 'I’ve always loved this application but as a individual non business user this is a hefty price to pay monthly subscription for in this tough economy I need more value to justify the spend', '4.1.12', 'us', '2026-05-11T20:30:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14054464131', 'AJFowler', 5, 'Best calendar app', 'From the natural calendar input/creation, to the calendar sets, to the email forwarding calendar creat. I love fantastical!!', '4.1.12', 'us', '2026-05-11T17:33:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14052958738', 'MWSCHAF', 5, 'Best Calendar Available', 'I can’t find anything to criticise in Fantastical. It has everything I need and more. Regardless of the platform, IOS or MAC, the interface is consistent and very user friendly. Customer service is very responsive and provides excellent assistance. I’ve used for a number of years and my experience has not changed.', '4.1.12', 'us', '2026-05-11T08:16:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14051437930', 'Cluke1993', 1, 'Great to Now Trash Ad-Spam', 'Used to be a great app on free and paid tier. Great UI/UX…beyond aggressive and intrusive promos to upgrade to premium now every time you use it or add any single appointment. Just use Apple or Google Calendar instead.', '4.1.12', 'us', '2026-05-10T21:52:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14050752701', 'bazkoch', 5, 'Life in order', 'I have everything on my calendar. It is never turned off. Enhancements come to keep in front of other apps. I have calendars setup for each portion of my life and I can turn them off as I need. I can also print a calendar to provide diary type information for my doctor. I have recommended this app and Cardhop to everyone I know!! Keep up the great work.', '4.1.12', 'us', '2026-05-10T16:36:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14050228958', 'MoeII', 5, 'The Best Calendaring App', 'I’ve worked with several calendaring apps over many years and the Fantastical Calendar is by far the best I’ve ever used.', '4.1.12', 'us', '2026-05-10T13:02:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14035106889', 'Marissa julia', 5, 'Permanently on my Home Screen', 'I have tried other apps but nothing compares to fantastical. It keeps me organized, lots of reminders and categorizing is the best.', '4.1.12', 'us', '2026-05-06T09:51:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14031045834', 'micahd323', 5, 'Great app', 'Use it every day. Awesome features. High recommend over the base Apple calendar app.', '4.1.12', 'us', '2026-05-05T07:07:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14020136623', 'Megantereon', 2, 'Low value premium', 'The basic calendar is similar to others like Calendars app, however the premium is 4x the price of others with little useful value added. Also not as readable as Calendars or the Apple calendar on an iPad.', '4.1.12', 'us', '2026-05-02T06:44:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14019742744', 'strublekopf', 5, 'New format is unreadable', 'I have been using and loving this calendar on my phone for years. I love the ability to dictate my entries and set reminders. Unfortunately, a recent update has made this calendar unreadable in my iPhone. The print is tiny, and you have to scroll up and down to find event events for a single day. Weeks and months are totally eligible.', '4.1.12', 'us', '2026-05-02T04:32:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14011593075', 'Viobruin', 4, 'Need a better widget', 'The app itself is great. That said, it needs a small widget that shows both the date and upcoming events. Right now, if you want a small widget with upcoming events it says “today” instead of giving the actual date. The only way to get the actual date with upcoming events is to use a bigger widget. I don’t understand why the developer can’t fix this. Other apps like Outlook and Google Calendar offer the small widget I’m referring to.', '4.1.12', 'us', '2026-04-29T22:01:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14003733597', 'Jimbobba', 5, 'Awesome calendar', 'This is by far the most useful Calendar app I’ve ever had. I use it for work, family, and personal stuff all layered together.', '4.1.12', 'us', '2026-04-27T14:30:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14002765144', 'E7Bless', 5, 'AWESOME', 'I love this calendar app. It is absolutely the best on the market.', '4.1.12', 'us', '2026-04-27T08:26:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '14000435222', 'True review non stop', 1, 'Annoying request', 'Constantly asking you to upgrade to the monthly/yearly plan. Does not give an option to stop asking this. So annoying.', '4.1.12', 'us', '2026-04-26T15:08:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13997867751', 'Velocity Mj', 2, 'Not Hassle Free', 'I wanted to like this app. but It really doesn’t give you much more in useful, everyday features over the iCalendar. But my main issue is that it goes out of sync with my iCal on my other devices. In order to use the app you have to add your calendar iCloud account and to that, you have to generate a specific password. This is the only app that I have that requires this time consuming hassle. Every time it goes out of and I try to re add the app using the app specific password that I previously generated , it isn’t recognized and I have to make another one. I’m paying for an app and I have to go through this??? I finally gave up and haven’t used this app 8 months. It isn’t worth the money for what you get and you go through when it goes out of sync.', '4.1.12', 'us', '2026-04-25T22:31:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13982540944', 'Marcel (Breezy)', 5, 'widget and reminder animations', 'Please add a way so that the widget constantly is up to date, because sometimes when I change something from the app and then go to my home screen and check it on the widget, it takes a long time for the widget to change it, even though it is changed in the app. Maybe add an update button or so. Also, please add more animations. It is a bit awkward when you tick a reminder and mark it as completed and give it a cooldown or some seconds which are clear to the user and which the user can undo the ticking of reminders. Thanks a lot!', '4.1.12', 'us', '2026-04-21T11:35:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13982463283', 'kc! Bradshaw', 5, 'Essential', 'What can I say, the app is fantastic, and appropriately named. If you never felt like the Apple calendar app worked for you, I recommend giving Fantastical a try.', '4.1.12', 'us', '2026-04-21T11:05:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13973718089', 'shaun1995mrr', 5, 'amazing app', 'I say my today plan to Claude . Claude help me arrange the events to iOS calendar and reminder. then these events and tasks visually found in Fantastical.', '4.1.11', 'us', '2026-04-18T23:40:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13971490141', 'BellaCigno', 1, 'It’s unusable now', 'I’ve been using this app for ten years. I loved so many things about it-especially alerts for travel time. At some point there was an update where almost all events are automatically put in as proposed. So they aren’t really confirmed until you hit confirm. It’s super irritating and some our meetings have just disappeared off the calendar. My assistant has gone back to iCal and now I’m searching for a new calendar app. When are developers going to realize that you don’t need to mess with the simplest and most straightforward things? We just want to input an event. It’s not that deep. There should be a setting to turn this off.', '4.1.11', 'us', '2026-04-18T08:43:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13952665338', 'Paul621@', 5, 'Best calendar app!!!', 'Organizes everything and memorize appointments that I totally have forgotten', '4.1.11', 'us', '2026-04-12T23:41:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='718043190'), '13947528534', 'Yury S.', 1, 'Nickle and dime', 'I paid way too much for this app when I first bought it for it to keep asking me for more and more money to keep access to features. If you’re going to sell the app at a premium price don’t lock features behind a subscription paywall for your paying customers.', '4.1.11', 'us', '2026-04-11T12:13:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14253874836', 'SumeyraaaaM', 2, 'Bugs', 'My free trial ended the next day l subscribed although it shows that it’s supposed to end on July 6 🤷🏻‍♀️And the screen become all white when l wanted to type that question on the app,so l couldn’t. Besides l find it ridiculous why we need premium just to take 5 minute break.', '5.19.5', 'us', '2026-07-02T07:05:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14253587286', 'k_anaastasia_t', 5, 'Добрый день!', 'Просьба добавить возможность задавать промежуток ограничения пользования приложения. Сейчас принцип - я выбираю промежуток, когд приложение не доступно. Можно добавить инверсию? То есть сделать ограничение, когда приложение доступно? Я бы так хотела ограничивать социальные сети и смотреть их только днем (1 час), а утром и вечером исключить. Это реально удобная фича', '5.19.5', 'us', '2026-07-02T05:46:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14249865266', 'Egemen1637', 5, 'MÜKEMMEEELLL', 'PLUS DA ASIRI PAHALIDEĞİL HARİKA', '5.19.5', 'us', '2026-07-01T08:08:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14240416782', 'knivesandwhisky', 2, 'Plagued by In-App Purchases Now…', 'I bought Forest maybe two years ago at the recommendation of a friend. I think it’s a great tool for keeping me off my phone, especially when I need to focus on something or have short intervals of time away from my phone. But after redownloading it recently after a period of not using it, there are so many more in-app purchases that restrict the way the app is used and make it hard to incentivize using it. I liked Forest because it was a pay-once kind of app, and not subscription based the way most things are nowadays. But now in order to cultivate any sort of beautiful forest or garden on this app, you have to pay exorbitant amounts of money for fake trees and shrubs (any amount of money is exorbitant for fake trees and shrubs on an app i’ve already paid for 🙄). Unfortunately Forest has caved to the same sort of capitalist greed that every other app has. If anyone has any other productivity apps that work well and won’t cost me an arm and a leg please let me know!', '5.19.5', 'us', '2026-06-29T04:06:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14238994753', '健健康后', 5, '发现风格', '大学城光辉海波发热率先垂范g个尴尬的vv徐晓燕采用v隔壁b唯一一个个v的观察员v活动和哈哈不许吃饱h副本我觉得结局很高俄官方给爸爸打你电话哈哈', '5.19.5', 'us', '2026-06-28T18:27:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14233191295', 'Yomama2108', 5, 'I love forest', 'I am a huge fan of forest. My friends and I use it all the time and even compete on it through the social feature. Forest has helped me study and has changed my life.', '5.19.5', 'us', '2026-06-27T08:20:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14232066089', '^^🌻', 5, 'Helps me study', 'I’ve studied for an hour straight just so I can have cuter plants', '5.19.5', 'us', '2026-06-27T02:17:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14229826826', 'HarryStylesfan ❤️🤍💙', 5, 'Amazing I have gained better focus', 'I LOVE this app! It helps me focus when I practice my instruments sometimes when I am bored I will just make a timer to watch it grow it pass passes the time and I have gotten better with my instruments!', '5.19.5', 'us', '2026-06-26T12:11:40-07:00');
