((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14145760874', 'GabrielDavidAvi', 5, 'My dad', 'My dad is a special individual. The cares about me so badly that he uses this app to mediate his stress and as a parenting tool for me to enjoy knowing how he parents me and cares for me and treats me as a. an adult because he loves this app so much.', '5.18.0', 'us', '2026-06-05T00:04:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='866450515'), '14145064978', 'KetchupPacket', 5, 'Effective', 'Works really well, love that I work towards getting more in my forest and has other tips. Can’t wait to use this more for pt school.', '5.18.0', 'us', '2026-06-04T18:48:44-07:00'),
