((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14247493561', '467(() mi n c hm', 5, 'Free', 'It’s free and good for productivity', '4.5.1', 'us', '2026-06-30T18:36:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14241880885', 'Artist/Filmmaker', 4, 'Excellent Start ~ Needs Completing', 'It is my understanding that a search feature has been sought after, requested for at least three years. It truly is essential for a visual calendar, AI isn’t. Structured app as it is is a good start, visually pleasing, intuitive, but isn’t complete. Setting times for events is rather laborious and the repeat feature needs more options such as “last Saturday of the month” as most basic calendars provide. A little more development and this would be a grand all in one calendar. It just isn’t quite there yet.', '4.5.1', 'us', '2026-06-29T10:55:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14239607045', '𝚁𝚒𝟿', 5, 'Great Organization Tool!', 'I struggle with ADHD, and I have a hard time remembering to do things on a daily basis. With Structured, I can see exactly what I need to do within an a specific time frame, so I can remember to get things done!', '4.5.1', 'us', '2026-06-28T22:39:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14238807148', 'DANCING DIVAA🩰', 5, 'it’s good', 'i’m so organized and i can stay focused and relaxed', '4.5.1', 'us', '2026-06-28T17:13:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14238068607', 'Illusion2012', 5, 'I love this app! (One feature suggestion)', 'I love this app! I especially appreciate the ai tools! They are so smart and sometimes have a cute little personality. I would suggest the Ai chats being able to continue after the first chat not just having to start a new chat.', '4.5.1', 'us', '2026-06-28T12:30:42-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14234610080', 'Kylan!!', 5, 'Wonderful app!!', 'I love this app!! I definitely recommend!!', '4.5.1', 'us', '2026-06-27T16:22:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14234561115', 'Taylor2426', 5, 'Perfect!!! 😊', 'I’ve tried various apps for time management, tasks and scheduling and have been dissatisfied with all of them. This one is simple to use, accomplishes exactly what I need and has a great interface. I also love the energy leveling. It’s a fantastic idea where you can better analyze the mental load of your daily workload! It’s super neat that it can also integrate into other apps such as awake and one sec. Makes it even easier to stay on track throughout the day and eliminate distractions. I also link that it offers a lifetime subscription. I’m tired of paying monthly fees for every app. The free subscription also has a lot to offer.', '4.5.1', 'us', '2026-06-27T16:03:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14234090342', 'Человек157336643', 5, 'Идеально!', 'Все очень нравится, но верните пожалуйста прошлый вариант настройки времени. Раньше в настройке времени при варианте стандарт, можно было двигать поминутно. Теперь шаг примерно в 15 минут появляется, стало жутко неудобно', '4.5.1', 'us', '2026-06-27T13:04:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14233246179', 'Eric. Aren', 1, 'Worthless Now', 'Was excited for the AI features to help me import calendar and emails to immediately add them to my planner. But the ai feels so limited, can’t even do custom colors for tasks, and missed the point of the prompts I gave it.', '4.5.1', 'us', '2026-06-27T08:36:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14228816090', 'Anappleaday2', 5, 'I like it!', 'It’s easy to use, works with all of my calendars, has updates so I know they’re continuing to improve, and the AI part writes my tasks out so I don’t have to think about it. Also, when AI writes my tasks, and it looks like I won’t be done until 11pm, I realize I’ve over tasked myself! Which is funny, but also reminds me that I cannot physically do all the things I think I should do in one day.', '4.5.1', 'us', '2026-06-26T07:13:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14225238678', 'Harry Potter26263$', 5, 'Helpful', 'It made me so much more productive', '4.5.1', 'us', '2026-06-25T09:27:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14224559985', 'AHuli12', 2, 'Free version too limited', 'Can only add 3 events per day with the free version. Want you to pay $30/year. No way to hide the AI button in the middle of the screen that you need to pay for.', '4.5.1', 'us', '2026-06-25T06:12:44-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14221907277', 'erinnncatherine', 5, 'Helps me so much with my daily routines', 'This app has helped me so much to visualize my day and stick to my rule of life and daily routines. I have a young toddler and I’m going back to school so this app has come in clutch in helping me focus and stay on task while keeping the big picture of the entire day easily accessible. Definitely recommend for people who struggle with time management.', '4.5.1', 'us', '2026-06-24T13:03:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14218489072', 'Dracarys88', 5, 'Hands down best App', 'I have tried many many apps for organization and ADHD. This is hands down the best tool that is actually practical and helpful! I love how there are so many custom features. The app makes it so easy to set everything up especially for those who get overwhelmed easily.', '4.5.1', 'us', '2026-06-23T16:19:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14218166390', '124589$;/4(,!@85:?', 5, 'Intervals are a game changer', 'I already loved this app, it has kept me functional and productive for years. Now they added the interval timer and I can’t believe how great it is. I am flying through my week, at home and at work. I’d pay for it twice if I could.', '4.5.1', 'us', '2026-06-23T14:13:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14217318455', 'Rm7288', 5, 'I love this app!!', 'This has been so great at keeping me on top of my tasks, it even creates subtasks for my wake up and get ready for bed routine. I feel like it’s put a lot in order for me in a time when I’ve been struggling to regain control of what used to be a “structured” life.', '4.5.1', 'us', '2026-06-23T09:30:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14214764109', 'Goose1495', 5, 'Really helpful', 'I searched for years for a good planning app. I started using structured about a year ago and it is legit the best! I have the free version which in my opinion is still really great. As someone who REALLY needs to be able to plan out everything and have it to look at, this is a lifesaver. Thank you to the creators of this app, my days are so much easier! (Also the satisfaction of checking tasks off is amazing)', '4.5.1', 'us', '2026-06-22T17:02:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14212929170', 'Inja Nixx', 5, 'This Really Works', 'I’m dyslexic, with a bit of ADHD tossed in. I’ve gone through a gazillion planners/calendars, and none of them really met my needs. I finally gave Structured a try and to my great relief it works. It’s convenient and easy to use. That is, it simplifies and structures my day instead of complicating it. I wish I had discovered it much sooner. Thanks for creating it.', '4.5.1', 'us', '2026-06-22T06:48:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14211826194', 'hshdbrbrejsjisis', 5, 'POMODORO. LOVE IT.', 'Thank you for listening to feedback and adding the focused timer.', '4.5.1', 'us', '2026-06-21T23:35:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14202289104', 'Shahab Barzgar', 5, 'Best Planer', 'This is one of the best apps for planning our day. I hope the developers add Persian language. We use this a lot in Iran.🧡', '4.5.1', 'us', '2026-06-19T11:30:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14200550887', '飞天小蛋糕哎呀', 5, 'J人的人生app', '太喜欢这个app', '4.5.1', 'us', '2026-06-19T02:03:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14197990813', 'CapybaraGirl!', 5, 'Love it!', 'Right off the bat, it''s a great app. Organized, customizable, and plenty to do even without pro. But I only have one suggestion, could you please make a family plan for pro? My mother and I LOVE this app... but it would be easier if we could have a family plan for pro. Thank you!', '4.5.1', 'us', '2026-06-18T09:33:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14195140337', 'lupeaiglechasseur', 4, 'Graph', 'I don’t like the graph that keeps coming up at the top of my first daily task and below my any time tasks, wish I could get rid of it', '4.5.1', 'us', '2026-06-17T15:29:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14194614675', 'That’s the bomb', 5, 'Amazing', 'They let you pick your theme, no adds and they always make sure I do what I say I need to, if your needing a simple checklist of things that need done this app is for you👌🏻', '4.5.1', 'us', '2026-06-17T12:21:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14193578206', 'الیزابت', 5, 'A miracle', 'This app changed my life, I always have been a last minute person or even worse! Didn’t feel like do the tasks, I’ve installed this, and because I love colors and themes I started playing in it, made a cute environment and started to organize my long time waited tasks. As a game. I could caught many things up since I got this app.', '4.5.1', 'us', '2026-06-17T07:09:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14192108005', 'Sonion ringbrudger', 5, 'Son', 'son', '4.5.1', 'us', '2026-06-16T21:34:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14188495496', 'CrystalJenn', 5, 'I love Structured!! It really keeps me in line!', 'Structured really does keep reminded to check on myself, I like it a lot.', '4.5.1', 'us', '2026-06-15T23:51:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14182762622', 'Lino_Flower', 5, 'So simple, so easy, so lovely!', 'I’m only on my first few days right now, and at first when I started I thought it’ll be hard to start. But actually its really simple and easy! It keeps everything I have to do organized, and then I can have plenty of time to play and rest! I used to not be able to manage time and lose control of time, but now with strcuctured everything is neat. I love this app and I say everyone should try it.', '4.5.1', 'us', '2026-06-14T11:32:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14180692759', 'hellojerome', 1, 'Too expensive', 'The price for this ?!? Ridiculously expensive', '4.5.1', 'us', '2026-06-13T23:32:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14180179181', 'Momma Pia', 2, 'This game seems cool', 'This game seems cool but it said I had to pay monthly money which I don’t wanna do even tho it’s cheap I’m just not interested in subscriptions cause I already have to do that so I want a game that is free now it seems cool and helpful but not for me', '4.5.1', 'us', '2026-06-13T19:50:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14178374217', 'orion🦭', 1, 'Pricing changed and cannot purchase Pro Lifetime', 'I was using the annual pro, only for one year, and saved up for the lifetime for Pro. I''m extremely sad and upset seeing the lifetime rose so much in price. I can''t afford it now and will unfortunately be moving to something else. I feel this is unfair... I genuinely enjoyed using Structured when I did, but it''s unusable without Pro, for me at least, hence why I was planning on purchasing.', '4.5.1', 'us', '2026-06-13T09:02:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14174208355', 'Lord_Banjo', 3, 'Good but could use improvement.', 'I am trying this app out, but find myself severely disappointed in how app handles “overlapping” tasks. I juggle 2 jobs with variable schedules, and have ADHD which this app claims to be aimed at, so I schedule out work shifts in my calendar so I visualize my week and plan other events around them. I want to be able to nest work tasks within that scheduled time, but with the way overlapping tasks are handled, it’s visually a mess. I would love to be able to have larger time blocks schedulable (or imported from calendar), with to dos ables to be placed inside them in a way that makes visual sense.', '4.5.1', 'us', '2026-06-12T08:06:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14173695372', 'Chaplain665', 5, '#navigatingbrokeness', 'Great tool for digital planning.', '4.5.1', 'us', '2026-06-12T05:46:03-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14172336369', 'ADHDQuen💅', 1, 'You can do better', 'As a Person with severe ADHD, I think this app is not giving me the opportunity to be organized. Without the Structured Pro plan, I can’t repeat some of the tasks that I need to do on a daily basis. To be honest, I do not have the money and patience for having to pay for this pro to only get 2 things unlocked. I know you guys got an Apple Award but the only award I would be giving you guys is that you are very good at convincing people to get the app. You guys know you can do better.', '4.5.1', 'us', '2026-06-11T20:14:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14171007468', 'danny25467477', 2, 'Stupid small flaw', 'The app itself is fine, it’s basically a fancy series of alarms but it’s what I need. It had a major flaw in the fact that it simply stops working if you don’t update it immediately when it needs one. It stops giving notifications even though it’s nothing but a PDA timer. Frustrating.', '4.5.1', 'us', '2026-06-11T11:52:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14169634295', 'Richard A.R.', 2, 'Still no location-based reminders', 'The app is almost perfect, really needs this feature to seal the deal.', '4.5.1', 'us', '2026-06-11T05:02:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14168808672', '@2015 Cami', 5, 'I love this app 💋', 'It is so good. I feel like I''m more Organized and more healthy so thank you owner for making this app happen', '4.5.1', 'us', '2026-06-10T23:11:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14167012517', 'Starlight1191', 5, 'It’s one of the greatest apps ever', 'Structured helps me plan my day accurately. It’s exactly what I needed and I’ve been searching for something like this for a long time.', '4.5.1', 'us', '2026-06-10T11:17:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14164542921', 'lmplath', 2, 'plsss remove ai', 'i have been using this app for a long time & have found it really helpful - please heavily consider removing the ai functioning on this app or i may migrate/move on. there’s no need to sacrifice our planet for the sake of an app.', '4.5.1', 'us', '2026-06-09T20:04:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14164074090', 'ThePurpleOne720', 5, 'Plans out my life!', 'This app is great for planning out my day/week/month/year! It’s incredibly productive and had nice customization options. I love the inbox feature - it’s perfect for when I don’t have a specific date for a task.', '4.5.1', 'us', '2026-06-09T16:54:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14162455970', 'chloeb--', 5, 'Perfect ADHD friendly planner', 'Would recommend', '4.5.0', 'us', '2026-06-09T07:43:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14162243785', 'Cheyennelangley1103', 5, 'I love this app so much! It’s great for AuDHD business owners!', 'I recommend this app to everyone I see struggling and all my clients.. definitely worth the $30 per year! You can just use the free version but I love the extra features!!', '4.5.1', 'us', '2026-06-09T06:40:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14159375405', 'Slater71', 1, 'Frustrating', 'Interrupts your session continually asking if you’d like to upgrade even though you’ve selected no each time.', '4.5.1', 'us', '2026-06-08T11:43:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14158434549', 'QuamBonum', 5, 'A great personal planner', 'I use Structured every day like I used to use a DayTimer. My favorite thing about it is the ability to import calendars and reminders from automated systems, but more importantly to be able to hide things that I don’t need to accomplish, but want to be aware of when I’m planning. It’s easy to use and beautiful and the sync they provide on Structured Cloud is amazing.', '4.5.1', 'us', '2026-06-08T06:52:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1499198946'), '14156691231', 'ItRaynsAlot', 3, 'Needs More Color Choices', 'Great app with a plethora of icon choices, but the colors are lacking. For creative like me who need more variety in the sight of their schedule, a few colors just aren’t enough. Allow us to have hex colors or the color wheel will allow us to choose the colors we want. Five stars if that’s fixed.', '4.5.1', 'us', '2026-06-07T18:42:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14250705984', 'Caroline nickname', 4, 'Most fun I’ve ever had doing chores', 'I love the ttrpg style and mechanics that make this both a game AND a task checklist. I actually feel motivated to not only create checklists of tasks I need to do but checking things off those lists. Remembering to do smaller basic tasks has never been more fun and motivating. Joining a party and doing quests with friends has made it even more exciting. Only reason it’s not 5 stars is because the habit function doesn’t work. Everything else works, it’s just the habit function. It worked for the first few weeks I had the app, and I liked it a lot, but it hasn’t worked for about a month now. I have the latest app version too.', '4.0.3', 'us', '2026-07-01T12:11:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14236647228', 'Velocity38', 5, 'Awesome app!', 'I love Habitica. It’s one of the few productivity apps that actually keeps me motivated because it turns my tasks into an RPG. One feature I’d love to see is custom completion sounds. Being able to choose or upload a sound when completing a task (or even assign different sounds to Dailies, To-Dos, and Habits) would make checking things off feel even more rewarding and personalized. I think it would fit perfectly with Habitica’s game-inspired design!', '4.0.3', 'us', '2026-06-28T05:20:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14229977857', 'Buz to lose 10', 5, 'It Improves productivity and focus', 'Habitica makes getting things done fun. I on my third year of using it.', '4.0.3', 'us', '2026-06-26T13:03:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14226788401', 'Heart is the', 4, 'More game stuff', 'It is less of a game and more of a to do list, I want to BE fighting the penguin, I want to see a mini game where I look for things, other wise habitica is the best', '4.0.3', 'us', '2026-06-25T18:41:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14195862641', 'Anonymous 6min/gzm fan', 5, 'Amazing 🤩', 'Habitica is an absolutely amazing app that has helped me a lot in motivating me to get my tasks done and I use it for reminders and habits. Incredible!!!', '4.0.3', 'us', '2026-06-17T20:18:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14195822775', 'Puppygut12', 5, 'Habitica', 'I have gotten a lot better at remembering to do things around the house. Very fun, especially if you are in a party!', '4.0.3', 'us', '2026-06-17T20:02:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14181850768', 'Thegotis', 5, 'It works', 'This app is silly but my brain loves to level up and get better equipment. I love using the to do list and see myself (my avatar) earning coins and improving as a person by completing tasks and good habits. If you forget to do the things that are good for you, give this a try.', '4.0.3', 'us', '2026-06-14T06:57:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14170940197', 'written11', 3, 'Pay to win', 'It’s a great app and I definitely recommend it to anyone who is motivated by gamification. It’s a little confusing to navigate at first, but great once you get the hang of it. However if you want to collect all the pets and such, you have no choice but to subscribe. Pet quests can be gained if you join a party with people who have subscriptions, but for pets that can’t be obtained through quests you’re basically screwed. Challenges can give you gem rewards, but chances of winning are very slim. I would love if gems were purchasable with coins but were very expensive per gem to encourage people to either grind for them or subscribe. That being said I can see how that could be abused with FCV and spamming habits, so if that were implemented those things would need to be adjusted and capped. But I do think it’s doable and less scammy, and honestly a more motivating option. I’ve fallen off Habitica a lot because when those things are unattainable there’s little incentive to actually use the app TL;DR: Good app overall but in my opinion the motivating factors are not sustainable. Claims not to be a pay to win game but absolutely is one if you want to collect things, which is the main reward system of the game. Needs adjustments', '4.0.3', 'us', '2026-06-11T11:32:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14160469702', 'Anonymoose 🫎🫎', 5, 'Perfect for School', 'As someone with ADHD this is really helping me get through college. Heavily recommend for keeping up with good habits and assignments! Simple to use but comprehensive enough for customization to fit your needs.', '4.0.3', 'us', '2026-06-08T18:33:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14160453168', 'ianwittig', 5, 'Best', 'Best habit tracking app, even without the gamification. Used for 10 years. Tried others.', '4.0.3', 'us', '2026-06-08T18:26:26-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14159138964', 'AngelicaPai', 5, '10/10 I love this app so much', 'Used it for years. Love the way that I get held accountable. And it''s genuinely really fun and satisfying', '4.0.3', 'us', '2026-06-08T10:26:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14155680246', 'Iuseapps123', 5, 'Dub', 'I love how it’s so easy to check off and make new habits. I have my Habitica widget on my Home Screen and it’s makes it so easy to remember to do stuff and I feel like I get stuff done more effectively now.', '4.0.3', 'us', '2026-06-07T12:08:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14152537531', '😑😶😴', 5, 'Habitica review', 'I really like it! I love how it has pets and hatching potions, though I wish Cactuses and Dragons appeared more. I also kind of think the seasonal armor is a tiny bit overpriced. But I love the fact that you can customize the app icon and task noises. Although it is fun and kid appropriate, I recently read a review where someone said that the people in their party were being rude and unkind. I think maybe you should add a filter where you can’t type rude things and the person who is being removed by the party has to have a good reason. Anyways I love the app and it’s awesome.', '4.0.3', 'us', '2026-06-06T16:52:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14144981635', 'Runbunbun27', 5, 'Best app ever', 'I love this app so much', '4.0.3', 'us', '2026-06-04T18:14:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14142534563', 'KyleRH86', 5, 'Incredible for being free!', 'Thank you so much for your generous help to us all! I really appreciate what you’re doing for the world!! :)', '4.0.3', 'us', '2026-06-04T04:18:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14141733850', 'Yuyuruzi', 4, 'Fun, but sucks that you have to buy gems.', 'There’s so many things you can buy with gems, but you can’t unless you buys them with real money ):', '4.0.3', 'us', '2026-06-03T22:21:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14141074981', 'Elchivojd', 5, 'Helpful', 'Since the past two months Habitica has helped me get discipline im literally 12 and now every single day I run and i play the piano and I haven’t skipped a day really recommended 🤑🤑🤑', '4.0.3', 'us', '2026-06-03T17:40:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14141017427', 'Mr pickle 607', 5, 'Routine', 'I use this app to build a routine that I could follow and keep track of my progress, and this app is perfect for this. And even though it’s gamified I stoped caring about that after a week or two', '4.0.3', 'us', '2026-06-03T17:17:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14139960757', 'Byrne Archer', 4, 'GG', 'The game is very easy to get the hang of, and you can set all of your tasks to be things you need to do, or if you want to make a habit of something or stop doing a habit, you can just put it here to keep track of it! There are some minor bugs that could be fixed but it makes up for easy gameplay and ability to play with other people like friends or a good way to meet new friends! :D', '4.0.3', 'us', '2026-06-03T10:47:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14139703347', 'Tviytftiyfjhtfhjvgyjftiyty', 3, 'Happy', 'Happy', '4.0.3', 'us', '2026-06-03T09:26:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14134662711', 'Minichi', 3, 'De-leveling', 'How did the entire dev team think that stripping players of their LEVELS when dying to a boss was good idea?? I can get behind the party taking damage, losing gear/weapons, but it’s absurd to lose your LEVEL just because you died to the boss. There is no reason for this mechanic to exist. You punish EVERYONE because certain people can’t complete the dailies everyday. Again, it makes sense to lose your gear and take damage as a whole group, but to be de-leveled is where the mechanic is nonsense. This mechanic should be removed. Never have I played a game where I was stripped of my level status just because of losing to a boss. Other than this, it’s fine.', '4.0.3', 'us', '2026-06-02T03:28:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14129718799', 'NachoCatYt', 5, 'Great and free', 'Been looking for a habit tracker app, and I probably downloaded 5 or 10 and this was the only one that is actually usable without a free trial. Also UI is very fun and simple.', '4.0.3', 'us', '2026-05-31T20:31:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14115259816', 'GAMEON8505', 3, 'Good but needs more widgets', 'Enjoying it so far my only complaint is there’s no home screen widget for habits and there should be a lock screen checklist widget where I can see all my tasks from my lock screen', '4.0.3', 'us', '2026-05-28T04:27:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14103433077', 'Valence88', 2, 'Can’t change username', 'The username editing screen that displayed after I signed up with Google was not obvious, so I accidentally accepted the prefilled username, which I did not want, and now I can’t change it. I won’t use it unless I can choose a different name.', '4.0.3', 'us', '2026-05-25T00:28:23-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14092934201', 'Mdmom715', 3, 'Discover tab is broken', 'The Discover tab’s search function is broken so it isn’t possible to find challenges, significantly reducing the value of the app.', '4.0.3', 'us', '2026-05-22T06:28:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14071017821', 'Alex.Stork', 1, 'Cross Platform Reminder Bug', 'So far my experience has been mixed. Habitica doesn’t work as seamlessly as other to do solutions like Todoist, with the biggest annoyance being broken cross platform reminder between PC, Android, and iOS. I’m using Habitica for a very narrow purpose because I like the RPG mechanics. But I would not recommend this as anyone’s standalone approaching Light task management system. This bug has reportedly been open for years and has never been fixed.', '4.0.3', 'us', '2026-05-16T06:42:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14070982700', 'Love the content', 3, 'Close, on the right track', 'Being a gamer at heart, love this. Easy to create goals and habits to track. Wish you could just have a report daily showing how many habits/tasks you got done that day with the EXP earned that day. I want this to ensure each day was productive. So I want to see maybe in a widget: points, tasks, and XP earned for the day', '4.0.3', 'us', '2026-05-16T06:32:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14060550794', 'Cougar Cannon', 5, 'Used for a Full Year', 'This is hands-down the best goal app I’ve ever used. All the game stuff aside, the goal functions are entirely customizable and easy to use. Organization is clean. The hardest time of this last year was when I stopped using it for a few months, and I’ve recently started using it again religiously; I’m never going back. The game aspect is fun. It’s pretty sweet hitting goals and then seeing my dude in full moon-armor riding a purple dragon with a banner and a sword. Really though it’s just an incredibly solid goal app with a couple fun twists. My ONLY critique; I wish the quests weren’t so hard to do solo. I’m not exactly super social, and I’d love to fight monsters by myself. I’ve been on the same lunar quest for a few months now. Get this app and DIVE into it. My life would be nowhere near as organized without it, and you can tell someone put their heart and soul into designing it.', '4.0.3', 'us', '2026-05-13T10:03:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14040150429', 'MSEndlly', 5, 'Awesome', 'It’s really change my life thank you', '4.0.3', 'us', '2026-05-07T20:08:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '14001677796', 'gun-ta', 5, 'Don’t waste paper', 'Genuinely I was interested in checking out this app for a long time. Once I finally got it set up with all my dailies and such, it looks VERY visually pleasing. The community seems quite friendly, and this app really encourages you to do something for yourself and helping your life. Thumbs up to the people behind this and continuing to make it grow 👍', '4.0.2', 'us', '2026-04-27T01:19:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13979172887', 'Jgmommie', 4, 'SO HELPFUL!!!', 'I was awful at keeping up with my chores. This helped me and my kids enjoy them! It seemed boring at first, but then I discovered you can hatch and raise pets to become mounts. I am constantly doing chores just to earn food for them! I don’t really like that Habitica only gives certain amounts of gems to those who have no subscription, but then doesn’t give more. They have 3 main sections. One is habits. Each day it resets, and you can get more and more points for every time you do what you want to become a habit each day. Then there are dailies that you can check off and it will reset the next day. The last one is a todo list. You check off what you did and it won’t pop back up! This is a great encouragement! My kids love it. Definitely recommend! It still takes a while to raise all the pets, so I still love it!!!!!! Get it! It will change your life!', '4.0.2', 'us', '2026-04-20T11:42:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13971265948', 'exposetruth', 1, 'WIDGETS NOT UPDATING AGAIN FOR 100th time', 'This bug is constantly coming back where you add to your To Dos and it doesn’t update and it either skips it or doesn’t show it at all. I sent a message to their admin to report the bug and they were rude saying just use the app itself for now. Completely unacceptable and not professional. this app could easily have 4 to 5 stars but it’s no wonder they have 2.4 only. Please have this fixed. I’m not alone so many people are leaving the app bc of this constant back and forth', '4.0.2', 'us', '2026-04-18T07:36:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13943518270', 'AmbientBark9183', 5, 'Super helpful with ADHD', 'I have been looking for gamified task managers for a while now, and this one really feels like you’re putting yourself into a game. There is also that accomplishment feeling of checking off something you’ve done. While I play this by myself, I realized you could put yourself into a solo party so you could beat the bosses by yourself. In addition, they have a pomodoro timer chrome extension that gives you more points for studying! There had been some buzz for a while of the timer not being able to sync with your account, but I’m glad that it is fixed now! It makes me more motivated to get back into the pomodoro method of productivity.', '4.0.2', 'us', '2026-04-10T10:10:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13934283695', 'Lifesaver''s', 1, 'Not working', 'When I try to sign in it always says request timed out and I can’t sign in', '4.0.2', 'us', '2026-04-07T19:48:14-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13930224697', 'Jessellllll', 1, 'Unethical', 'I downloaded this app and use it one day to see if it would be efficient to use with clients. Since then, I have been trying to figure out how to unsubscribe yet I’ve been charged.', '4.0.2', 'us', '2026-04-06T15:34:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13894882697', 'Boboslayer6841', 5, 'Healthy habit builder and life changer', 'Very useful and helpful. Made motivation for me and I got through some of my toughest goals. Truly an amazing app.', '4.0.2', 'us', '2026-03-27T20:50:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13882582042', 'Bloxxel64', 2, 'ADHD, autism, and executive dysfunction, not helpful', 'I tried this app because it offered the premise of turning completing your tasks into a fun game, instead it’s simply ties whether or not you complete tasks to arbitrary values, there was no consequence for losing “health” by not completing tasks, I didn’t feel like I was accomplishing anything by completing tasks, nor did I feel any sense of failure for not completing them, the daily reminder notification didn’t even work correctly. If you’re going to advertise this as some form of game, maybe make it an actual game instead of some images and bars.', '4.0.2', 'us', '2026-03-24T10:06:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13865707870', 'Meggers111', 5, 'Life changing!', 'I’ve been using this app for a few years (just crossed 365 days of a daily) and it’s so amazing how well it organizes my life and gamifies the idea of life improvement. Highly recommend!', '4.0.1', 'us', '2026-03-19T13:32:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13857742779', 'BigBoss9382', 5, 'This app is goated', 'Been using this consistently since COVID stated, super helpful for organize my life and make me feel in control', '4.0.1', 'us', '2026-03-17T07:03:54-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13844591939', 'vanskik3', 1, 'App Constantly Crashes', 'A recent update changed the look of the app but resulted in the app constantly crashing. It’s almost unusable. They should roll back the update.', '4.0.1', 'us', '2026-03-13T12:01:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13838933613', 'OneBigFishStory', 3, 'Good For Helping Me Improve, But Very Buggy!', 'I have been using the app for nearly two years, and I have been able to steadily increase the number of tasks and frequency at which I do them. In that respect, I find the app very helpful for my ADHD. However the app is extremely buggy. At least once a week, the app will tell me it started a new day, but it hasn’t cleared out my dailies from the previous day. I then can’t log my tasks for the current day until something about the server resets and finally refreshes so I can log my tasks. Also, regardless of all the other improvements that have been made in the app, a glaring issue is that pressing the “+” button beside a task will not add the point to the task I selected, but to a completely different task. The haptic tracking is very off. It’s extremely frustrating that I have to tap the “+” to add points every time, I can’t just type it in. When my method of using the app is assigning points based on how hard the task is for me on a given day (sometimes my chronic pain conditions make a task much more difficult than on a different day), I have to repeatedly tap the “+” button to add those points that day. Sometimes I give myself 100 points for cleaning the toilet or doing the dishes, and having to press the button 100 times is so aggravating when the number glitches and adds some of the points elsewhere instead. Can this be addressed in an upcoming update, please? The haptic feedback badly needs adjusting. Some days these bugs are so bad, I don’t even want to use the app at all.', '4.0.1', 'us', '2026-03-11T20:01:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13829834726', '600ccbugslayer', 3, 'Not good for ADD folks', 'I have a task list because I’m easily distracted and can’t remember stuff, right? So i open habitica to manage a specific task but oh, there’s some important notification that pops up - every time i open the app. I read it and completely forget why i open the app. It’s so completely frustrating. The other annoyances are right after I start editing an existing task, the cursor moves to the end and now I have to rewrite the entire task. I tried the group tasks, but none of us could figure out how to use them to assign or share tasks. There are some useful abilities like sub tasks, recurring and daily task, and a wonderful number of options for scheduling & reminders. These are the reasons I use the app. If only I could figure out how to turn off pop-ups!', '4.0.1', 'us', '2026-03-09T04:23:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13825516262', 'JCruz_23', 5, 'Game On!', 'If you’re looking for a way to manage your actions and reward yourself for following through then I recommend this app for you… And if you have buddies with similar issues of following through, I recommend party mode like in DnD. I like this app because it saves me time of opening up my note book every time or having to rewrite my dailies… I use to hate that in middle school. Automation is key!', '4.0.1', 'us', '2026-03-07T20:11:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13823675799', 'brassattack84', 2, 'Crashing issues after update', 'I loved this app! looked forward to plugging in habits and checking off to dos every day but after the update it won’t even open. Crashes immediately upon launch. Restarting phone/uninstalling and reinstalling did not help :(', '4.0.1', 'us', '2026-03-07T08:19:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13816465368', 'OgDog24', 3, 'New update', 'The tasks are huge and they are now daunting. I liked them when they were smaller and I could see the whole screen. Can we change back please or at least give the option to adjust the sizing?', '4.0.1', 'us', '2026-03-05T06:57:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13800024555', 'SunflowerValentine', 2, 'New liquid glass update is atrocious', 'I have NO idea why this app decided it would be a good idea to try and mimic one of the worst and most hated Iphone updates in my lifetime. It is ridiculously ugly, and using it has gone from pleasant to something that actually hurts my eyes and makes my head hurt. I can’t quite bring myself to rank it less than 2 stars, because I’ve been using it for so long with so much success, but I’m just deeply dismayed, and I don’t even know if I *can* keep using it when it grates so badly at my brain. I hope someday they at least give us a setting to turn off this new visual update. for the time being, I think I’ll keep trying to use the as-yet unchanged desktop site, but I’m just feeling so discouraged - I honestly almost started crying when I logged on today to start going through my dailies. This just really, really sucks', '4.0.1', 'us', '2026-02-28T13:51:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13793184905', 'Best😽🙀😹😸😻😼🫶🏼', 4, 'THE BEST ROUTINE EVER!!!!!!!!', 'I love ❤️ this app!!!!!!!!🤑🤑🤑$$$$$$$$¢¢¢$¢', '4.0.1', 'us', '2026-02-26T17:36:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13791199455', 'MJordan23Z', 1, 'Moving in the WRONG direction!!!!', '⭐☆☆☆☆ I realize I’m late to this news, but I just rediscovered Habitica after using it consistently from 2020 through 2023 — and I genuinely cannot believe the guilds are gone. The guilds were the soul of this app. That’s not dramatic — that’s accurate. They were how I found goal-specific communities, niche challenges, accountability partners, and like-minded people pushing toward the same achievements. Whether it was fitness, language learning, productivity sprints, or life resets, guilds created momentum. They made change feel communal instead of lonely. Coming back, I was actually excited. I thought, “Okay, let’s see what guilds are active now. Let’s plug back in.” And they just… don’t exist. That completely deflates the experience. The app without guilds feels like a stripped-down habit tracker with RPG cosmetics. Functional? Sure. Inspiring? Not even close. What makes this more frustrating is the subscription fee. You’re charging $4.99/month. If moderation was the issue, raise the price. Gate guild access behind subscription. Recruit paid moderators. Build a scaled-down version. There were options. Eliminating them entirely feels like removing the engine because maintaining it was inconvenient. I understand this happened a while ago. I’m just rediscovering the app now, and the downgrade hits hard. The excitement, the optimism, the sense of shared transformation — gone. For an app built around gamified self-improvement, removing the primary social motivation system feels like a massive strategic misstep. Really disappointing.', '4.0.1', 'us', '2026-02-26T05:22:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='994882113'), '13784143675', 'Sheldonplayz', 5, 'Best app ever', 'This is one of the best things I’ve had it helps me a lot when it comes to keeping track of things. What they need to add is maybe pre-set messages for the little ones and maybe a way to stop people from spamming', '4.0', 'us', '2026-02-24T06:28:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '14116063088', 'FriendlyReviewerCinq', 1, 'Does not work anymore at all and just hangs', 'Since some of the newer updates, for whatever reason the app just doesn’t load anything at all and doesn’t allow me to click or do anything. My iphone is one of the newer models so it’s not an update thing.', '4.0.2', 'us', '2026-05-28T08:33:47-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13966079285', 'evillynnnnnn', 3, 'Lags terribly', 'I’ve been using this app for years and it’s been helping me keep good habits- I have a streak that’s 47 months long. But it’s been really laggy and crashes a lot lately. It’s disappointing. I’d rather not move to another app but I’m starting to feel like I’m being forced to.', '3.15.2', 'us', '2026-04-16T20:47:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13832504095', 'Jeff13131', 1, 'App used to be better', 'This app used to be perfect, it was simple, tracked anything, and was a one-time cheap payment. Now that they’ve added a ton of unnecessary bells and whistles, this app can be replaced by something better that doesn’t have a subscription requirement. This app should be a tracker and nothing more.', '3.15.2', 'us', '2026-03-09T22:30:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13742146421', 'luvduv', 1, 'Scam', 'I got scammed $149.99!!! I downloaded the Habit tracker app a year ago. Can’t remember how much I paid for it. This January, I was charged $150!!! For a “Growth Bundle” I went to dispute the charge but my Chase credit card wants documentation on how much I agreed to be charged. Of course I don’t have any from an app I downloaded over a year ago! I’m so mad!', '3.15.1', 'us', '2026-02-12T11:28:40-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13706868575', 'Arisumiboys', 5, 'Good', 'So far it’s perfect', '3.15.1', 'us', '2026-02-02T19:07:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13701503325', 'skvllface', 5, 'cleanest design, nothing superfluous', 'this is the best habit tracking app for ios and apple watch. it’s worth the subscription cost immediately if you want a minimal design with maximal functionality (unit tracking, customizable reminders + schedule) for tracking your habits. i’ve tried many other apps and nothing is as simple and beautiful without missing features.', '3.15.1', 'us', '2026-02-01T08:43:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13613981255', 'KokomoKid1962', 2, 'Had High Hopes', 'Had some issues with the app, reached out to support, never heard back. Very buggy syncing with Apple Heath.', '3.15.0', 'us', '2026-01-09T10:13:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13580297324', 'sylvia ❤', 4, 'Simple App', 'Wish it had a monthly habit option :/ very simplistic app, not the most customizable.', '3.14.1', 'us', '2026-01-01T01:22:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13576858122', 'Tommy 2 Toes 4 Real', 1, 'Have to pay twice', 'I’m still upset over this. I’ve tried contacting customer service a few times over a few months and no response. I paid for the full app a few years ago like others and now I have to pay for a subscription? And then you can’t even reply to my emails about it? Seriously?', '3.14.1', 'us', '2025-12-31T05:23:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13571422092', 'akunap', 3, 'Almost perfect', 'It’s a good app but I wish they had a way to show more habits in the widget or let us choose which ones show up', '3.14.1', 'us', '2025-12-29T19:47:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13512526597', 'Gabal007', 3, 'Great app, support needs to be more responsive.', 'This is an amazing app. I use it every day to track my habits. I love the reporting features which allow me to gauge my progress over time. I''ve been having some issues with it recently. The app became very sluggish. I need to kill it numerous times to make it work. This is very annoying. I would''ve given it a 5 star if the support team answered my numerous emails and fixed the issue. Giving it a 3 star for the time being.', '3.14.0', 'us', '2025-12-14T04:50:02-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13492335593', 'ziyaoyan', 5, 'App is great, widget can be more customizable', 'Really great habit tracker. Only wish that there was a bigger widget that allowed for more habits. Or that the widget allows you to pick which habits to display.', '3.14.0', 'us', '2025-12-08T20:27:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13467130073', 'jrtjtrtjr', 4, 'Almost perfect', 'Overall, I really love this app and its tracking features. It’s clean, intuitive, and helps me stay consistent. There are just two things that get a bit annoying: 1. When I’m checking off multiple habits, there’s a small delay after each tap, so I can’t quickly mark several items at once. 2. If I edit a habit (frequency, units, color, etc.), the app automatically moves that habit to the top of my list—disrupting the specific order I’ve organized. Aside from those two things, I find the app super helpful and genuinely enjoy using it.', '3.14.0', 'us', '2025-12-02T09:02:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13460244118', 'Mo_Fletch', 3, 'Great but glitchy', 'I love this app, but it is very glitchy. It takes several taps to add or subtract a habit count. I''ve deleted and redownloaded the app to my iphone 14 several times and continue to have this issue, not sure why! It''s really negatively affecting my use', '3.13.0', 'us', '2025-11-30T13:57:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13347885485', 'SaraLiba', 1, 'Doesn’t recognize my paid subscription suddenly', 'I actually quite like this app overall, even though it can be laggy. What I very much DON’T like is that several weeks ago, despite the fact that I have an annual paid subscription through late December, it stopped giving me access to premium features like unlimited goals. When I go to create a new goal now, I get a paywall asking me to upgrade to premium. Worst of all, I reached out to support ages ago about this problem and never got a response. I have been using this app for years but I guess I’ll have to find another one if they’re not going to address that I cannot access features I have already paid for without paying again.', '3.13.0', 'us', '2025-11-02T10:20:00-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13265256358', 'Laurenabeth', 3, 'Recommend but…', 'Have been using this app for years and can confirm I am now a daily flosser, a daily bed maker, and I never miss taking my vitamins. That being said, the premium version is not cheap, and there’s a weird lag after checking off and item that has gotten worse over time (I assumed because of the amount of data it holds now but could be because it’s simply become a clunky app) and has rendered the app almost unusable. It also doesn’t recognize time zones so the data gets destroyed when I travel, as it can’t tell what day it is. Lastly, as others have said, it doesn’t sync across devices, which is a huge disappoint for such an expensive app. I will be using this until I upgrade my phone, and then I will likely look for something new.', '3.13.0', 'us', '2025-10-14T05:51:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13262318239', 'Lizziejean7219', 1, 'Don’t do it!!!', 'I subscribed to this a long time ago through the growth app, it’s been a nightmare ever since. I have been charged twice for a yearly subscription when my subscription doesn’t even exist, I signed up for a free trial so guess what? Somehow I am getting charged but don’t have an account yet? Hmmm…how is that? I have reached out to support to cancel a dozen times and get no response. This company is corrupt and steal!', '3.13.0', 'us', '2025-10-13T11:25:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13249878139', 'QueenSusel', 3, 'Highly recommended!', 'Love this app! I’m a list and planning lover. I’ve tried most of these types of apps but this one has been my favorite through the years. It’s pleasant to the eyes, has never given me tech issues, and I really like the extra feature of charts to track productivity. I just wish they had a desktop version too. edit: has become really buggy over time and veeeery slow. I don’t use it throughout the day anymore because it makes my other apps shut down, like my music app. Very disappointed that I can’t multitask with it anymore. :(', '3.13.0', 'us', '2025-10-10T13:56:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13240359658', 'Lynn358521', 1, 'Paid for upgrade, but it didn’t upgrade', 'DO NOT USE. Used to be a great app, now it’s buggy and lags. Paid for an upgrade at one point because I like how minimal the layout is compared to other habit apps, it never applied and is prompting me to pay again to upgrade. Waste of money.', '3.13.0', 'us', '2025-10-08T08:24:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13230858906', 'JayWat2.0', 1, 'Used to work much better', 'I used to like this app but it’s slow and barely works at this point.', '3.13.0', 'us', '2025-10-06T04:05:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13204134623', 'gb13186', 1, 'Can’t get in touch with support', 'I really love the app but I upgraded and was charged but it still asks me to upgrade to add additional habits. I’m only able to add 3 and I’m trying to move fully to this tracker from Another I like less. I’ve emailed support twice. SOS.', '3.13.0', 'us', '2025-09-30T03:58:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13106055329', 'Con gdjeh', 4, 'Too manny adds', 'The app works fine although I have a payed subscription but it keeps sending me “offers to upgrade” certainly annoying.', '3.12.4', 'us', '2025-09-06T08:22:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13105697042', 'annaeb_', 2, 'Glitchy :(', 'I have had this app for a while and sadly its become so laggy and glitchy its almost unusable', '3.12.4', 'us', '2025-09-06T06:44:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13071110686', 'MarchoftheMeguins', 1, 'Ripoff', 'This app is a complete ripoff; especially do not upgrade your membership. I did so and it was completely unrecognized in the app and the support team NEVER responded. Save your money and go elsewhere', '3.12.4', 'us', '2025-08-28T09:13:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '13036517547', 'dp91918', 1, 'Scam', 'I purchased this app before it was an insanely-priced subscription model. Customer service was zero help in transferring me over to the full paid app. Streaks is a one-time purchase and is equal if not better.', '3.12.4', 'us', '2025-08-19T12:27:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12935963325', 'Dicxiidid', 5, 'Хорошо приложение мне понравилось', 'Очень хорошое приложение❗️', '3.12.3', 'us', '2025-07-25T12:37:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12923581384', 'Mr Toner', 1, 'Thievery', 'Thievery I once was a big fan of this app — in fact, all the apps from this developer. Then they got greedy. ￼Their Growth Bundle provided reasonable pricing for all of their apps and I''ve been a subscriber for five years. But my recently-renewed subscription is no longer active in any but one of the 10 apps I use ￼— and I''m being gouged to the tune of $340+ every year if I want to continue using them. Developer support is nonexistent; my email messages are￼ being ignored. ￼Given the plethora of reasonably-priced apps that do what this app does, you''re better off looking someplace else.', '3.12.3', 'us', '2025-07-22T11:14:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12921070038', 'ACN4231', 1, 'Almost unusable due to lagging', 'This app has lagged more and more over the last year to the point it barely functions. They’re clearly not making updates to it while charging $60 per year', '3.12.3', 'us', '2025-07-21T21:09:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12875307538', 'KamTheMan14', 1, 'Worst Support On Planet Earth', 'DONT WASTE YOUR TIME OR MONEY. These guys are a joke. Have been waiting nearly 3 weeks for an email response and I’ve sent multiple since. They’re doing absolutely nothing to solve my problem and they’ve locked down their app. Used to have the premium version but they kicked me back to the basic, now my goals and history are erased and they’re not doing a thing to help.', '3.12.3', 'us', '2025-07-10T06:54:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12844031407', 'Dee168373', 2, 'Bugs', 'Love the app design but it’s extremely slow to load to the point of uselessness sometimes.', '3.12.3', 'us', '2025-07-02T09:27:31-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12833757287', 'deerheart2020', 1, 'Glitching and slow', 'I have been using this app for 5 years and this last year it is glitching and very slow responding. I am probably going to have to stop using it.', '3.12.3', 'us', '2025-06-29T21:27:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12829229457', 'Luke-em-and-duke-em', 3, 'I want to love it, but don’t', 'Missing some simple features (that reminders has): why can’t we just click on the widget to mark something as complete? Why can’t we click on the notification to mark as complete? Why is the order of the tasks constantly resetting? You have to be ahead of them to be differentiated… otherwise, why would we pay? Until some changes happen, I’m switching to another option that’s actively developing ✌️', '3.12.3', 'us', '2025-06-28T16:54:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12828258037', 'pixidize', 5, 'love this', 'I only have one habit for this app, but I love the design and the widget as well. Cute and customizable.', '3.12.3', 'us', '2025-06-28T10:41:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12803786956', 'T7511', 1, 'Developer no longer supports', 'I purchased the one time forever subscription and the developer now is forcing an upgrade to premium subscription. They do not respond to support inquiries about restoring previous purchases.', '3.12.3', 'us', '2025-06-22T04:37:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12798451343', 'ben bassy', 1, 'Borderline idiotic', 'The app has close to zero functionality and will spam you with whatever tasks you set instead of batching them. At best it’s annoying at worst. It’s completely useless.', '3.12.3', 'us', '2025-06-20T18:01:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12789423554', 'IAmLiterallyABantha', 1, 'Mostly bad', 'EDIT 6/18/25: Checked back in with this app to see if any issues had been addressed; unfortunately I can only add insane lag to the list. When I check off a task, the app seizes up trying to mark it complete. I have invested too much time and money into this app. I’m done! EDIT 2: Possible scam? I paid for a growth bundle and it only applied to one app instead of the whole bundle. In-app links for support/feedback are all broken. Nice. If you want to complain or request a refund, try going through Apple. Developer does not want to be contacted for some reason. EDIT: Downgrading my review, because the things I mentioned were actually facets of the same issue. Since I got the app weeks ago, there have been countless unannounced design/format changes. Every time I add a new task, the creation process is somewhat different (ie, you used to be able to add tasks to custom groups; suddenly all my custom groups are gone and tasks can be sorted only by time of day). It’s confusing and makes me wonder if I paid money for a product that was incomplete. I really like this app. It works with my ADHD. The app generally works fine, and it’s nice to look at. But, two things I don’t get. First, the color palette where I choose the background for my tasks changed today without warning. My old tasks still appear in the old colors, but I can’t make a new task in the old colors, only in a new, muted palette. So being who I am (and someone who relies on color coding), I have to go through and change alllllllll the tasks so they match again. Sigh…okay. Also, the ability to make a monthly task seems to have vanished. I made a monthly task when I first got the app, so I know it was an option before. Why? This is so basic.', '3.12.3', 'us', '2025-06-18T09:39:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12786221357', 'geekrishi', 5, 'Absolutely love the minimalism', '10/10', '3.12.3', 'us', '2025-06-17T13:23:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12783597022', 'mirthispalpable', 3, 'Laggy', 'I like the app and have been using it for a while, but recently it is laggy and glitchy when trying to check off a task. It’s pretty annoying even though I only use it for a few habits- I’m sure it’s much more irritating for those who use it for more throughout the day.', '3.12.3', 'us', '2025-06-16T21:23:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12733596516', 'ashleymcain97', 1, 'App lags', 'I’ve been using this app for years and the last 6 months it is really slow, freezes and lags while using. Now looking for a new app that works because it makes me want to pull my hair out using it now', '3.12.3', 'us', '2025-06-03T21:24:01-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12731608760', 'Jami Spradlin', 5, 'Customizable But Simple', 'It is rare to find an app that actually impresses me, but Do managed to immediately and is one of the first apps I install on any new phone or tablet. The user interface is simple yet comprehensive, with a variety of options that can be further adjusted by going into the advanced settings below the basic settings. Not overwhelming despite the variety of customization options offered, easy to use, aesthetically-pleasing… you can add forgotten or late activities to previous dates and times with ease. I can legitimately not think of a single flaw with this app. I have autism and ADHD- my schedules, habits, and medications are all absolutely essential to my mental well-being, the Premium option was a great upgrade but the free version is perfect for even my rather extensive references as well.', '3.12.3', 'us', '2025-06-03T08:49:53-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12725571465', 'JasonDyba1', 4, 'A bit buggy', 'This is my favorite habit tracker that I’ve found, but every time I check off a daily habit, the app freezes up for about 30 seconds while trying to execute the animation. It makes using the app pretty slow. It didn’t used to be like this and I’ve been hoping it’d be resolved in an update.', '3.12.3', 'us', '2025-06-01T18:34:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12717134682', 'Rainbow-noddles23', 4, 'Primum', 'Wish you didn’t have to pay for premium to make unlimited goals', '3.12.3', 'us', '2025-05-30T15:27:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12715461504', 'kbarn0al', 2, 'Can’t back out!!', 'I have been trying to cancel my subscription since I don’t really use it and I can’t figure out how! No one will help me so that’s a big no no for me. Don’t try to trap me to pay for something I no longer want !!!', '3.12.3', 'us', '2025-05-30T06:20:41-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12681073800', 'alim.arsh', 1, 'Poor Customer Service', 'I love this app but unfortunately I don’t have access to my subscription anymore, and the customer service is leaving a lot to be desired. They emailed me back once, and I replied with more information, but now it has been a month without any response. I have emailed a couple times and all attempts to contact them have been ignored.', '3.12.3', 'us', '2025-05-21T07:13:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12679324232', 'Lyd876854', 1, 'App speed is really bad', 'I have had a subscription to this app for the past 4 years. I unfortunately think I will have to switch to one of there competitors as the app speed is way to slow. It glitches each time I scroll and it doesn’t work any time I try to check off a habit. It makes is really hard to do and track my habits when I don’t even want to or can’t use my tracking app.', '3.12.3', 'us', '2025-05-20T19:29:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12675255179', 'BK_101', 1, 'Customer Support Needed', 'Hello - I submitted multiple several weeks ago about a duplicate charge and still not having premium features. I am still awaiting a reply. Please assist so that I can utilize the app in the fullest after already paying in the past. Thank you.', '3.12.3', 'us', '2025-05-19T16:36:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12632798564', 'CatG210', 1, 'Fees', 'I paid for the full version of this app in 2018 for $4.99. And it upgraded and then wants to charge $59 a year or it has horrible ads. I had been using this app for years, and love it. But continuously adding additional fees after paying a “one time” upgrade fee, seems incredibly scammy.', '3.12.3', 'us', '2025-05-08T04:15:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12623235661', 'don josepe', 2, 'Lags', 'Lags all the time', '3.12.3', 'us', '2025-05-05T11:21:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1103961876'), '12580616226', 'almostfamous09', 1, 'Bait and switch, No support response', 'Paid for one-time premium upgrade of unlimited app access and have since been blocked by a new paywall constantly asking to pay again. No response on outreach and follow up to support to resolve.', '3.12.3', 'us', '2025-04-24T06:47:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14258176383', 'dfwjr', 1, 'Not Worth the Money', 'Why bother paying an annual fee for something that Apple provides for free? I’ve used both this and Apple’s free version and I don’t see what I’m paying for. I just wish I could get some of my money back.', '2026.13', 'us', '2026-07-03T07:28:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14247662902', 'Postorder', 5, 'It has been 12 years since I wrote my first journal', 'I can’t say anything except amazing the every moment I write on it. Pure joy.', '2026.13', 'us', '2026-06-30T19:35:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14247619655', 'CalvinLanier', 5, 'Love it personally', 'This app is my life. Many notes i have written feels like a life chapter. Easy and simple', '2026.13', 'us', '2026-06-30T19:19:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14239305444', 'Lonleylioness', 5, 'Long time user', 'I loved this so much I purchased my best friend the full version. So I get a notification reminding me to journal. It won’t open. It’s still in my apps but won’t respond! I went to the App Store and updated it and thankfully ALL my entries are present and accounted for. Initially, I thought the thing ate my 12 plus yrs of stuff so I wanted to correct my mistake as apparently the update took a bit longer to catch up with all my goings on! Love this app and hope my girlfriend is enjoying the full version. I retired so I’ll continue to be satisfied with it as is!!', '2026.13', 'us', '2026-06-28T20:29:55-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14238590331', 'Pomaikai99', 2, 'Loved this app till it glitched', 'Hey maybe it’s just my phone but everytime I drop a pin in the maps it usually adds the location coordinates but it keeps saving as 0 0 coordinates and not the right location. Please fix! And I’d give it 5 stars but I’ve been using this app for a while and it’s worked amazing until this glitch started happening', '2026.13', 'us', '2026-06-28T15:45:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14236953160', 'Ahdgnwbd', 5, 'Great app! No complaints.', 'Have been using this app for years now. It’s nice when I don’t feel like whipping out my journal but I want to express something or get a thought out. ✨✨👌🏽', '2026.13', 'us', '2026-06-28T06:53:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14233461930', 'embracingTheBlonde', 5, 'Long time loyal customer', 'Highly recommend to everyone! Gives you just enough of what you need without distracting you!! Go with this one!', '2026.13', 'us', '2026-06-27T09:38:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14229981614', 'Kpie2012', 5, 'Love it!', 'Great online journal, syncs between devices.', '2026.13', 'us', '2026-06-26T13:04:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14228921063', 'Shep#1', 5, 'Love it! How are you feeling honey how''s your eye', 'I absolutely love this app! I''ve been using it daily for over four years and I have referred to it often with the search function to answer questions that come up. Because I attach photos to most entries, I can quickly come up with pictures of important events. The search function is invaluable.', '2026.12', 'us', '2026-06-26T07:41:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14219310472', 'SierraKD', 5, 'Just Write ;)', 'I have appreciated Day One from day one, but even more so when multiple journals became an option for the free version. I love having multiple journals (each with a different focus and color) and that I can move my long messages full of life’s details from chats with friends to my Day One journals.', '2026.13', 'us', '2026-06-23T21:55:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14218965326', 'piecesoflight', 5, 'Best gratitude journal app', 'I love this app so much, I''ve been using it to journal gratitude, glimmers and prayers for over two years and it''s been so fun and easy to use, the ads are once-in-a-blue-moon, it''s customizable, and the only thing that bugs me about the free version is only being able to upload one photo per entry, which isn''t a huge deal anyway. Highly recommend this app!! Also backs up to the cloud, I''ve switched phones and still kept all my entries!! Also gives me a daily reminder so I don''t forget to journal', '2026.12', 'us', '2026-06-23T19:31:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14216070168', 'Czuque', 5, 'This is what I have been looking for', 'I have tried to a variety of apps for recording daily activities and random thoughts. FINALLY I have found the tool in Day One. And the deeper I dig, the more I find that I can use; things I did not know that I need.', '2026.12', 'us', '2026-06-23T02:40:43-07:00');
INSERT OR IGNORE INTO reviews
  (tracked_app_id, review_id, author, rating, title, body, app_version, region, review_date)
VALUES
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14215863756', 'xxFlyingGoriliaLover69xx', 1, 'Used to be good, now AI slop + in your face premium features', 'If you don''t mind constant popups begging you to pay them money to have the basic human right to change your color scheme, and don''t mind how for some reason they too, are shoving AI features in your face you can just barely turn off, Then this app is great. But for anyone else, it''s grown to be unusable. And with the way the modern internet is, it probably won''t ever show you this review because they withhold information to hold more power over you. If you have to take away anything let it be this, stay true to yourself and don''t let any screens or technology affect you. Learn to rely on yourself and learn the real truth that they hide from you to make more money. They control your screens now, and if you let the screens influence you, they control your mind, and the worlds mind to. Spread the word.', '2026.13', 'us', '2026-06-23T01:05:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14212356736', 'Vwoman', 5, 'Love!', 'This app has helped me capture some really dark moments in my life. It allows me to add pictures and it captures dates and times and locations. I have been able to go back and look at my progress and years of how I’ve grown. This is a necessary app for everyone, no matter what is going on in your life. The good and the bad.', '2026.12', 'us', '2026-06-22T03:36:29-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14212309053', 'suzanneh64', 5, 'Love it', 'The prompts are great', '2026.12', 'us', '2026-06-22T03:17:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14201266417', 'Sanngar', 1, 'AI Slop', 'I pay for a Silver subscription. I don’t care about AI and I don’t want to be constantly pestered to ‘upgrade’ to the Gold plan. This app is now garbage. You’ve ruined it. I have unsubscribed. Good riddance. In response to the developer: it’s too late. You’ve lost a paying customer for life. Stupid decisions have consequences.', '2026.12', 'us', '2026-06-19T06:22:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14196306260', 'gle92', 1, 'Can’t access the free journal anymore', 'Now the screen shows up as Buy or no longer being able to access the basic version? This is not nice at all', '2026.12', 'us', '2026-06-17T23:42:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14196258963', 'TehLosers', 2, 'IOS app not working', 'I’m unable to access the journal from the list screen and I’m unable to add photos to entries.', '2026.12', 'us', '2026-06-17T23:19:51-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14190006024', 'The Cheery One', 5, 'Journal companion', 'I’ve been using the Day One journal free version over a year. I love it! It keeps all my daily entrees and photos. It shows me what I did that day a year ago. I really appreciate the simplicity and having everything accessible. This tool is one of my favorite apps hands down!', '2026.12', 'us', '2026-06-16T09:01:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14188888515', 'Nick1st', 4, 'Organization', 'Day One has completely revamped the app over the past few years, Bravo! I started with DO 3 years ago but left for more comprehensive system with Evernote. Now I’m back to DO . There is a learning curve but I’m making friends with it. Keep up the good work!!', '2026.12', 'us', '2026-06-16T02:55:42-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14188293301', 'mamacha', 1, 'Why charge a lot more for what was included in premium?', 'I really liked Day One. I’ve had it for over five years. They recently included some Ai features that were included in my premium service. You could generate AI IMAGES from your entries, get prompts, and some great summaries for your entries., I had really been enjoying this new addition to DayOne. UNTIL TONIGHT— when those features were suddenly 🚫removed 🚫 from my premium membership ! NOW they made a new membership level that costs more and if you want those previously included in Premium, you have to upgrade to Silver. It really stinks that I received the AI features for a short time only to have Day One take them away. I am strongly thinking of canceling my over 5 year old membership and looking for another journaling app. Thanks a lot,DayOne. 👎🏽', '2026.12', 'us', '2026-06-15T22:13:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14182380781', 'allialves', 5, 'BEST journaling app ever!!!', 'I’ll never use another journaling app!! Day One makes it so easy to add pictures, videos, and audio recordings- even of days past. It’s incredible💕', '2026.12', 'us', '2026-06-14T09:34:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14179676349', 'bbatcat', 2, 'Time to move on. OG user. Now its all about the subscription', 'Really have reached my limit with this app paid user from the beginning they had no grandfathering when they went to the annoying and oh so tired subscription model and now every time I do anything, it’s a prompt for a subscription. I’m just gonna move to the free apple journaling app I’m over it. They just care about money. Updates have been useless things like group chat. I am not interested.', '2026.12', 'us', '2026-06-13T16:31:43-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14175239110', 'Jay from Pasadena', 2, 'Enjoying the update', 'I too was originally skeptical of being forced into their sync system. I read their terms of service and frankly some of the language was frightening, but I had a couple email exchanges with their extremely responsive customer service and I was satisfied they could not use my private entries in the future. I''ve been using for two months now and their sync service is fantastic. I had period issues with iCloud with Day One Classic, but I''ve never had an issue so far syncing between my iMac, iPhone, and iPad. The bottom line is that for YEARS I struggled to consistently journal - since getting Dayone in 2012, and now Dayone 2 - I journal more than I have in my entire life. It is awesome for capturing moments and recording my life. I know some day there won''t be a price you can put on having these entries. It''s so easy to capture photos in DayOne 2 and being able to have multiple photos in an entry is awesome. If your nervous about their sync, just read the news, it''s a risk we all take using the cloud, but to me the trade off is that I''m building a lifetime of memories with this app. Update MANY years later - I wrote the above a long time ago. I’ve been using this app daily and haven’t missed a day since 2015. The new conversation element is amazing to me. It helps me journal throughout the day more instead of trying to remember the whole day. Quite frankly the AI asks some very insightful questions that help me go deeper and have really improved my entries. I’m hoping eventually they will add the ability to use AI to “converse” with your older entires like “hey how did I handle this previously . . . “. UPDATE 6/11/2026 - after giving original plus members (I’ve been using the journal since 2012) the daily chat for about the last 8 months the tiers changed with no notice or warning. Went to use it today and see now I’m “silver” and have to upgrade to use it. I get it, apps need to make money but it’s a shame is the same old methods - hook you on the service for some indefinite period of time then take it away. Not a lot of loyalty for long time subscribers. I feel like that is disappointing. Even changing the tiers and not keeping it the same. Might be time to look for other options or use apples. Really a shame they just don’t have as much loyalty toward their subscribers and users that have been here since well Day One. Pun intended. Their latest bait and switch on features I just thought was a really poor thing to do. Gave the use of chat for like 8 months then raised the price of the tier I was on and decided to take away the features. I was using the chat in beta. Very disappointed and a little sad to have to login for another option.', '2026.12', 'us', '2026-06-12T13:25:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14173475117', 'Zombieee man', 1, 'Unorganized and complicated', 'Your app sucks. Where’s the calendar?! So many options I can never find the only thing I need the screen with the calendar. So many options it’s so unorganized i can’t find anything! And everytime I try to enter something for yesterday it will write a new entry for today. No I clearly clicked on yesterday. Your app is so fkn annoying. Unessary complicated. Instead of my giant calendar I have to keep fkn scrolling by each day and it doesn’t even automatically show what I wrote it shows a bunch of pictures of my camera roll of options to put in… like just show me what I wrote nice and easy and quick. Instead it’s all a fkn migraine. So fkn unorganized and annoying. I’ve been using this for weeks and I still can’t get the hang of it . I hate this app. Used to be a big screen of a big calendar and u can click on the day.. where did it go?!! Why am I scrolling day by day?! Is it gone?!', '2026.12', 'us', '2026-06-12T04:33:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14168899217', 'MissingMyDroid', 1, 'From 5 ⭐️to No More', 'Functionality LOST with Apple’s updates from April, May and June. Was holding out hope until the June update. Now more grief than when I began journaling. Years of archiving my journey with a rare disease for my daughter and those who come afterwards was healing and empowering. Now I cannot even open years of work. Evil overlords for the win again. Go tech bros. Thanks.', '2026.12', 'us', '2026-06-10T23:54:18-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14168312939', 'thinker,08', 3, 'Customer Service is Now Non-Existent', 'I asked a question about searching a particular entry over about 3.5 weeks ago and still no reply. As far as I can tell you can do a global search of every single journal and entry and it finds every instance, HOWEVER once that list populates, there’s no way of knowing which entry is the one you want and no way to search a particular date without reading the entire entry, and those can be rather long. I asked whether there was a way to do this and apparently I have them stumped. 🤷🏻‍♀️ It’s been what, a year or so since I wrote the above and still no better searching feature. Anyway, I’m a longtime Premium user and have tried the Ai daily chat. It was buggy and I don’t know whether that’s been fixed or not. What I do know is that there is NO discount to upgrade from Premium (now called Silver) to Gold and it would cost me $40.00 more per year for that feature.', '2026.12', 'us', '2026-06-10T19:28:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14163393202', 'lil_nekoi', 1, 'used to love this app but its wayyyy to expensive now? and not even any options to do pay monthly', 'i paid $10 or so for the old version of this app. each year the price is more and more expensive. $10/lifetime, then $4/per month, then $8, then $12, now the only option is $75 yearly?! sad to have to find an alternative', '2026.12', 'us', '2026-06-09T12:35:57-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14159007380', 'ElrusA', 3, 'Glitches since adding AI', 'I’ve subscribed to this app for several years. It has worked flawlessly up until recently when they added AI. Now my ipad app glitches out and won’t even show the entries I just added. Syncing between my ipad and iphone is very slow and has gotten progressively worse. Support used to respond right away, but I’ve been waiting for them to fix this issue for days without response.', '2026.11.1', 'us', '2026-06-08T09:45:30-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14157787830', 'Jay🫀', 1, 'Complete money grab', 'all the basic features are hidden behind pay walls. You can’t even put it two images in the same notes without paying on top of that the prices are egregious $74 a month I believe. It didn’t seem to me because the app is very basic. You can find way better app for free doing the same thing for much better results I will be copying and pasting a few notes that I have in here into my new Notes app and will be deleting as soon as possible😭', '2026.11.1', 'us', '2026-06-08T03:08:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14153127183', 'mathiasparks', 2, 'Forever bound to the subscription', 'Great journal app, but if you ever stop paying for the subscription you are no longer able to access all the journal entries you made while paying for it. This is atrociously wrong to do to customers.', '2026.11.1', 'us', '2026-06-06T20:51:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14146461847', 'CBee35', 5, 'App not working on iPad M5', 'I have used Day One app for many years and loved it. However it recently started to update on my new iPad M5, but got stuck and would not work. The Day One app was showing as darkened as though near end of update. The developers responded to my inquiry regarding the problem. It is fixed and back to normal. Yes, I still love the app. Loved the app before this.', '2026.11.1', 'us', '2026-06-05T04:56:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14145899532', 'SFSheerio', 2, 'Not a good ui', 'There are some parts of the software that are really great like the ability to send photos to the journal. But the interface on an iPhone is abysmal if you have a long journal. It’s constantly bringing you to the top and you have to scroll all the way down to get to earlier entries. And if you delete an entry it again brings you to the top you have to scroll back down to the bottom entry you open will also bring you back to the top. It’s so incredibly frustrating!!', '2026.11.1', 'us', '2026-06-05T01:09:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14143871105', 'Niteghoull', 4, 'Needs Dark Mode love&Android Love', 'It’s a shame that the drawing mode on dark mode, does not work (ios). It makes the colors saturated (extremely dark). I tried drawing a sun using yellow, and it was just this ugly mustard dark yellow. But on light mode, the colors are fine. Also the app for android, does not work for drawing. Which is a shame! I am trialing the Silver subscription, and I like it! But on my phone, there is no drawing :c please make drawing availability for Android!', '2026.11.1', 'us', '2026-06-04T11:13:21-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14143662458', 'Slowstart…..', 1, 'How do I get my money back???', 'I started a free 30 day trial about 5 minutes ago but I was immediately charged for a full year. I’ve already gone into subscriptions and cancelled. HOW DO I GET MY MONEY BACK???? Very deceptive and dishonest practice!!', '2026.11.1', 'us', '2026-06-04T10:06:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14143192550', 'we_had_a_pact!', 4, 'I love this app - please remove ai from the interface', 'I love this app and use it all the time. Moreover I’ve used it for 8+ years so the ability to search through journal entries, upload photos, and create various journals for different things has been great for organizing my introspective practices. However - I don’t want to see AI on the app interface whenever I’m writing. I really wish I could toggle off even the ai icon. When I’m journaling I’m putting down my thoughts and feelings and recollections - flaws and all - and I don’t want or at all need ai anywhere near that process. I understand that it’s “off” in my app, but the fact that it’s there every time I journal is an annoyance and frankly mars an aesthetic and the positive brand association (one of very few tech brands that I’ve enjoyed despite the forced ai everywhere).', '2026.11.1', 'us', '2026-06-04T07:44:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14141478422', 'antonio.cortes', 5, 'User experience', 'I do love the way the controls are organized it just makes me love the app so much.!', '2026.11.1', 'us', '2026-06-03T20:24:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14136594196', 'Another rando human', 2, 'Be warned, company pushing their AI filled Gold Tier hard', 'I''ve liked the app a lot - nice intuitive format, and very easy to use if you like to add photos and screenshots directly into your journal entries. But the prices are increasing, and it has gone full Team A.I. - they are pushing the a.i. features hard and defaulting people with paid subscriptions to the highest tier "gold" subscriptions that include it. Not a happy camper. Prior to the a.i. stuff, I''d have given this app five stars.', '2026.11.1', 'us', '2026-06-02T13:41:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14128304294', 'Review guy 467', 5, 'This has been a lifesaver', 'It was in February of last year when I first began to use this app. Since then, this app has been a lifesaver. I quit Facebook or before I found this app. And this app has been my private Facebook basically. I am grateful for this app because I can put out my true thoughts without having to face any scrutiny from random folks and certain family members. I can almost say that even more this app has been beneficial for my mental health as well. I know it cost to use the extra features on here. But the biggest benefit from it has been how much it’s been helping my mental health.', '2026.11.1', 'us', '2026-05-31T11:36:22-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14127669057', 'fsht@nk', 5, 'My daily journal: Love this app', 'I’ve been using this app for a couple years now. I used to just use Apple Notes, but it doesn’t have memories or reminders. Apple ‘journal’ app was still in its infancy - only living on the iPhone and I’ve even poked with it since and I have no inclination to switch. This app reminds me of things that happened in the past, I can put photos in here of random things that don’t have to. “clutter” my photo album - because they are things of my day-to-day stuff that I like to have with journal entries. I can create as many journal “books“ as I want.', '2026.11.1', 'us', '2026-05-31T08:23:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14122037326', 'Icebourg', 1, 'User since 2012', 'They’ve added new AI functionality, and despite it being on a plan I don’t pay for, and despite this being functionality I would never use in a personal journal — there’s no way to turn it off. It’s always sitting there, waiting for you to accidentally hit it.', '2026.11.1', 'us', '2026-05-29T21:43:58-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14113456705', 'Dash1212eh', 5, 'It’s been years..', 'I’ve been using DayOne for years.. I enjoy the layout and user ease, the upgrade is worth it but not necessary for a good experience. The book option 👌 plus ofc the memories.. good bad and ugly, it’s all worth revisiting at some point.. Memories: the preview makes it so you can decide what you’re ready for 😉', '2026.11', 'us', '2026-05-27T15:30:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14109749885', 'New Solar Dre One', 5, 'ANDRE’ REGINALD CHATMON, A NEW AND INVENTED AND EARTH AND DAY AND ONE AND NOW AND INVENTING AND YEAR', 'DRE EARTH', '2026.11', 'us', '2026-05-26T15:38:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14108550557', 'WookieWaffles33', 5, 'Best journal app', 'This app is super easy to navigate. And has been very useful and impactful for me.', '2026.11', 'us', '2026-05-26T08:36:26-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14108438408', 'blah bla boah 2', 1, 'Bad', 'App won''t update at all no matter the wifi, can''t delete it because it won''t update.', '2026.11', 'us', '2026-05-26T08:02:28-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14087227575', 'Fa11_', 5, 'AMAZING', 'Have been using this a lot great for journaling. I use it a lot during school days, it helps me get out my feelings and just having a lots of fun. would highly recommend to people who want to have someone to type/talk to.', '2026.10.1', 'us', '2026-05-20T15:33:35-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14086391665', 'any2996', 5, 'Best Journaling App', 'I have had the same app for years. Every time a new one comes out I try it and continue to use Day One, there is no other journaling app like this one. Journaling is the single best habit I have, it has changed me. It was easier to become consistent using Day One.', '2026.10', 'us', '2026-05-20T10:22:08-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14085586223', 'Theapushgoat', 5, 'Love this app', 'So many great uses for this app. Have used for years.', '2026.10', 'us', '2026-05-20T06:08:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1044867788'), '14084155249', 'longtimemac', 3, 'My most important app', 'I never leave reviews. But this app is too important not to let everyone know how great it is. If you care about recording your personal history, day-to-day events, or things that really matter, this is the app for you. There’s no better way to understand who you are or where are you were going than the app called Day One. The story begins today… This is day one. iPad OS 26.4.2', '2026.10', 'us', '2026-05-19T19:38:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14268452500', 'Krodti', 5, 'Ladygaga2026', 'Lady Gaga 2026', '3.73.185', 'us', '2026-07-05T20:24:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14268154648', 'Raven9412', 4, 'Love this app but…', 'This app is absolutely incredible, I’ve had it for some time now but, I feel one thing that could be improved is to make sure they are actually doing the self care part, for some people they may just want to see the journey your born takes instead of actually caring for themselves. Maybe just find a way to check to make sure their actually helping themselves.', '3.73.185', 'us', '2026-07-05T18:26:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14268143502', 'Velvet Papillon', 2, 'Not what it used to be.', 'I have used Finch for about 2 years. I used to love it but it seems the app has lost its soul. When I started mental health was front and center with a first aid section on the front page. It’s now buried in the menu. It has evolved to become more about the monthly events and collecting stuff than it is about mental health. The devs have stopped listening to their users and any attempt to contact them is met with silence or a copy and paste generic email. Sadly it seems they don’t actually care anymore. There are always glitches and bugs sometimes they are fixed but then new glitches pop up. They are more concerned with making new features than addressing the functionality. The last straw for me was the 50’s diner event that has a lot of issues for racial exclusion. I’m not saying this was an intentional choice but their response to it was. When users tried to address these issues on social media (because emails aren’t working) they were all deleted. When it was finally addressed on Reddit there wasn’t an apology just a suggestion to hide conversations about race behind a NSWF tag. I’m so disappointed that the app I once loved has become something that causes me to feel worse.', '3.73.185', 'us', '2026-07-05T18:22:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14268128960', 'Gabbyluvsmangos', 5, 'Love the app, here are some of my ideas', 'I absolutely love Finch. It has helped me build healthy habits, and my penguin is so cute. My favorite part is traveling, discovering new foods, animals, and places. One thing would love to see is more travel destinations especially countries like the Dominican Republic, Puerto Rico, Colombia, and Mexico. It would be so fun to learn about more cultures and discover more foods,animals, and landmarks from those places. I also think adding even more discoveries and activities for each destination would make traveling even more exciting. My absolute favorite one would be the Dominican Republic because it would be such a cool place for my Finch to explore! Overall, Finch is an amazing app, and I can’t wait to see what gets added in future updates!', '3.73.185', 'us', '2026-07-05T18:16:56-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14268049153', 'sofa4kkaa', 5, 'I luv it <3', 'Милейшее оформление и достаточно большое количество ежедневных задач, которые можно настроить под себя. Мне пока все супер нравится!', '3.73.185', 'us', '2026-07-05T17:46:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267897612', 'SuessicalTheMusical', 5, 'Wish they’d add a screen time blocker!', 'I wish it could make you earn your screen time, but otherwise a great app!', '3.73.185', 'us', '2026-07-05T16:49:10-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267829983', 'THE_WOLFIE', 5, 'Probably best self care app you could ever get.', 'it doesn''t have you paying for any extra self care it tracks your days and even has an emergency kit if you need it!', '3.73.185', 'us', '2026-07-05T16:22:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267798153', 'harperdagoat014', 5, 'i love thisss', 'this app has really helped me reach my personal goals and actually made me more motivated to complete things', '3.73.185', 'us', '2026-07-05T16:10:12-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267640919', 'The very sassy girl', 5, 'Omg', 'I absolutely LOVE this app it is so cute!!It has helped me so much and everyone is SO NICE!!!I hope u love it to 🪺❤️😊🐱', '3.73.185', 'us', '2026-07-05T15:09:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267514251', 'Starlite50', 5, 'It gets me motivated', 'I think finch is awesome. U have goals and try to complete them.', '3.73.185', 'us', '2026-07-05T14:19:17-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267443192', '60935k', 5, 'Finch', 'It is so good it gets you up makes you do things so it helps me get out of bed cause there is s streak and I have to keep but it is so good I recommend you you trying it', '3.73.185', 'us', '2026-07-05T13:54:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267387434', 'Minacool3337476474', 5, 'Finch', 'I like this app. It encourages you to do your goals and helps you feel good about doing them! One thing that’s not as good is the gem sytem, it’s a bit hard to get gems (or maybe I just don’t understand it that much) and it takes a lot of gems to buy things, but obviously that’s not the reason why they made this app, it serves it’s purpose well and has a very cute design! 5 Stars!', '3.73.185', 'us', '2026-07-05T13:34:38-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14267249904', 'Mirmir r', 5, 'Best game', 'I love this game so much it helps me understand how to get ready better.', '3.73.185', 'us', '2026-07-05T12:47:31-07:00');
