((SELECT id FROM tracked_apps WHERE apple_id='1528595748'), '14266487376', 'Chubby Elephants', 5, 'My favorite game', 'Finch is nice it is cute it is more helpful than other games it is really good I love Finch it is the best', '3.73.185', 'us', '2026-07-05T08:50:21-07:00'),
