((SELECT id FROM tracked_apps WHERE apple_id='1164801111'), '14240301395', 'Walkernjh', 5, 'Auto Sleep', 'Love this app. So easy to use and very accurate. I just wear my Apple Watch to bed and it does the rest!', '6.16', 'us', '2026-06-29T03:28:50-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1164801111'), '14233474585', 'CHEROKEE66', 5, 'Sleep questions', 'App is extremely helpful for tracking what is really going on at night, heart rate and how it affects deep sleep and total rest. Made me understand changes I could make to improve my health.', '6.16', 'us', '2026-06-27T09:42:43-07:00'),
