((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14151045057', 'Dmspictures', 2, 'Unreliable', 'Ok as far as features but I paid for the pro version which just randomly disappeared one day. App closes randomly very often. Pictures don’t load and I find myself restarting it constantly. Not worth the annoyance. Don’t bother paying for it.', '461.4.0', 'us', '2026-06-06T08:09:05-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14146159022', 'DARPs-dark nips', 1, 'Have to spend money to get anything', 'As soon as you down load you have to spend money in order to do anything. Just say that in description.', '461.4.0', 'us', '2026-06-05T03:05:05-07:00'),
