((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14132069087', 'Zisman81', 5, 'VSCO Changed my life 🪽✨🪄', 'Best film archive that allow you to flow on the go …creat your color science 🧬 profile like old times ..without compromising ✨', '461.3.0', 'us', '2026-06-01T10:41:25-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14125708151', 'sunnyjholie', 1, 'Trash', 'Trash just trash all those others reviews are just fake do not download is a waste of money', '461.3.0', 'us', '2026-05-30T19:58:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14106825693', 'Elias Howe', 3, 'USED to be better', 'I’ve been a LONG time paid user of VSCO and honestly? What happened with this app? I’ve used this app since 2014 and slowly I’ve seen this app just get continually worse, yet always gave it benefit of doubt. But now? Are you serious? VSCO constantly crashes, has deleted ALL of my drafts multiple times, refuses to import photos from my gallery and will usually crash while trying, and when saving images from my drafts, will save them with glitches and weird artifacts in the photos. I’ve reached out to support multiple times with zero response. What happened? Genuinely.', '461.2.0', 'us', '2026-05-25T21:14:37-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14105293179', 'rnx33', 3, 'New update is trash', 'The new update is horrible. We have to click on 5 different things to do one task. Bring back the old layout or make the app easier to use again. Why is the new import section awful? Also, why are we being asked for our birthdays? This is a photography app 💀', '461.2.0', 'us', '2026-05-25T11:12:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='588013838'), '14101832649', 'Atlantanre', 2, 'Dastardly annual pricing scheme', 'Making it 13 a month for monthly and five a month for an annual plan is dastardly. Let’s be real $5 a month for annual should be $7-8 a month MAX. Predatory annual lock in pricing / not standard at all', '461.2.0', 'us', '2026-05-24T12:59:38-07:00'),
