((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13969747467', 'MikeKeysProd', 5, 'Great stuff for the people', 'Thank you bro', '6.8.2', 'us', '2026-04-17T21:28:11-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13918815839', 'shelfy13', 5, 'Works amazingly', 'I love it and so far so good he is aiming for perfection', '6.8.0', 'us', '2026-04-03T11:24:49-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13909550519', 'SnapStarSean', 5, 'Deliciously Good…', 'The best git client, Working Copy. enables professional workflows anywhere anytime. It''s actively developed, supported, feature rich, fully documented, and highly integrated. Git works right, and so do the thoughtfully included addition features. OAuth, ssh keys, identities managed in app; multiple remotes, syntax highlighting, diff, merge, stash... AI code completion (your choice, your key). And, a full fledged iOS File Provider, x-callback-urls, Shortcut actions, folder sync, share sheet support for importing too! No doubts, this developer and app are ★★★★★ five stars, with a 10+ year history exemplifing innovation, work, and original Apple Indie Developer culture.', '6.8.0', 'us', '2026-03-31T23:03:27-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13861833404', 'alfig_dota', 5, 'Great app. Dows what it’s supposed to.', 'Straight forward and works every time. 5/5', '6.7.5', 'us', '2026-03-18T10:46:59-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13829127070', 'iJbol', 5, 'Excellent App', 'Worth every penny if you use iOS for any real dev work. I’m using it paired with Pythonista to version my projects to GitHub. Saved my butt a few times already with easy rollback.', '6.7.5', 'us', '2026-03-08T22:03:16-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13811045041', 'Tits32', 5, 'All it took was free trial.', '$35 dollars felt a bit high at first and considering the usual mindset of “subscription bad, one time pay good”; I dismissed the app. However, after trying aShell, plomgit, iSH and Github official app (all great apps in their own right and more general purpose), I am really impressed at how good this app works and how smooth it makes working with git repositories from the ios walled garden. In addition to that, I understand why the developer chose this mode of payment, since this is the only sustainable way for developer to work on this, while also ensuring that users who end up paying annually are the ones needing the newer features, and users who already paid don’t lose out on the access. Pretty happy to use this app and support the developer! Keep up the great work!', '6.7.2', 'us', '2026-03-03T15:53:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13802657182', 'Nor_Cal', 5, 'Pairs well with Obsidian', 'I use this to keep my Obsidan vault in sync with my iOS version (self hosted in GH) - I love this app!', '6.7.2', 'us', '2026-03-01T07:32:19-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13797028119', 'NiiCk ht40', 5, 'NiiCk', 'NiiCk', '6.7.2', 'us', '2026-02-27T18:53:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13792688825', 'Hemou_', 2, 'К сожалению плохо', 'Слишком загнутые цены, я лучше воспользуюсь компьютером чем буду платить за очевидно простые функции', '6.7.2', 'us', '2026-02-26T14:13:02-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13781070688', 'Dmitri1543kiu', 5, 'Excellent git client!', 'This is an excellent git client! Pull push commit … it’s all here and works with GitHub and all other git based servers! Edit directly in app too <3 I’m in love as my phone is now my go to for reviews while anywhere!', '6.7.2', 'us', '2026-02-23T08:52:48-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13779064373', 'Minus one to charisma', 5, 'It’s a pleasure to use', 'No I don’t do work on my iPad but I do use markdown for my notes. This is perfect to quickly go over documentation and push on the go.', '6.7.2', 'us', '2026-02-22T18:54:06-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13771884050', 'Fan of Catan', 5, 'Best Git client ever', 'By far the best Git client for iOS; combine with Blink for SSH/terminal (and integrated VS Code) and you have the most powerful mobile dev environment since my 10” Sony VAIO running OpenBSD 30 years ago', '6.7.2', 'us', '2026-02-20T19:44:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13749338226', 'Antiduplicity', 5, 'The best working copy app for the iPad', 'Keeps me up to date on the go. Integrates with the best editors. Cannot work without it', '6.7.1', 'us', '2026-02-14T11:29:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13747209880', 'SkullCandy£', 5, 'The wonderful life of a Working Copy :)', 'My life has been pure joy, knowing that with WorkFlow and Working Copy combined, I can accomplish more with less effort. I no longer have to handle half the manual work in my workflow, and everything runs smoother than ever. :). Butter.', '6.7.1', 'us', '2026-02-13T22:29:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13713101117', 'prenagha', 5, 'Excellent', 'Fantastic app. Well maintained. Good continued new features. Excellent support. Very well integrated with core iOS features.', '6.7.0', 'us', '2026-02-04T12:08:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13690960601', 'Hyperspace Radio', 5, 'Does what it says, well.', 'Does what it says, well. Interface took a little for me to get used to, but it''s providing exactly what I need with no issues. Recommend for this kind of tool, I don''t know anything else that does it better.', '6.6.9', 'us', '2026-01-29T16:16:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13685687793', 'Long-Forgotten', 5, 'Most Responsive Dev Ever!', 'The app itself is amazing, of course. It''s a game-changer to have such a powerful and full-featured git interface running on a device in my pocket! But beyond that, the developer, Anders, is so responsive and clearly cares about their craft and their customers'' experience. I''ve emailed them on multiple occasions, and they''ve immediately fixed bugs or even added entire new features just for me. I truly enjoy paying for the pro unlock to keep supporting Anders and this wonderful app as often as possible!', '6.6.9', 'us', '2026-01-28T07:43:45-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13584953700', 'Stacked88', 5, 'Wow', 'Such a neat app! It’s got a lot of capability. The developer seems kind and the pro version is definitely worth it. A real value add!', '6.6.7', 'us', '2026-01-02T04:17:43-07:00');
