((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13544698627', 'suobset', 5, 'Integral to my workflow', 'The single most important app on my iPhone that transcends it to my remote computer. Paired with an SSH client (Termius in my case), you’re ready to develop on the go.', '6.6.7', 'us', '2025-12-22T19:48:15-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13540951007', 'omhmichaels', 5, 'To bad it ain''t free', 'Should be a free project', '6.6.7', 'us', '2025-12-21T19:30:52-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13540685305', 'Chemical_Skin', 5, 'Support Materials', 'INPRoGress', '6.6.7', 'us', '2025-12-21T17:36:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13521164957', 'zxxxxhdbebe', 5, 'nice', 'I love it', '6.6.5', 'us', '2025-12-16T11:11:36-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13470546341', 'Benjyiw', 5, 'glad it exists', 'really glad the app exists', '6.6.1', 'us', '2025-12-03T07:06:09-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13454627694', 'jaassoooonmm', 5, 'Unbelievably featured', 'I used this to do some genuine web development in conjunction with Termius when I was working a retail job, and it did not disappoint. The feature set and flow, even on a tiny screen (iPhone 15 Pro) are excellent, and the developer also responded to my email regarding a bug quickly and with care. Highly recommend.', '6.5.9', 'us', '2025-11-29T05:18:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13441492000', 'Gem-Enterprise', 4, 'Acknowledge', 'I’m enjoying but would love the service on free plan', '6.6.0', 'us', '2025-11-25T18:15:32-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13436161117', 'Ezra0417', 5, 'Thanks for sharing your experience with us on Githut & self-hosting', 'Excellent thread', '6.5.9', 'us', '2025-11-24T09:02:07-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13432458004', 'Kolfate Anahita', 5, 'Excellent App.', 'If you are engaging with repositories in any capacity, this application is a quality of life tool that has the essential features to make your experience more efficient and effective. I have used this app since its inception and have never been inconvenienced or disappointed in its usefulness nor burdened by poor performance. This app serves as a git client in its own right as well.', '6.6.0', 'us', '2025-11-23T09:22:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13425010162', 'prag', 1, 'iOS 26 rewrite was a mistake', 'Numerous display and layout glitches such as the sidebar conflicting with the bottom controls in portrait mode, controls floating over and obscuring content in frustrating ways, only showing first two character of file names followed by ellipses, unreadable dark theme, etc. This tool is much more cumbersome to use now, it''s a confusing ill-behaved mess.', '6.6.0', 'us', '2025-11-21T11:17:20-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13401087393', 'CaptCaveman', 5, 'An indispensable tool', 'I''ve used this for years. Allows me to work on my various iOS / iPadOS devices seamlessly. My most common use cases are Obsidian and writing posts for a blog generated automatically via Jekyll.', '6.5.9', 'us', '2025-11-15T06:41:39-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13384877454', 'RichIWalt', 5, 'Functionality and Updates are over the top', 'I’m not going to write a two page report of the details ... but will provide a simply overview that the app developer is aiming for perfection. Working Copy is fantastic - functionality is over the top. Very nice interface !!! Very nice editor. And supports other great editors such as Textastic, as well. Btw ... this was the only repo that worked with a predefined port number that has to be declared. 5 stars all the way !!!', '6.5.9', 'us', '2025-11-11T06:33:24-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13342591298', 'Mobilemind', 5, 'Still the best and always improving', 'I’ve been using Working Copy for years. It’s the best repo utility available for iPhone & iPad, and it keeps getting better. I’m vigilant and check. Fantastic native app, great features, integration, and extensibility with/to other apps and services. Great pro features, and one of the best, most practical approaches for buying in to feature upgrades. Get the features you need, support the developer, while avoiding the feeling of “do nothing” permanent subscriptions. The developer provides critical updates, and the subscription offers meaningful & valuable new features & enhancements.', '6.5.7', 'us', '2025-11-01T07:54:34-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13276097647', 'Mugukido', 4, 'Time according', 'Good result', '6.5.5', 'us', '2025-10-16T18:33:13-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13238369295', 'Node-0', 5, '**THE GIT CLIENT** FOR IOS', 'This is the only git client you need for iOS, it features amazing files app support which means you will be able t9 grab freshly synced git repo content into all of your other apps that can access files app data. Amazing editing support, awesome ssh key compatibility. Look no further! Get Working Copy now!', '6.5.2', 'us', '2025-10-07T21:15:33-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13224015301', 'Qdrddr', 2, 'Can’t read repo from Mounted Location in Files app', 'Cool app, though can’t read repos from mounted locations from other apps such as Cryptomator, Disk Decipher, FileBrowser and many others.', '6.5.2', 'us', '2025-10-04T13:06:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='896694807'), '13200606052', '616c616e', 4, 'Student Discount', 'Thank you so much for unlocking pro features automatically for my student subscription on github itself! It’s awesome and says a lot about the good intents of the developer. However, kind of bummed that support <17.4 was dropped by the latest version…', '6.5.1', 'us', '2025-09-29T07:26:26-07:00'),
