((SELECT id FROM tracked_apps WHERE apple_id='1450936447'), '6357769520', 'Boomin4u', 5, 'Day 1', 'Loving it already! Will most likely pay for upgrade soon but the free version does a ton already :)', '1.13.1', 'us', '2020-08-24T20:08:51-07:00'),
