((SELECT id FROM tracked_apps WHERE apple_id='1450936447'), '6220732204', 'jesselperry', 5, 'Super powerful', 'Amazing what this app unlocks and allows with Shotcuts and HomeKit. There really isn’t any limit to what you can do', '1.13', 'us', '2020-07-20T09:28:10-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1450936447'), '6113841570', 'Hay Hay (hayden)', 5, '5 star', 'ITS REALLY GOOD ILSM🩰🍼🙈', '1.12.2', 'us', '2020-06-23T15:15:04-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1450936447'), '5983344726', 'Piercejpierce', 1, 'No triggers', 'Can’t make custom triggers, this is only good if you want notifications', '1.12.2', 'us', '2020-05-23T05:01:46-07:00'),
((SELECT id FROM tracked_apps WHERE apple_id='1450936447'), '5957195099', 'Rookie875', 1, 'doesnt work :/', 'evetytimr I create an app I click on it afterwards and it says "open app failed cause the app could not be opened." please make your apps work I want an aesthetic phone not more random apps that don''t work.', '1.12.2', 'us', '2020-05-17T06:07:01-07:00');
